#!/usr/bin/env node

/**
 * render-stems-cli.js
 * Puppeteer integration: spawna browser headless, executa offline-renderer.html
 */

import puppeteer from 'puppeteer';
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

async function renderStemsViaHeadless() {
  console.log('🎵 ELIFOOT Audio Rendering (Headless Puppeteer)');

  let browser;

  try {
    // Launch headless Chrome
    console.log('\n🚀 Launching headless Chrome...');
    browser = await puppeteer.launch({
      headless: 'new',
      args: ['--no-sandbox', '--disable-setuid-sandbox']
    });

    const page = await browser.newPage();

    // Intercept console logs
    page.on('console', msg => {
      console.log(`   [browser] ${msg.text()}`);
    });

    page.on('error', err => {
      console.error(`   [browser error] ${err.message}`);
    });

    // Navigate to offline renderer
    const htmlPath = path.join(__dirname, 'offline-renderer.html');
    const fileUrl = `file://${htmlPath}`;

    console.log(`\n📄 Loading: ${fileUrl}`);
    await page.goto(fileUrl, { waitUntil: 'networkidle0' });

    // Wait for rendering to complete
    // Check for status div update
    console.log('\n⏳ Rendering stems...');
    let renderComplete = false;

    for (let i = 0; i < 120; i++) { // Max 2 minutes
      const status = await page.evaluate(() => {
        const statusDiv = document.getElementById('status');
        return statusDiv?.textContent || '';
      });

      if (status.includes('✅ Done') || status.includes('❌ Error')) {
        renderComplete = true;
        console.log(`\n${status}`);
        break;
      }

      if (i % 10 === 0) {
        console.log(`   ${status}`);
      }

      await new Promise(resolve => setTimeout(resolve, 1000));
    }

    if (!renderComplete) {
      console.warn('⚠️ Rendering timeout (check browser logs above)');
    }

    await browser.close();
    console.log('\n✅ Rendering complete!');

  } catch (err) {
    console.error('❌ Puppeteer error:', err.message);
    if (browser) await browser.close();
    process.exit(1);
  }
}

// Run
renderStemsViaHeadless().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});

#!/usr/bin/env node

/**
 * render-stems.js
 * Orchestrates full audio generation pipeline:
 * 1. Generate metadata (AudioGenerator)
 * 2. Pre-render stems via Tone.Offline (Puppeteer)
 * 3. Saves WAV files to public/audio/stems/
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { AudioGenerator } from '../src/audio/AudioGenerator.js';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

async function main() {
  const args = process.argv.slice(2);
  const config = {
    dryRun: args.includes('--dry-run'),
    seed: args.find(a => a.startsWith('--seed='))?.split('=')[1] || Date.now(),
    outputDir: 'public/audio',
    stemsDir: 'public/audio/stems'
  };

  console.log('🎵 ELIFOOT Audio Generation Pipeline');
  console.log(`📦 Config:`, JSON.stringify(config, null, 2));

  try {
    // Step 1: Generate metadata
    console.log('\n📝 Step 1: Generating metadata...');
    const generator = new AudioGenerator(config);
    const result = await generator.generate();

    if (!result.validation.passed) {
      console.error('\n❌ Metadata generation failed:');
      result.validation.errors.forEach(e => console.error(`  - ${e}`));
      process.exit(1);
    }

    const tracks = result.generated.tracks;
    console.log(`✅ Generated ${tracks.length} track definitions`);

    // Write metadata
    if (!config.dryRun) {
      if (!fs.existsSync(config.outputDir)) {
        fs.mkdirSync(config.outputDir, { recursive: true });
      }

      const metadataPath = path.join(config.outputDir, 'metadata.json');
      fs.writeFileSync(metadataPath, JSON.stringify(result, null, 2));
      console.log(`✅ Metadata written: ${metadataPath}`);
    }

    // Step 2: Batch pre-render stems (browser context)
    console.log('\n🎼 Step 2: Pre-rendering stems...');
    if (config.dryRun) {
      console.log('📋 DRY RUN - skipping Tone.Offline rendering');
    } else {
      // Check if Puppeteer available (optional for now)
      try {
        const puppeteer = await import('puppeteer');
        console.log('✅ Puppeteer found, can render stems');
        // TODO: Spawn browser for Tone.Offline rendering
        // For now, just note that stems would be rendered here
      } catch (e) {
        console.warn('⚠️ Puppeteer not available, skipping offline rendering');
        console.log('   Install: npm install puppeteer');
      }
    }

    // Summary
    console.log(`\n📊 Pipeline Summary:`);
    console.log(`  - Tracks: ${tracks.length}`);
    console.log(`  - Categories:`);
    Object.entries(result.generated.manifest.categories).forEach(([cat, count]) => {
      console.log(`    • ${cat}: ${count}`);
    });
    console.log(`  - Vertentes:`);
    Object.entries(result.generated.manifest.vertentes).forEach(([vert, count]) => {
      console.log(`    • ${vert}: ${count}`);
    });

    console.log(`\n✅ Audio generation pipeline complete!`);
    console.log(`   Next: npm run dev && visit http://localhost:5173`);
    console.log(`   Then: MusicDirector will load stems and respond to game events`);

  } catch (err) {
    console.error('❌ Fatal error:', err);
    process.exit(1);
  }
}

main().catch(err => {
  console.error('Fatal error:', err);
  process.exit(1);
});

#!/usr/bin/env node

/**
 * test-synth.js
 * Direct audio synthesis in Node.js (no Tone.js, no browser needed)
 * Generate 4 WAV stems with oscillator synthesis
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const testStemsDir = path.join(path.dirname(__dirname), 'public', 'audio', 'test-stems');

// Ensure output dir exists
if (!fs.existsSync(testStemsDir)) {
  fs.mkdirSync(testStemsDir, { recursive: true });
}

const SAMPLE_RATE = 44100;
const DURATION_SECONDS = 30;
const TOTAL_SAMPLES = SAMPLE_RATE * DURATION_SECONDS;

// Oscillator functions (sample-based)
function sine(frequency, sampleRate, time) {
  return Math.sin(2 * Math.PI * frequency * time);
}

function square(frequency, sampleRate, time) {
  return sine(frequency, sampleRate, time) >= 0 ? 1 : -1;
}

function sawtooth(frequency, sampleRate, time) {
  const phase = (frequency * time) % 1;
  return 2 * phase - 1;
}

function triangle(frequency, sampleRate, time) {
  const phase = (frequency * time) % 1;
  return phase < 0.5 ? 4 * phase - 1 : 3 - 4 * phase;
}

/**
 * Generate test stem with oscillator-based groove
 */
function generateStem(vertente, bpm) {
  console.log(`  🎼 Synthesizing ${vertente}...`);

  const samples = new Float32Array(TOTAL_SAMPLES);
  const beatDuration = 60 / bpm;

  // Osc configs per vertente
  let grooveGen;
  switch (vertente) {
    case 'deep':
      grooveGen = generateDeepGroove(beatDuration, samples);
      break;
    case 'tech':
      grooveGen = generateTechGroove(beatDuration, samples);
      break;
    case 'progressive':
      grooveGen = generateProgressiveGroove(beatDuration, samples);
      break;
    case 'funky':
      grooveGen = generateFunkyGroove(beatDuration, samples);
      break;
  }

  // Normalize and reduce clipping
  let max = 0;
  for (let i = 0; i < samples.length; i++) {
    max = Math.max(max, Math.abs(samples[i]));
  }
  const gain = max > 0 ? 0.95 / max : 1;
  for (let i = 0; i < samples.length; i++) {
    samples[i] *= gain;
  }

  return samples;
}

function generateDeepGroove(beatDuration, samples) {
  const sampleRate = SAMPLE_RATE;
  let pos = 0;

  // Kick (quarter notes)
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 4); beat++) {
    const kickStart = beat * beatDuration * 4 * sampleRate;
    const kickDur = 0.12 * sampleRate;
    for (let i = 0; i < kickDur && kickStart + i < samples.length; i++) {
      const sample = sine(120, sampleRate, (kickStart + i) / sampleRate) * Math.exp(-i / (0.05 * sampleRate));
      samples[kickStart + i] += sample * 0.6;
    }
  }

  // Bass pad
  const bassFreq = 65;
  const bassStart = 0;
  const bassDur = samples.length;
  for (let i = bassStart; i < bassDur; i++) {
    samples[i] += sawtooth(bassFreq, sampleRate, i / sampleRate) * 0.2;
  }

  // Pad (triangle wave, slow)
  const padFreq = 130;
  for (let i = 0; i < samples.length; i++) {
    samples[i] += triangle(padFreq, sampleRate, i / sampleRate) * 0.15 * (0.5 + 0.5 * Math.sin(i / (0.5 * sampleRate)));
  }
}

function generateTechGroove(beatDuration, samples) {
  const sampleRate = SAMPLE_RATE;

  // Tight kick (8th notes)
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 0.5); beat++) {
    const kickStart = beat * beatDuration * 0.5 * sampleRate;
    const kickDur = 0.08 * sampleRate;
    for (let i = 0; i < kickDur && kickStart + i < samples.length; i++) {
      const sample = sine(100, sampleRate, (kickStart + i) / sampleRate) * Math.exp(-i / (0.04 * sampleRate));
      samples[kickStart + i] += sample * 0.7;
    }
  }

  // Bass (square, driving)
  const bassFreq = 110;
  for (let i = 0; i < samples.length; i++) {
    samples[i] += square(bassFreq, sampleRate, i / sampleRate) * 0.25;
  }

  // Stabs (sawtooth, percussive)
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 2); beat++) {
    const stabStart = beat * beatDuration * 2 * sampleRate + beatDuration * sampleRate;
    const stabDur = 0.15 * sampleRate;
    for (let i = 0; i < stabDur && stabStart + i < samples.length; i++) {
      const sample = sawtooth(330, sampleRate, (stabStart + i) / sampleRate) * Math.exp(-i / (0.08 * sampleRate));
      samples[stabStart + i] += sample * 0.3;
    }
  }
}

function generateProgressiveGroove(beatDuration, samples) {
  const sampleRate = SAMPLE_RATE;

  // Building kick (starts slow, gets tighter)
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 4); beat++) {
    const kickStart = beat * beatDuration * 4 * sampleRate;
    const decay = 0.08 + (beat * 0.0001);
    const kickDur = decay * sampleRate;
    for (let i = 0; i < kickDur && kickStart + i < samples.length; i++) {
      const sample = sine(100, sampleRate, (kickStart + i) / sampleRate) * Math.exp(-i / (decay * sampleRate));
      samples[kickStart + i] += sample * 0.65;
    }
  }

  // Bass (minimal, sustained C2)
  const bassFreq = 65;
  for (let i = 0; i < samples.length; i++) {
    samples[i] += sawtooth(bassFreq, sampleRate, i / sampleRate) * 0.15;
  }

  // Swelling pad (triangle, long envelope)
  const padFreq = 130;
  for (let i = 0; i < samples.length; i++) {
    const envelope = 0.3 + 0.5 * Math.sin(i / (1 * sampleRate));
    samples[i] += triangle(padFreq, sampleRate, i / sampleRate) * envelope * 0.12;
  }

  // Melody (last third, rising)
  const melodyStart = (2 * samples.length) / 3;
  const melodyFreqs = [262, 330, 392, 523]; // C4, E4, G4, C5
  let melodyIdx = 0;
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 3); beat++) {
    const noteStart = melodyStart + beat * beatDuration * 3 * sampleRate;
    const noteDur = beatDuration * 3 * sampleRate;
    const freq = melodyFreqs[melodyIdx % melodyFreqs.length];
    for (let i = 0; i < noteDur && noteStart + i < samples.length; i++) {
      const sample = square(freq, sampleRate, (noteStart + i) / sampleRate) * Math.exp(-i / (0.5 * sampleRate));
      samples[noteStart + i] += sample * 0.18;
    }
    melodyIdx++;
  }
}

function generateFunkyGroove(beatDuration, samples) {
  const sampleRate = SAMPLE_RATE;

  // Syncopated kick pattern
  const kickPattern = [0, 0.75, 2, 2.5, 3, 3.75];
  for (let beat = 0; beat < samples.length / sampleRate / (beatDuration * 4); beat++) {
    kickPattern.forEach((offset) => {
      const kickStart = (beat * 4 + offset) * beatDuration * 0.5 * sampleRate;
      if (kickStart < samples.length) {
        const kickDur = 0.12 * sampleRate;
        for (let i = 0; i < kickDur && kickStart + i < samples.length; i++) {
          const sample = sine(110, sampleRate, (kickStart + i) / sampleRate) * Math.exp(-i / (0.06 * sampleRate));
          samples[kickStart + i] += sample * 0.6;
        }
      }
    });
  }

  // Bouncy bass (6-note pattern)
  const bassBeat = beatDuration * (2 / 3);
  const bassFreqs = [65, 82.41, 97.99, 82.41, 65, 65]; // C2, D#2, F2, D#2, C2, C2
  for (let beat = 0; beat < samples.length / sampleRate / bassBeat; beat++) {
    const bassStart = beat * bassBeat * sampleRate;
    const freq = bassFreqs[beat % bassFreqs.length];
    const bassDur = 0.5 * sampleRate;
    for (let i = 0; i < bassDur && bassStart + i < samples.length; i++) {
      const sample = square(freq, sampleRate, (bassStart + i) / sampleRate) * Math.exp(-i / (0.1 * sampleRate));
      samples[bassStart + i] += sample * 0.2;
    }
  }

  // Melody (6-note pattern, retro square)
  const melodyBeat = beatDuration * (2 / 3);
  const melodyFreqs = [262, 330, 392, 466.16, 392, 330]; // C4, E4, G4, A#4, G4, E4
  for (let beat = 0; beat < samples.length / sampleRate / melodyBeat; beat++) {
    const noteStart = beat * melodyBeat * sampleRate;
    const freq = melodyFreqs[beat % melodyFreqs.length];
    const noteDur = 0.4 * sampleRate;
    for (let i = 0; i < noteDur && noteStart + i < samples.length; i++) {
      const sample = square(freq, sampleRate, (noteStart + i) / sampleRate) * Math.exp(-i / (0.08 * sampleRate));
      samples[noteStart + i] += sample * 0.15;
    }
  }
}

/**
 * Convert float samples to PCM 16-bit and write WAV file
 */
function writeStemToWav(stemName, samples) {
  const numChannels = 1;
  const sampleRate = SAMPLE_RATE;
  const bytesPerSample = 2;
  const blockAlign = numChannels * bytesPerSample;
  const byteRate = sampleRate * blockAlign;
  const dataSize = samples.length * bytesPerSample;

  // WAV header
  const header = Buffer.alloc(44);
  let offset = 0;

  // RIFF chunk descriptor
  header.write('RIFF', offset); offset += 4;
  header.writeUInt32LE(36 + dataSize, offset); offset += 4;
  header.write('WAVE', offset); offset += 4;

  // fmt sub-chunk
  header.write('fmt ', offset); offset += 4;
  header.writeUInt32LE(16, offset); offset += 4; // Subchunk1Size
  header.writeUInt16LE(1, offset); offset += 2;  // AudioFormat (1 = PCM)
  header.writeUInt16LE(numChannels, offset); offset += 2;
  header.writeUInt32LE(sampleRate, offset); offset += 4;
  header.writeUInt32LE(byteRate, offset); offset += 4;
  header.writeUInt16LE(blockAlign, offset); offset += 2;
  header.writeUInt16LE(16, offset); offset += 2; // BitsPerSample

  // data sub-chunk
  header.write('data', offset); offset += 4;
  header.writeUInt32LE(dataSize, offset); offset += 4;

  // Convert float samples to PCM 16-bit
  const pcmData = Buffer.alloc(dataSize);
  for (let i = 0; i < samples.length; i++) {
    const s = Math.max(-1, Math.min(1, samples[i]));
    const pcm = s < 0 ? s * 0x8000 : s * 0x7fff;
    pcmData.writeInt16LE(pcm, i * 2);
  }

  // Write file
  const filePath = path.join(testStemsDir, `${stemName}.wav`);
  fs.writeFileSync(filePath, Buffer.concat([header, pcmData]));
  console.log(`   💾 Saved: ${stemName}.wav (${(header.length + dataSize) / 1024 / 1024}.toFixed(2)} MB)`);
}

// Main
async function main() {
  console.log('🎵 ELIFOOT Audio Test Synth (Node.js)');
  console.log('\n🔊 Rendering 4 test stems (30s each)...');

  const stems = [
    { id: 'test_deep', vertente: 'deep', bpm: 115 },
    { id: 'test_tech', vertente: 'tech', bpm: 128 },
    { id: 'test_progressive', vertente: 'progressive', bpm: 122 },
    { id: 'test_funky', vertente: 'funky', bpm: 124 }
  ];

  for (const stem of stems) {
    const samples = generateStem(stem.vertente, stem.bpm);
    writeStemToWav(stem.id, samples);
  }

  console.log('\n✅ Done! 4 test stems synthesized');
  console.log(`📁 Files: ${testStemsDir}`);
}

main().catch(err => {
  console.error('❌ Error:', err.message);
  process.exit(1);
});

import React, { useState } from 'react';
import { useGame } from './context/GameContext';
import { StartView } from './components/StartView';
import { DashboardView } from './components/DashboardView';
import { PlayerDashboardView } from './components/PlayerDashboardView';
import { PlayerMatchView } from './components/PlayerMatchView';
import { SquadView } from './components/SquadView';
import { MarketView } from './components/MarketView';
import { StandingsView } from './components/StandingsView';
import { MatchView } from './components/MatchView';
import { MonitorView } from './components/MonitorView';
import { FloatingBugButton } from './components/FloatingBugButton';
import { Sidebar } from './components/Sidebar';
import { CosmeticShopView } from './components/CosmeticShopView';
import { AutoPlayView } from './components/AutoPlayView';
import { StyleguideView } from './components/StyleguideView';
import { AchievementsView } from './components/AchievementsView';
import { TutorialView } from './components/TutorialView';
import { PressView } from './components/PressView';
import { SaveSlotsView } from './components/SaveSlotsView';
import { RivalriesView } from './components/RivalriesView';
import { ChronicleView } from './components/ChronicleView';
import { isSoundEnabled, setSoundEnabled, sfx } from './utils/sound';
import { MonitorService } from './services/MonitorService';
import { AudioController } from './audio/AudioController.jsx';
import { EfButton } from './components/ui/EfButton';

// Install global error handlers (idempotente)
MonitorService.getInstance().install();

function App() {
    const { gameState, getEngine, saveGame, resetGame, changeView } = useGame();
    const [soundOn, setSoundOn] = useState(isSoundEnabled());
    const [savedToast, setSavedToast] = useState(false);


    const renderView = () => {
        switch (gameState.view) {
            case 'start': return <StartView />;
            case 'dashboard': return <DashboardView />;
            case 'player_dashboard': return <PlayerDashboardView />;
            case 'player_match': return <PlayerMatchView />;
            case 'match': return <MatchView />;
            case 'squad': return <SquadView />;
            case 'market': return <MarketView />;
            case 'standings': return <StandingsView />;
            case 'monitor': return <MonitorView />;
            case 'styleguide': return <StyleguideView />;
            case 'achievements': return <AchievementsView />;
            case 'tutorial': return <TutorialView />;
            case 'press': return <PressView />;
            case 'shop': return <CosmeticShopView />;
            case 'autoplay': return <AutoPlayView />;
            case 'saves': return <SaveSlotsView />;
            case 'rivalries': return <RivalriesView />;
            case 'chronicle': return <ChronicleView />;
            default: return <StartView />;
        }
    };

    const engine = getEngine();

    const handleSave = () => {
        if (saveGame) saveGame();
        sfx.success();
        setSavedToast(true);
        setTimeout(() => setSavedToast(false), 1500);
    };

    const handleSoundToggle = () => {
        const next = !soundOn;
        setSoundEnabled(next);
        setSoundOn(next);
        if (next) sfx.click();
    };

    const handleReset = () => {
        if (window.confirm('Apagar carreira e voltar pra tela inicial? Não tem como recuperar.')) {
            if (resetGame) resetGame();
        }
    };

    return (
        <div style={{ display: 'flex', minHeight: '100dvh', backgroundColor: '#000' }}>
            {gameState.started && gameState.view !== 'start' && gameState.view !== 'tutorial' && (
                <Sidebar />
            )}

            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', position: 'relative', overflowX: 'hidden' }}>
                {gameState.started && (
                    <header className="top-bar glass-panel">
                        <div className="logo">OléFUT</div>
                        <div className="user-info" style={{display:'flex',alignItems:'center',gap:'0.6rem'}}>
                            <span className="manager-name">{gameState.manager}</span>
                            {gameState.mode === 'player' && engine.proPlayer && (
                                <strong>R$ {engine.proPlayer.money}</strong>
                            )}
                            {gameState.mode === 'manager' && (
                                <span>Sem {engine.currentWeek}/38</span>
                            )}
                            {/* P2-13: save manual button */}
                            <EfButton
                                variant="secondary" size="sm"
                                onClick={handleSave}
                                title="Salvar manual (auto-save ativo)"
                                style={{padding:'0.25rem 0.55rem'}}
                            >
                                💾
                            </EfButton>
                            {/* P1-6: sound toggle */}
                            <EfButton
                                variant="secondary" size="sm"
                                onClick={handleSoundToggle}
                                title={soundOn ? 'Som ON (clique pra desligar)' : 'Som OFF (clique pra ligar)'}
                                style={{padding:'0.25rem 0.55rem'}}
                            >
                                {soundOn ? '🔊' : '🔇'}
                            </EfButton>

                            <EfButton
                                variant="secondary" size="sm"
                                onClick={() => changeView?.('monitor')}
                                title="Monitor (bugs/gameplay/feedback)"
                                style={{padding:'0.25rem 0.55rem'}}
                            >
                                📊
                            </EfButton>
                            <EfButton
                                variant="secondary" size="sm"
                                onClick={handleReset}
                                title="Resetar carreira"
                                style={{padding:'0.25rem 0.55rem'}}
                            >
                                🔄
                            </EfButton>
                        </div>
                        {savedToast && (
                            <div style={{position:'fixed',top:'4rem',right:'1rem',background:'#39FF14',color:'#111417',padding:'0.5rem 1rem',borderRadius:'0',fontSize:'0.85rem',fontWeight:600,zIndex:1000,animation:'slideUp 0.3s',border:'2px solid #4A5059',fontFamily:"'Press Start 2P', monospace"}}>
                                ✅ Salvo!
                            </div>
                        )}
                    </header>
                )}

                <main style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                    {renderView()}
                </main>

                <FloatingBugButton />
                <AudioController />
            </div>
        </div>
    );
}

export default App;

import React, { useMemo } from 'react';
import { useGame } from '../context/GameContext';
import { ACHIEVEMENTS, MILESTONES } from '../engine/systems/AchievementsSystem';
import { EfPanel, EfButton } from './ui';
import bgTrophyRoom from '../assets/environments/bg_trophy_room.png';

import { 
    Trophy, ArrowLeft, Star, LockKey, LockOpen, CheckCircle
} from '@phosphor-icons/react';

const RARITY_ORDER = { Common: 0, Uncommon: 1, Rare: 2, Legendary: 3 };
const RARITY_COLORS = {
    Common:    { bg: '#CD7F32', border: '#8B5A2B', label: 'BRONZE', text: '#FFF' },
    Uncommon:  { bg: '#C0C0C0', border: '#808080', label: 'PRATA', text: '#000' },
    Rare:      { bg: '#FFD700', border: '#AA8800', label: 'OURO', text: '#000' },
    Legendary: { bg: '#E040FB', border: '#9C27B0', label: 'PLATINA', text: '#FFF' }
};

function computeProgress(id, engine) {
    if (!engine) return 0;
    const stats = engine.managerStats || {};
    const matchesPlayed = (stats.wins || 0) + (stats.draws || 0) + (stats.losses || 0);
    const titles = engine.legacy?.titles?.length || 0;
    const seasons = engine.seasonNumber || 1;

    switch (id) {
        case 'Champion': return titles >= 1 ? 100 : 0;
        case 'Cup_winner': return engine.legacy?.cupTitles ? 100 : 0;
        case 'Back_to_back': return titles >= 2 ? 100 : (titles >= 1 ? 50 : 0);
        case 'Unbeaten': return Math.min(100, ((stats.streak || 0) / 20) * 100);
        case 'Rookie': return matchesPlayed >= 1 ? 100 : 0;
        case 'Iron_man': return Math.min(100, (matchesPlayed / 50) * 100);
        case 'Veteran_15': return Math.min(100, (seasons / 15) * 100);
        case '100_goals': {
            const goals = engine.proPlayer?.career?.totalGoals || 0;
            return Math.min(100, (goals / 100) * 100);
        }
        case 'Hat_trick': return engine.proPlayer?.career?.hatTricks > 0 ? 100 : 0;
        case 'Survivor': return seasons >= 1 ? 100 : 0; // simplified
        case 'Legend_tier': {
            const prestige = engine.legacy?.prestige || 0;
            return Math.min(100, (prestige / 1000) * 100);
        }
        default: return 0;
    }
}

export function AchievementsView() {
    const { changeView, getEngine, getDashboardView } = useGame();
    const engine = getEngine();

    const colors = {
        bg: '#0D1117',
        panelBg: '#161B22',
        panelElevated: '#1A1F24',
        border: '#2D3748',
        text: '#FDFBF7',
        textMuted: '#8E9E94',
        accent: '#39FF14',
        secondary: '#40BAF7',
        warning: '#FFD700',
        danger: '#FF3333'
    };

    const sorted = useMemo(() => {
        return Object.entries(ACHIEVEMENTS)
            .map(([id, ach]) => ({
                id,
                ...ach,
                progress: computeProgress(id, engine),
                unlocked: computeProgress(id, engine) >= 100
            }))
            .sort((a, b) => {
                if (b.unlocked !== a.unlocked) return b.unlocked - a.unlocked;
                return RARITY_ORDER[a.rarity] - RARITY_ORDER[b.rarity];
            });
    }, [engine]);

    const stats = useMemo(() => {
        const total = sorted.length;
        const unlocked = sorted.filter(a => a.unlocked).length;
        const totalReward = sorted.filter(a => a.unlocked).reduce((s, a) => s + a.reward, 0);
        return { total, unlocked, percent: Math.round((unlocked / total) * 100), totalReward };
    }, [sorted]);

    // Render continuous progress bar
    const renderProgressBar = (percent, color) => {
        return (
            <div style={{
                height: '8px',
                backgroundColor: colors.bg,
                border: `1px solid ${colors.border}`,
                overflow: 'hidden',
                flex: 1
            }}>
                <div style={{
                    height: '100%',
                    width: `${percent}%`,
                    backgroundColor: color,
                    transition: 'width 300ms ease-out'
                }} />
            </div>
        );
    };

    return (
        <div className="ef-anim-fade-in" style={{
            backgroundImage: `url(${bgTrophyRoom})`,
            imageRendering: 'pixelated',
            WebkitImageRendering: 'pixelated',
            backgroundColor: colors.bg,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundAttachment: 'fixed',
            minHeight: '100dvh',
            padding: '24px',
            color: colors.text,
            fontFamily: 'var(--font-sans)',
            overflowY: 'auto'
        }}>
            <div style={{ maxWidth: '1000px', margin: '0 auto', display: 'flex', flexDirection: 'column', gap: '24px' }}>

                {/* HEADER */}
                <EfPanel padding="lg" style={{ 
                    display: 'flex', 
                    justifyContent: 'space-between', 
                    alignItems: 'center',
                    borderBottom: `2px solid ${colors.secondary}`
                }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                        <div style={{ width: '48px', height: '48px', backgroundColor: colors.panelElevated, display: 'flex', justifyContent: 'center', alignItems: 'center', border: `1px solid ${colors.border}` }}>
                            <Trophy size={28} color={colors.secondary} />
                        </div>
                        <div>
                            <h2 style={{ margin: '0 0 4px 0', fontSize: '1.2rem', fontFamily: 'var(--font-sans)', color: colors.text, fontWeight: 'bold' }}>
                                CONQUISTAS
                            </h2>
                            <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.8rem', color: colors.textMuted }}>
                                DESAFIOS E MARCOS DA CARREIRA
                            </span>
                        </div>
                    </div>
                    <EfButton variant="secondary" size="md" onClick={() => changeView(getDashboardView())}>
                        <ArrowLeft size={16} /> SAIR
                    </EfButton>
                </EfPanel>

                {/* OVERALL PROGRESS */}
                <EfPanel padding="lg" style={{
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                    gap: '24px'
                }}>
                    <div style={{ textAlign: 'center', minWidth: '100px' }}>
                        <span style={{ display: 'block', fontFamily: 'var(--font-mono)', fontSize: '0.8rem', color: colors.textMuted, marginBottom: '8px', fontWeight: 'bold' }}>PONTOS</span>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '4px', fontFamily: 'var(--font-mono)', fontSize: '1.5rem', color: colors.warning, fontWeight: '800' }}>
                            <Star weight="fill" /> {stats.totalReward}
                        </div>
                    </div>

                    <div style={{ flex: 1 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontFamily: 'var(--font-mono)', fontSize: '0.8rem' }}>
                            <span style={{ color: colors.textMuted, fontWeight: 'bold' }}>PROGRESSO GERAL</span>
                            <span style={{ color: colors.secondary, fontWeight: 'bold' }}>{stats.unlocked} / {stats.total}</span>
                        </div>
                        <div style={{
                            height: '12px',
                            backgroundColor: colors.bg,
                            border: `1px solid ${colors.border}`,
                            overflow: 'hidden'
                        }}>
                            <div style={{
                                height: '100%',
                                width: `${stats.percent}%`,
                                backgroundColor: colors.secondary,
                                transition: 'width 300ms ease-out'
                            }} />
                        </div>
                    </div>

                    <div style={{ textAlign: 'center', minWidth: '100px' }}>
                        <span style={{ display: 'block', fontFamily: 'var(--font-mono)', fontSize: '0.8rem', color: colors.textMuted, marginBottom: '8px', fontWeight: 'bold' }}>COMPLETO</span>
                        <span style={{ fontFamily: 'var(--font-mono)', fontSize: '1.5rem', color: colors.accent, fontWeight: '800' }}>
                            {stats.percent}%
                        </span>
                    </div>
                </EfPanel>

                {/* ACHIEVEMENT CARDS */}
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                    {sorted.map(ach => {
                        const rarityColors = RARITY_COLORS[ach.rarity];
                        return (
                            <EfPanel
                                key={ach.id}
                                className={ach.unlocked ? 'ef-anim-fade-in' : ''}
                                style={{
                                    borderLeft: `4px solid ${ach.unlocked ? rarityColors.bg : colors.border}`,
                                    opacity: ach.unlocked ? 1 : 0.6,
                                    position: 'relative',
                                    overflow: 'hidden',
                                    display: 'flex',
                                    flexDirection: 'column'
                                }}
                            >
                                <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px', marginBottom: '12px' }}>
                                    <div style={{
                                        width: '48px', height: '48px', minWidth: '48px',
                                        backgroundColor: ach.unlocked ? rarityColors.bg : colors.bg,
                                        color: ach.unlocked ? rarityColors.text : colors.textMuted,
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        fontSize: '1.5rem',
                                        border: `2px solid ${ach.unlocked ? rarityColors.border : colors.border}`
                                    }}>
                                        {ach.badge}
                                    </div>
                                    <div style={{ flex: 1 }}>
                                        <div style={{ fontFamily: 'var(--font-sans)', fontSize: '1rem', color: colors.text, marginBottom: '4px', fontWeight: 'bold' }}>
                                            {ach.name}
                                        </div>
                                        <div style={{
                                            fontFamily: 'var(--font-mono)',
                                            fontSize: '0.75rem',
                                            color: ach.unlocked ? rarityColors.bg : colors.textMuted,
                                            fontWeight: 'bold',
                                            display: 'flex',
                                            alignItems: 'center',
                                            gap: '8px'
                                        }}>
                                            <span>{rarityColors.label}</span>
                                            <span style={{ color: colors.border }}>•</span>
                                            <span style={{ display: 'flex', alignItems: 'center', gap: '2px', color: ach.unlocked ? colors.warning : colors.textMuted }}>
                                                <Star weight="fill" /> {ach.reward} PTS
                                            </span>
                                        </div>
                                    </div>
                                    <div>
                                        {ach.unlocked ? (
                                            <CheckCircle size={24} color={colors.accent} weight="fill" />
                                        ) : (
                                            <LockKey size={24} color={colors.border} />
                                        )}
                                    </div>
                                </div>

                                <div style={{
                                    fontSize: '0.85rem',
                                    color: colors.textMuted,
                                    marginBottom: '16px',
                                    lineHeight: '1.5',
                                    fontFamily: 'var(--font-sans)',
                                    flex: 1
                                }}>
                                    {ach.desc}
                                </div>

                                {!ach.unlocked && ach.progress > 0 && (
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginTop: 'auto' }}>
                                        {renderProgressBar(ach.progress, rarityColors.bg)}
                                        <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.8rem', color: rarityColors.bg, fontWeight: 'bold' }}>
                                            {Math.round(ach.progress)}%
                                        </span>
                                    </div>
                                )}
                            </EfPanel>
                        );
                    })}
                </div>
            </div>
        </div>
    );
}

export default AchievementsView;

