                        🎯 GDD SYSTEMS STATUS — LIVE
                    </h3>
                    <div style={{
                        display: 'grid',
                        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                        gap: '6px',
                        fontSize: '0.75rem'
                    }}>
                        <GDDStatus
                            label="§12.4 #6 Scarcity"
                            emoji="⏰"
                            count={stats.decisions?.filter(d => d.action === 'SCARCITY_WINDOW').length || 0}
