import React, { useState, useEffect, useRef } from 'react';
import { FORMATION_PRESETS, getPreset, FORMATION_KEYS } from '../engine/FormationLayout';
import { EfTooltip, EfButton } from './ui';
import { ArrowsClockwise, FloppyDisk } from '@phosphor-icons/react';

const FIELD_W = 600;
const FIELD_H = 400;
const JERSEY_R = 22;

/**
 * FormationBoard — Drag/drop visual editor for tactical positioning
 * ELIFOOT classic style: campo verde + 11 camisas com nome/posição/número
 *
 * Props:
 *  - team: { id, name, squad[], formation, formationLayout? }
 *  - onSave: (newLayout) => void
 *  - onChange: (newLayout) => void  // optional live update
 *  - editable: bool (default true)
 *
 * Coords normalizadas [0,1]; canvas escala 600×400.
 */
export function FormationBoard({ team, onSave, onChange, editable = true }) {
    const [formation, setFormation] = useState(team?.formation || '4-3-3');
    const [layout, setLayout] = useState(() => buildInitialLayout(team, team?.formation || '4-3-3'));
    const [draggedSlot, setDraggedSlot] = useState(null);
    const fieldRef = useRef(null);

    const colors = {
        bg: '#0D1117',
        panelBg: '#161B22',
        panelElevated: '#1A1F24',
        border: '#2D3748',
        text: '#FDFBF7',
        textMuted: '#8E9E94',
        accent: '#39FF14',
        secondary: '#40BAF7',
        warning: '#FFD700',
        danger: '#FF3333',
        field: '#1E3A2F', // Darker, more premium green
        fieldLines: '#111417',
        jerseyBlue: '#1E40AF',
        jerseyGold: '#B8860B' // Premium gold for GK
    };

    useEffect(() => {
        // When formation changes, reset to preset layout (preserve player assignments by role)
        const preset = getPreset(formation);
        const newLayout = {};
        const titulares = (team?.squad || []).filter(p => p.isTitular).slice(0, 11);
        preset.forEach((slot, i) => {
            const player = titulares[i] || null;
            newLayout[slot.slot] = {
                playerId: player?.id || null,
                x: slot.x,
                y: slot.y,
                role: slot.role
            };
        });
        setLayout(newLayout);
        if (onChange) onChange(newLayout);
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [formation, team]);

    function handlePointerDown(e, slotIdx) {
        if (!editable) return;
        e.preventDefault();
        setDraggedSlot(slotIdx);
    }

    function handlePointerMove(e) {
        if (draggedSlot === null || !fieldRef.current) return;
        const rect = fieldRef.current.getBoundingClientRect();
        const x = (e.clientX - rect.left) / rect.width;
        const y = (e.clientY - rect.top) / rect.height;
        const cx = Math.max(0.05, Math.min(0.95, x));
        const cy = Math.max(0.05, Math.min(0.95, y));
        setLayout(prev => {
            const next = { ...prev, [draggedSlot]: { ...prev[draggedSlot], x: cx, y: cy } };
            if (onChange) onChange(next);
            return next;
        });
    }

    function handlePointerUp() {
        setDraggedSlot(null);
    }

    function resetToPreset() {
        const preset = getPreset(formation);
        const newLayout = {};
        const titulares = (team?.squad || []).filter(p => p.isTitular).slice(0, 11);
        preset.forEach((slot, i) => {
            const player = titulares[i] || null;
            newLayout[slot.slot] = {
                playerId: player?.id || null,
                x: slot.x,
                y: slot.y,
                role: slot.role
            };
        });
        setLayout(newLayout);
        if (onChange) onChange(newLayout);
    }

    function handleSave() {
        if (onSave) onSave({ formation, layout });
    }

    if (!team) return <div style={{ color: colors.textMuted, fontFamily: 'var(--font-mono)' }}>Time não encontrado.</div>;

    const playerById = {};
    (team.squad || []).forEach(p => { playerById[p.id] = p; });

    return (
        <div className="formation-board" style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {/* Formation selector */}
            <div style={{ display: 'flex', gap: '8px', alignItems: 'center', flexWrap: 'wrap', backgroundColor: colors.panelBg, padding: '12px', border: `1px solid ${colors.border}` }}>
                <span style={{ fontSize: '0.85rem', color: colors.textMuted, fontFamily: 'var(--font-mono)', marginRight: '8px' }}>ESQUEMA:</span>
                {FORMATION_KEYS.map(k => (
                    <EfTooltip key={k} content={`Mudar para ${k} — reorganiza posições padrão`}>
                        <EfButton
                            variant={formation === k ? 'primary' : 'secondary'} size="sm"
                            onClick={() => setFormation(k)}
                        >
                            {k}
                        </EfButton>
                    </EfTooltip>
                ))}

                <div style={{ flex: 1 }} />

                <EfTooltip content="Voltar para posições padrão da formação atual">
                    <EfButton variant="secondary" size="sm" onClick={resetToPreset} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <ArrowsClockwise size={16} /> RESET
                    </EfButton>
                </EfTooltip>

                {onSave && (
                    <EfButton variant="primary" size="sm" onClick={handleSave} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <FloppyDisk size={16} weight="fill" /> SALVAR
                    </EfButton>
                )}
            </div>

            {/* Field SVG */}
            <div
                ref={fieldRef}
                style={{
                    width: '100%',
                    maxWidth: FIELD_W,
                    aspectRatio: `${FIELD_W} / ${FIELD_H}`,
                    position: 'relative',
                    background: colors.field,
                    border: `4px solid ${colors.panelElevated}`,
                    overflow: 'hidden',
                    cursor: draggedSlot !== null ? 'grabbing' : 'default',
                    touchAction: 'none',
                    margin: '0 auto',
                    boxShadow: `inset 0 0 40px #040805`
                }}
                onPointerMove={handlePointerMove}
                onPointerUp={handlePointerUp}
                onPointerLeave={handlePointerUp}
            >
                <svg viewBox={`0 0 ${FIELD_W} ${FIELD_H}`} width="100%" height="100%" style={{ display: 'block' }}>
                    {/* Field lines */}
                    <rect x="4" y="4" width={FIELD_W - 8} height={FIELD_H - 8} fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <line x1="0" y1={FIELD_H / 2} x2={FIELD_W} y2={FIELD_H / 2} stroke={colors.fieldLines} strokeWidth="2" />
                    <circle cx={FIELD_W / 2} cy={FIELD_H / 2} r="48" fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <circle cx={FIELD_W / 2} cy={FIELD_H / 2} r="3" fill={colors.fieldLines} />

                    {/* Top goal box */}
                    <rect x={FIELD_W / 2 - 100} y="0" width="200" height="70" fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <rect x={FIELD_W / 2 - 40} y="0" width="80" height="24" fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <path d={`M ${FIELD_W / 2 - 40} 70 A 40 40 0 0 0 ${FIELD_W / 2 + 40} 70`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />

                    {/* Bottom goal box */}
                    <rect x={FIELD_W / 2 - 100} y={FIELD_H - 70} width="200" height="70" fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <rect x={FIELD_W / 2 - 40} y={FIELD_H - 24} width="80" height="24" fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <path d={`M ${FIELD_W / 2 - 40} ${FIELD_H - 70} A 40 40 0 0 1 ${FIELD_W / 2 + 40} ${FIELD_H - 70}`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />

                    {/* Corner arcs */}
                    <path d={`M 0 16 A 16 16 0 0 0 16 0`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <path d={`M ${FIELD_W - 16} 0 A 16 16 0 0 0 ${FIELD_W} 16`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <path d={`M 0 ${FIELD_H - 16} A 16 16 0 0 1 16 ${FIELD_H}`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />
                    <path d={`M ${FIELD_W - 16} ${FIELD_H} A 16 16 0 0 1 ${FIELD_W} ${FIELD_H - 16}`} fill="none" stroke={colors.fieldLines} strokeWidth="2" />

                    {/* Jerseys (11 slots) */}
                    {Object.entries(layout).map(([slotIdx, pos]) => {
                        const player = pos.playerId ? playerById[pos.playerId] : null;
                        const cx = pos.x * FIELD_W;
                        const cy = pos.y * FIELD_H;
                        const isDragging = draggedSlot === Number(slotIdx);
                        const isGk = pos.role === 'GOL';
                        const fillColor = isGk ? colors.jerseyGold : colors.jerseyBlue;
                        const strokeColor = isGk ? '#8B6508' : '#1E3A8A';

                        return (
                            <g
                                key={slotIdx}
                                transform={`translate(${cx}, ${cy})`}
                                style={{ cursor: editable ? 'grab' : 'default', transition: isDragging ? 'none' : 'transform 0.2s ease-out' }}
                                onPointerDown={(e) => handlePointerDown(e, Number(slotIdx))}
                            >
                                {/* Shadow */}
                                <circle r={JERSEY_R} fill="#040805" cy={isDragging ? 8 : 4} cx={isDragging ? 4 : 2} />

                                {/* Jersey Base */}
                                <circle r={JERSEY_R} fill={fillColor} stroke={colors.text} strokeWidth="2" opacity={isDragging ? 0.8 : 1} 
                                        style={{ filter: isDragging ? 'brightness(1.2)' : 'none' }} />

                                {/* OVR */}
                                <text y="4" textAnchor="middle" fill={colors.text} fontSize="14" fontWeight="bold" fontFamily="var(--font-mono)">
                                    {player?.ovr || '?'}
                                </text>

                                {/* Player Name Background */}
                                <rect x="-30" y="24" width="60" height="14" rx="4" fill="#111417" />

                                {/* Player Name */}
                                <text y="34" textAnchor="middle" fill={colors.text} fontSize="9" fontWeight="600" fontFamily="var(--font-sans)">
                                    {player?.name?.split(' ')[0]?.slice(0, 8) || 'VAZIO'}
                                </text>

                                {/* Role Badge Background */}
                                <rect x="-16" y="40" width="32" height="12" rx="2" fill={colors.panelElevated} stroke={colors.border} strokeWidth="1" />

                                {/* Role */}
                                <text y="49" textAnchor="middle" fill={colors.secondary} fontSize="8" fontWeight="bold" fontFamily="var(--font-mono)">
                                    {pos.role}
                                </text>
                            </g>
                        );
                    })}
                </svg>
            </div>

            <div style={{ fontSize: '0.8rem', color: colors.textMuted, textAlign: 'center', fontFamily: 'var(--font-mono)', padding: '8px', backgroundColor: '#0E1F14', }}>
                {editable ? '👆 ARRASTE OS JOGADORES PARA AJUSTAR O POSICIONAMENTO EM CAMPO' : '👁️ VISUALIZAÇÃO DA FORMAÇÃO TÁTICA'}
            </div>
        </div>
    );
}

function buildInitialLayout(team, formationId) {
    if (team?.formationLayout) return team.formationLayout;
    const preset = getPreset(formationId);
    const result = {};
    const titulares = (team?.squad || []).filter(p => p.isTitular).slice(0, 11);
    preset.forEach((slot, i) => {
        const player = titulares[i] || null;
        result[slot.slot] = {
            playerId: player?.id || null,
            x: slot.x,
            y: slot.y,
            role: slot.role
        };
    });
    return result;
}

export default FormationBoard;

import React, { useEffect, useRef, useCallback, useState } from 'react';
import { EfButton } from './ui/EfButton';

/**
 * §12.4 Octalysis #6: Scarcity Emphasis
 * Shows urgency indicators for deadlines, rare events, limited resources
 */
export function ScarcityBanner({ engine }) {
    const team = engine?.getTeam(engine.manager?.teamId);
    if (!team) return null;

    const seasonWeek = ((engine.currentWeek - 1) % 38) + 1;
    const items = [];

    // Transfer window closing (weeks 1-4 and 20-22 are windows)
    if (seasonWeek >= 18 && seasonWeek <= 20) {
        items.push({ emoji: '⏰', text: `Janela fecha em ${22 - seasonWeek} semanas!`, color: '#f59e0b' });
    }
    if (seasonWeek >= 21 && seasonWeek <= 22) {
        items.push({ emoji: '🚨', text: 'ÚLTIMA CHANCE — janela fecha!', color: '#ef4444' });
    }

    // Budget scarcity
    if ((team.balance || 0) < 500000 && seasonWeek > 5) {
        items.push({ emoji: '💸', text: `Caixa crítico: R$${Math.round((team.balance || 0) / 1000)}k`, color: '#ef4444' });
    }

    // Expiring contracts
    const expiring = team.squad?.filter(p => p.contract && p.contract.weeksLeft <= 4) || [];
    if (expiring.length > 0) {
        items.push({ emoji: '📋', text: `${expiring.length} contrato${expiring.length > 1 ? 's' : ''} expirando!`, color: '#f59e0b' });
    }

    if (items.length === 0) return null;

    return (
        <div className="scarcity-banner">
            {items.map((item, i) => (
                <span key={i} className="scarcity-item" style={{ color: item.color }}>
                    {item.emoji} {item.text}
                </span>
            ))}
        </div>
    );
}

/**
 * §12.4 Octalysis #8: Loss Avoidance "Dread" Visual
 * Shows relegation danger zone with pulsing red when at risk
 */
export function DreadIndicator({ engine }) {
    const team = engine?.getTeam(engine.manager?.teamId);
    if (!team) return null;

    const standings = engine.getStandings(team.zone, team.division);
    const pos = standings?.findIndex(s => s.teamId === team.id);
    const total = standings?.length || 20;
    const isRelegation = pos !== undefined && pos >= total - 4;
    const isClose = pos !== undefined && pos >= total - 6 && pos < total - 4;

    const boardConf = engine.board?.confidence ?? 60;
    const isFiring = boardConf < 20;

    if (!isRelegation && !isClose && !isFiring) return null;

    return (
        <div className={`dread-indicator ${isRelegation ? 'dread-critical' : 'dread-warning'}`}>
            {isRelegation && <span className="dread-pulse">⚠️ ZONA DE REBAIXAMENTO — {total - pos}º do fundo</span>}
            {isClose && !isRelegation && <span>😰 Perto da zona — {pos + 1}º lugar</span>}
            {isFiring && <span className="dread-pulse">🔥 DIRETORIA FURIOSA — Demissão iminente ({boardConf}%)</span>}
        </div>
    );
}

/**
 * §22.7 Keyboard Navigation Hook
 * Adds keyboard shortcuts to main game views
 */
export function useKeyboardNav({ changeView, onAdvanceWeek, currentView }) {
    useEffect(() => {
        const handler = (e) => {
            // Don't capture when typing in inputs
            if (e.target.tagName === 'INPUT' || e.target.tagName === 'SELECT' || e.target.tagName === 'TEXTAREA') return;

            switch (e.key) {
                case ' ': // Space = advance week (if on dashboard)
                case 'Enter':
                    if (currentView === 'dashboard' && onAdvanceWeek) {
                        e.preventDefault();
                        onAdvanceWeek();
                    }
                    break;
                case '1': changeView?.('dashboard'); break;
                case '2': changeView?.('squad'); break;
                case '3': changeView?.('market'); break;
                case '4': changeView?.('standings'); break;
                case '5': changeView?.('press'); break;
                case 'Escape': changeView?.('dashboard'); break;
                default: break;
            }
        };

        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [changeView, onAdvanceWeek, currentView]);
}

/**
 * §22.4 Ironman Mode
 * Save behavior utilities for single-slot autosave
 */
export const IronmanMode = {
    isActive: () => {
        try { return localStorage.getItem('elifoot_ironman') === 'true'; } catch { return false; } // storage unavailable
    },
    activate: () => {
        try { localStorage.setItem('elifoot_ironman', 'true'); } catch { /* ignore */ }
    },
    deactivate: () => {
        try { localStorage.removeItem('elifoot_ironman'); } catch { /* ignore */ }
    },
    /**
     * In ironman mode, autosave after every match week.
     * Seed is stored in save to prevent save-scumming.
     */
    autoSave: (engine, saveFunc) => {
        if (!IronmanMode.isActive()) return;
        if (typeof saveFunc === 'function') {
            saveFunc();
        }
    },
};

/**
 * §17 Tutorial Guide — Step-by-step guided tutorial overlay
 */
const TUTORIAL_STEPS = [
    {
        id: 'welcome',
        target: null,
        title: 'Bem-vindo ao OléFUT! ⚽',
        text: 'Você é o novo treinador. Vamos aprender o básico em 5 passos rápidos.',
        action: null,
    },
    {
        id: 'formation',
        target: 'Táticas',
        title: '1️⃣ Escolha sua Formação',
        text: 'Role até a seção de táticas e escolha uma formação. 4-3-3 é equilibrada para começar.',
        action: 'Clique em uma formação',
    },
    {
        id: 'training',
        target: 'Treino',
        title: '2️⃣ Treine o Elenco',
        text: 'Treinos semanais melhoram os atributos dos jogadores. Escolha um tipo de treino.',
        action: 'Clique em um treino',
    },
    {
        id: 'play',
        target: 'Jogar',
        title: '3️⃣ Avance a Semana',
        text: 'Clique no botão "Jogar Rodada" para simular a partida. Observe o resultado!',
        action: 'Clique em Jogar Rodada',
    },
    {
        id: 'adjust',
        target: null,
        title: '4️⃣ Reaja e Ajuste',
        text: 'Depois do jogo, leia os eventos, verifique lesões, e ajuste a tática se necessário.',
        action: null,
    },
    {
        id: 'done',
        target: null,
        title: '5️⃣ Pronto! 🎉',
        text: 'Você domina o básico. Explore transferências, base, e scouts para ir além. Boa sorte, treinador!',
        action: null,
    },
];

export function TutorialOverlay({ visible, onDismiss }) {
    const [step, setStep] = useState(0);

    if (!visible) return null;

    const current = TUTORIAL_STEPS[step];
    const isLast = step === TUTORIAL_STEPS.length - 1;

    return (
        <div className="tutorial-overlay" onClick={(e) => e.stopPropagation()}>
            <div className="tutorial-card">
                <div className="tutorial-progress">
                    {TUTORIAL_STEPS.map((_, i) => (
                        <span key={i} className={`tutorial-dot ${i <= step ? 'active' : ''}`} />
                    ))}
                </div>
                <h3 className="tutorial-title">{current.title}</h3>
                <p className="tutorial-text">{current.text}</p>
                {current.action && (
                    <p className="tutorial-action">👉 {current.action}</p>
                )}
                <div className="tutorial-buttons" style={{ display: 'flex', gap: '0.5rem', justifyContent: 'center' }}>
                    <EfButton variant="secondary" size="sm" onClick={() => {
                        try { localStorage.setItem('elifoot_tutorial_done', 'true'); } catch { /* storage full */ }
                        onDismiss();
                    }}>Pular tutorial</EfButton>
                    <EfButton variant="primary" size="sm" onClick={() => {
                        if (isLast) {
                            try { localStorage.setItem('elifoot_tutorial_done', 'true'); } catch { /* storage full */ }
                            onDismiss();
                        } else {
                            setStep(s => s + 1);
                        }
                    }}>{isLast ? 'Começar!' : 'Próximo →'}</EfButton>
                </div>
            </div>
        </div>
    );
}

/**
 * §17 Session Time Metrics
 * Tracks session duration and actions per minute
 */
export class SessionMetrics {
    constructor() {
        this.startTime = Date.now();
        this.actions = 0;
        this.matchesPlayed = 0;
    }

    recordAction() { this.actions++; }
    recordMatch() { this.matchesPlayed++; }

    getMetrics() {
        const elapsed = (Date.now() - this.startTime) / 1000 / 60; // minutes
        return {
            sessionMinutes: Math.round(elapsed * 10) / 10,
            actionsPerMinute: elapsed > 0 ? Math.round((this.actions / elapsed) * 10) / 10 : 0,
            matchesPerMinute: elapsed > 0 ? Math.round((this.matchesPlayed / elapsed) * 10) / 10 : 0,
            avgSecondsPerMatch: this.matchesPlayed > 0
                ? Math.round((elapsed * 60) / this.matchesPlayed) : 0,
        };
    }

    /** §12.1 — "One More Match" check: are sessions under 5 min per match? */
    isCoreLoopFast() {
        const m = this.getMetrics();
        return m.avgSecondsPerMatch > 0 && m.avgSecondsPerMatch < 300; // < 5 min
    }
}

import React from 'react';
import { EfTooltip } from './ui';
import { getTooltip } from '../data/tooltipsLoader';

/**
 * Help — Tooltip wrapper that pulls content from tooltips.json by ID
 *
 * Usage:
 *   <Help id="stat.ovr"><span>OVR 78</span></Help>
 *   <Help id="btn.train" position="bottom"><button>Treinar</button></Help>
 *
 * If `id` not found in tooltips.json, falls back to the optional `fallback` prop.
 * If still no content, renders children unwrapped.
 */
export function Help({ id, fallback, position = 'auto', delay = 300, children, className = '' }) {
    const content = getTooltip(id) || fallback;
    if (!content) return children;
    return (
        <EfTooltip content={content} position={position} delay={delay} className={className}>
            {children}
        </EfTooltip>
    );
}

export default Help;

/**
 * HexagonChart — SPEC-080
 *
 * Radar chart 6 attrs (FIN/TEC/CRI/TAC/DEF/FIS or GOL variants).
 * SVG-based, sem libs externas.
 */

import React from 'react';

export function HexagonChart({ player, size = 200, showLabels = true }) {
    const cx = size / 2;
    const cy = size / 2;
    const radius = size * 0.4;

    // 6 vertices spaced evenly
    const angle = (i) => (Math.PI * 2 * i) / 6 - Math.PI / 2;

    const p = player || {};
    const attrs = p.attributes || { FIS: 50, DEF: 50, CRI: 50, FIN: 50, REF: 50 };

    // Configura 6 eixos baseado na posição
    let chartAttrs = [];
    if (p.position === 'GOL' || p.naturalPosition === 'GOL') {
        chartAttrs = [
            { key: 'REF', label: 'REF', value: attrs.REF || 50, color: '#3A7DCE' },
            { key: 'DEF', label: 'POS', value: attrs.DEF || 50, color: '#7B2CBF' }, // Positioning
            { key: 'CRI', label: 'B.P', value: attrs.CRI || 50, color: '#FFD700' }, // Bola Parada
            { key: 'FIS', label: 'AGI', value: attrs.FIS || 50, color: '#E59866' }, // Agility
            { key: 'OVR', label: 'OVR', value: p.ovr || 50, color: '#39FF14' },
            { key: 'POT', label: 'POT', value: p.potential || p.ovr || 50, color: '#40BAF7' }
        ];
    } else {
        chartAttrs = [
            { key: 'FIN', label: 'FIN', value: attrs.FIN || 50, color: '#D62828' }, // Finalização
            { key: 'TEC', label: 'TEC', value: Math.floor(((attrs.FIN || 50) + (attrs.CRI || 50)) / 2), color: '#3A7DCE' }, // Técnica
            { key: 'CRI', label: 'CRI', value: attrs.CRI || 50, color: '#FFD700' }, // Criação
            { key: 'TAC', label: 'TAC', value: Math.floor(((attrs.DEF || 50) + (attrs.CRI || 50)) / 2), color: '#7B2CBF' }, // Tática
            { key: 'DEF', label: 'DEF', value: attrs.DEF || 50, color: '#2D5A3D' }, // Defesa
            { key: 'FIS', label: 'FIS', value: attrs.FIS || 50, color: '#E59866' }  // Físico
        ];
    }

    // Background hexagon
    const bgPoints = chartAttrs.map((_, i) => {
        const a = angle(i);
        return `${cx + radius * Math.cos(a)},${cy + radius * Math.sin(a)}`;
    }).join(' ');

    // Player values hexagon
    const playerPoints = chartAttrs.map((attr, i) => {
        const value = Math.max(1, Math.min(100, attr.value)) / 100;
        const a = angle(i);
        return `${cx + radius * value * Math.cos(a)},${cy + radius * value * Math.sin(a)}`;
    }).join(' ');

    // Concentric rings (25/50/75/100)
    const rings = [0.25, 0.5, 0.75, 1.0].map(r => {
        return chartAttrs.map((_, i) => {
            const a = angle(i);
            return `${cx + radius * r * Math.cos(a)},${cy + radius * r * Math.sin(a)}`;
        }).join(' ');
    });

    return (
        <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
            {/* Concentric rings */}
            {rings.map((points, i) => (
                <polygon
                    key={i}
                    points={points}
                    fill="none"
                    stroke="#0E1F14"
                    strokeWidth="1"
                />
            ))}

            {/* Axis lines */}
            {chartAttrs.map((_, i) => {
                const a = angle(i);
                return (
                    <line
                        key={i}
                        x1={cx}
                        y1={cy}
                        x2={cx + radius * Math.cos(a)}
                        y2={cy + radius * Math.sin(a)}
                        stroke="#0E1F14"
                        strokeWidth="1"
                    />
                );
            })}

            {/* Player polygon (filled) */}
            <polygon
                points={playerPoints}
                fill="#1B4332"
                stroke="#39FF14"
                strokeWidth="2"
                style={{ opacity: 0.8 }}
            />

            {/* Vertex dots colored per attr */}
            {chartAttrs.map((attr, i) => {
                const value = Math.max(1, Math.min(100, attr.value)) / 100;
                const a = angle(i);
                const x = cx + radius * value * Math.cos(a);
                const y = cy + radius * value * Math.sin(a);
                return (
                    <circle key={attr.key} cx={x} cy={y} r="4" fill={attr.color} stroke="#0F1A14" strokeWidth="1" />
                );
            })}

            {/* Labels */}
            {showLabels && chartAttrs.map((attr, i) => {
                const a = angle(i);
                const labelRadius = radius * 1.18;
                const x = cx + labelRadius * Math.cos(a);
                const y = cy + labelRadius * Math.sin(a);
                return (
                    <g key={attr.key}>
                        <text
                            x={x}
                            y={y}
                            textAnchor="middle"
                            dominantBaseline="central"
                            fontSize="10"
                            fontWeight="700"
                            fill={attr.color}
                        >
                            {attr.label}
                        </text>
                        <text
                            x={x}
                            y={y + 12}
                            textAnchor="middle"
                            dominantBaseline="central"
                            fontSize="9"
                            fill="#fff"
                        >
                            {Math.round(attr.value)}
                        </text>
                    </g>
                );
            })}
        </svg>
    );
}

export default HexagonChart;

import React, { useState } from 'react';
import { TACTICS } from '../engine/ManagerSystems';
import { Help } from './Help';
import { EfTooltip, EfModal, EfButton } from './ui';
import { 
    ArrowsLeftRight, Strategy, Lightning, Users, CheckCircle, Warning, XCircle, Play
} from '@phosphor-icons/react';

const MAX_LIVE_SUBS = 5;

/**
 * LiveSquadEditModal — Modal aberto durante pause da partida ao vivo
 *
 * Permite:
 * - Substituições live (até 5/jogo, FIFA realista)
 * - Mudança tática (sem cooldown)
 * - Visualização energia/moral plantel atual
 *
 * Limitação v1.0: subs visuais + state commit, não recalcula resultado
 * (engine sync). Refactor para generator é v1.3.
 */
export function LiveSquadEditModal({ team, engine, currentMinute, liveSubsCount, onSubMade, onClose }) {
    const [selectedOut, setSelectedOut] = useState(null);
    const [tactic, setTactic] = useState(engine.currentTactic);
    const [feedback, setFeedback] = useState('');

    const colors = {
        bg: '#0D1117',
        panelBg: '#161B22',
        panelElevated: '#1A1F24',
        border: '#2D3748',
        text: '#FDFBF7',
        textMuted: '#8E9E94',
        accent: '#39FF14',
        secondary: '#40BAF7',
        warning: '#FFD700',
        danger: '#FF3333'
    };

    if (!team) return null;

    const titulares = team.squad.filter(p => p.isTitular && !p.injury);
    const reserves = team.squad.filter(p => !p.isTitular && !p.injury && p.energy > 10);

    const subsLeft = MAX_LIVE_SUBS - liveSubsCount;

    const handleSub = (outPlayer, inPlayer) => {
        if (subsLeft <= 0) {
            setFeedback('error:Limite de 5 substituições atingido.');
            return;
        }
        if (engine.applyLiveSubstitution) {
            const result = engine.applyLiveSubstitution(outPlayer.id, inPlayer.id, currentMinute);
            if (result?.success) {
                setFeedback(`success:${outPlayer.name} substituído por ${inPlayer.name} aos ${currentMinute}'`);
                setSelectedOut(null);
                onSubMade();
            } else {
                setFeedback(`error:${result?.msg || 'Erro na substituição.'}`);
            }
        } else {
            // Fallback inline if engine method missing
            outPlayer.isTitular = false;
            inPlayer.isTitular = true;
            inPlayer.energy = Math.min(100, inPlayer.energy + 10);
            outPlayer.energy = Math.max(outPlayer.energy, 30);
            setFeedback(`success:${outPlayer.name} substituído por ${inPlayer.name} aos ${currentMinute}'`);
            setSelectedOut(null);
            onSubMade();
        }
    };

    const handleTacticChange = (newTacticKey) => {
        if (engine.setTactic) {
            engine.setTactic(newTacticKey);
            setTactic(newTacticKey);
            setFeedback(`success:Tática alterada para ${TACTICS[newTacticKey]?.name}`);
        }
    };

    const isFeedbackSuccess = feedback.startsWith('success:');
    const isFeedbackError = feedback.startsWith('error:');
    const cleanFeedback = feedback.replace('success:', '').replace('error:', '');

    return (
        <EfModal
            open={true}
            onClose={onClose}
            title={
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                    <Strategy size={24} color={colors.secondary} /> 
                    <span>GESTÃO TÁTICA ({currentMinute}')</span>
                </div>
            }
            size="md"
            footer={
                <EfButton variant="primary" onClick={onClose} size="lg" style={{ width: '100%', display: 'flex', gap: '8px' }}>
                    RETOMAR PARTIDA <Play weight="fill" />
                </EfButton>
            }
        >
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>

                {/* Status Bar */}
                <div style={{ display: 'flex', gap: '12px' }}>
                    <EfTooltip content="Limite FIFA: 5 substituições por jogo">
                        <div style={{
                            flex: 1,
                            backgroundColor: colors.bg,
                            padding: '12px',
                            border: `1px solid ${subsLeft <= 0 ? colors.danger : colors.border}`,
                            display: 'flex',
                            flexDirection: 'column',
                            alignItems: 'center',
                            gap: '4px'
                        }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.8rem', color: colors.textMuted, fontFamily: 'var(--font-mono)' }}>
                                <ArrowsLeftRight size={16} /> SUBSTITUIÇÕES
                            </div>
                            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', fontFamily: 'var(--font-mono)', color: subsLeft <= 0 ? colors.danger : colors.text }}>
                                {liveSubsCount} / {MAX_LIVE_SUBS}
                            </div>
                        </div>
                    </EfTooltip>
                </div>

                {/* Feedback */}
                {feedback && (
                    <div style={{
                        backgroundColor: isFeedbackSuccess ? '#1B4332' : '#8B0000',
                        border: `1px solid ${isFeedbackSuccess ? colors.accent : colors.danger}`,
                        color: isFeedbackSuccess ? colors.accent : colors.danger,
                        padding: '12px 16px',
                        fontSize: '0.9rem',
                        fontFamily: 'var(--font-mono)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '8px'
                    }}>
                        {isFeedbackSuccess ? <CheckCircle size={20} /> : <Warning size={20} />}
                        {cleanFeedback}
                    </div>
                )}

                {/* Tactic switch */}
                <div>
                    <Help id="btn.set_tactics">
                        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem', color: colors.textMuted, marginBottom: '12px', fontFamily: 'var(--font-mono)' }}>
                            <Strategy size={16} /> TÁTICA ATUAL
                        </div>
                    </Help>
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: '8px' }}>
                        {Object.entries(TACTICS).map(([k, v]) => (
                            <EfTooltip key={k} content={v.description || `Tática ${v.name}`}>
                                <EfButton
                                    variant={tactic === k ? 'primary' : 'secondary'}
                                    size="sm"
                                    onClick={() => handleTacticChange(k)}
                                >
                                    {v.name}
                                </EfButton>
                            </EfTooltip>
                        ))}
                    </div>
                </div>

                {/* Substituição UI */}
                {subsLeft > 0 && (
                    <div style={{ borderTop: `1px solid ${colors.border}`, paddingTop: '20px' }}>
                        {!selectedOut && (
                            <div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem', color: colors.textMuted, marginBottom: '12px', fontFamily: 'var(--font-mono)' }}>
                                    <Users size={16} /> SUBSTITUIR QUEM?
                                </div>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', maxHeight: '250px', overflowY: 'auto', paddingRight: '4px' }}>
                                    {titulares.map(p => {
                                        const energyColor = p.energy < 50 ? colors.danger : p.energy < 75 ? colors.warning : colors.accent;
                                        return (
                                            <div key={p.id} style={{
                                                display: 'flex',
                                                justifyContent: 'space-between',
                                                alignItems: 'center',
                                                padding: '10px 12px',
                                                backgroundColor: colors.bg,
                                                border: `1px solid ${colors.border}`,
                                                cursor: 'pointer',
                                                transition: 'all 0.15s ease'
                                            }} 
                                            onClick={() => setSelectedOut(p)}
                                            onMouseEnter={e => e.currentTarget.style.borderColor = colors.secondary}
                                            onMouseLeave={e => e.currentTarget.style.borderColor = colors.border}
                                            >
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                                    <span style={{ 
                                                        backgroundColor: colors.panelElevated, 
                                                        color: colors.textMuted, 
                                                        padding: '2px 6px', 
                                                        fontSize: '0.75rem', 
                                                        fontFamily: 'var(--font-mono)',
                                                        width: '36px',
                                                        textAlign: 'center'
                                                    }}>
                                                        {p.position}
                                                    </span>
                                                    <span style={{ fontFamily: 'var(--font-sans)', fontWeight: '600' }}>{p.name}</span>
                                                </div>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '4px', color: energyColor, fontSize: '0.8rem', fontFamily: 'var(--font-mono)' }}>
                                                    <Lightning size={14} weight="fill" /> {p.energy}%
                                                </div>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        )}

                        {selectedOut && (
                            <div>
                                <div style={{
                                    backgroundColor: '#8B0000',
                                    border: `1px solid ${colors.danger}`,
                                    padding: '12px',
                                    marginBottom: '16px',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center'
                                }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                                        <XCircle size={20} color={colors.danger} />
                                        <span style={{ color: colors.danger, fontFamily: 'var(--font-mono)', fontSize: '0.9rem' }}>SAINDO:</span>
                                        <strong style={{ fontFamily: 'var(--font-sans)' }}>{selectedOut.name} ({selectedOut.position})</strong>
                                    </div>
                                    <EfButton variant="secondary" size="sm" onClick={() => setSelectedOut(null)}>CANCELAR</EfButton>
                                </div>

                                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem', color: colors.textMuted, marginBottom: '12px', fontFamily: 'var(--font-mono)' }}>
                                    <Users size={16} /> ESCOLHER RESERVA
                                </div>

                                <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', maxHeight: '200px', overflowY: 'auto', paddingRight: '4px' }}>
                                    {reserves.length === 0 && (
                                        <div style={{ color: colors.textMuted, fontSize: '0.85rem', textAlign: 'center', padding: '24px 0', fontFamily: 'var(--font-mono)' }}>
                                            NENHUM RESERVA COM ENERGIA DISPONÍVEL
                                        </div>
                                    )}
                                    {reserves.map(p => (
                                        <div key={p.id} style={{
                                            display: 'flex',
                                            justifyContent: 'space-between',
                                            alignItems: 'center',
                                            padding: '8px 12px',
                                            backgroundColor: colors.bg,
                                            border: `1px solid ${colors.border}`
                                        }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                                                <span style={{ 
                                                    backgroundColor: colors.panelElevated, 
                                                    color: colors.textMuted, 
                                                    padding: '2px 6px', 
                                                    fontSize: '0.75rem', 
                                                    fontFamily: 'var(--font-mono)',
                                                    width: '36px',
                                                    textAlign: 'center'
                                                }}>
                                                    {p.position}
                                                </span>
                                                <div style={{ display: 'flex', flexDirection: 'column' }}>
                                                    <span style={{ fontFamily: 'var(--font-sans)', fontWeight: '600' }}>{p.name}</span>
                                                    <span style={{ color: colors.textMuted, fontSize: '0.75rem', fontFamily: 'var(--font-mono)' }}>
                                                        OVR: <strong style={{ color: colors.text }}>{p.ovr}</strong> • ENERGIA: <strong style={{ color: colors.accent }}>{p.energy}%</strong>
                                                    </span>
                                                </div>
                                            </div>
                                            <EfButton
                                                variant="primary"
                                                size="sm"
                                                onClick={() => handleSub(selectedOut, p)}
                                                style={{ display: 'flex', alignItems: 'center', gap: '4px' }}
                                            >
                                                ENTRAR <ArrowsLeftRight size={14} />
                                            </EfButton>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </EfModal>
    );
}

