    { view: 'saves',        icon: FloppyDisk, label: 'SAVES' },
    { view: 'autoplay',     icon: Robot, label: 'AUTOPLAY' }
];

const NAV_ITEMS_PLAYER = [
    { view: 'player_dashboard', icon: House, label: 'DASHBOARD' },
