    const [step, setStep] = useState(0);

    const colors = {
        bg: '#0D1117',
        panelBg: '#161B22',
        panelElevated: '#1A1F24',
        border: '#2D3748',
        text: '#FDFBF7',
        textMuted: '#8E9E94',
        accent: '#39FF14',
        secondary: '#40BAF7',
        warning: '#FFD700',
        danger: '#FF3333'
    };

    // --- AUDIT-FIX #16: Tutorial Funnel Tracking for SPEC-113 ---
    const FUNNEL_KEY = 'elifoot_tutorial_funnel';
    const tracked = useRef(new Set());

    const trackStep = useCallback((idx) => {
        if (tracked.current.has(idx)) return;
        tracked.current.add(idx);
        try {
            const raw = localStorage.getItem(FUNNEL_KEY);
            const arr = raw ? JSON.parse(raw) : [];
            arr.push({ step: STEPS[idx]?.title || `Step ${idx}`, stepIndex: idx, reached: true, reachedAt: Date.now() });
            localStorage.setItem(FUNNEL_KEY, JSON.stringify(arr));
        } catch { /* ignore */ }
    }, []);

    const trackDrop = useCallback((idx) => {
        try {
            const raw = localStorage.getItem(FUNNEL_KEY);
            const arr = raw ? JSON.parse(raw) : [];
            arr.push({ step: STEPS[idx]?.title || `Step ${idx}`, stepIndex: idx, reached: true, droppedAt: Date.now() });
            localStorage.setItem(FUNNEL_KEY, JSON.stringify(arr));
        } catch { /* ignore */ }
    }, []);

    // Track step 0 on mount
    useEffect(() => { trackStep(0); }, [trackStep]);

    const finish = () => {
        trackStep(step);
        try {
            localStorage.setItem(STORAGE_KEY, 'true');
            localStorage.setItem('elifoot_tutorial_origin', 'completed');
        } catch { /* ignore */ }
        changeView('start');
    };

    const skip = () => {
        trackDrop(step);
        try {
            localStorage.setItem(STORAGE_KEY, 'skipped');
            localStorage.setItem('elifoot_tutorial_origin', 'skipped');
        } catch { /* ignore */ }
        changeView('start');
    };

    const next = () => {
        trackStep(step);
        if (step < STEPS.length - 1) setStep(step + 1);
        else finish();
    };

    const prev = () => {
        if (step > 0) setStep(step - 1);
    };

    const cur = STEPS[step];

    return (
        <div className="ef-anim-fade-in" style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minHeight: '100dvh',
            padding: '24px',
            backgroundColor: colors.bg,
            backgroundImage: `url(${bgTutorial})`,
            backgroundSize: 'cover',
            backgroundPosition: 'center',
            backgroundAttachment: 'fixed',
            imageRendering: 'pixelated',
            color: colors.text,
            fontFamily: 'var(--font-sans)'
        }}>
            <EfPanel padding="lg" style={{
                maxWidth: '600px',
                width: '100%',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                textAlign: 'center',
                gap: '24px',
                borderTop: `4px solid ${colors.secondary}`
            }}>
                <div className="ef-anim-pop-in" key={`icon-${step}`} style={{ 
                    width: '120px', 
                    height: '120px', 
                    backgroundColor: colors.bg,
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    border: `1px solid ${colors.border}`,
                    boxShadow: `0 0 30px #111417`
                }}>
                    {cur.icon}
                </div>

                <div className="ef-anim-slide-up" key={`content-${step}`}>
                    <h2 style={{ margin: '0 0 16px 0', fontSize: '1.5rem', color: colors.text, fontWeight: '900', fontFamily: 'var(--font-sans)' }}>
                        {cur.title}
                    </h2>
                    <p style={{ margin: 0, fontSize: '1rem', lineHeight: '1.6', color: colors.textMuted }}>
                        {cur.body}
                    </p>
                </div>

                <div style={{
                    display: 'flex',
                    justifyContent: 'center',
                    gap: '8px',
                    width: '100%',
                    margin: '8px 0'
                }}>
                    {STEPS.map((_, i) => (
                        <div
                            key={i}
                            style={{
                                flex: 1,
                                height: '4px',
                                backgroundColor: i === step ? colors.secondary : i < step ? colors.accent : colors.border,
                                transition: 'background-color 300ms ease'
                            }}
                        />
                    ))}
                </div>

                <div style={{ display: 'flex', gap: '12px', width: '100%', marginTop: '8px' }}>
                    {step > 0 && (
                        <EfButton variant="secondary" size="lg" onClick={prev} style={{ flex: 1 }}>
                            <ArrowLeft size={20} /> ANTERIOR
                        </EfButton>
                    )}
                    <EfButton variant="primary" size="lg" onClick={next} style={{ flex: step === 0 ? 1 : 2 }}>
                        {step < STEPS.length - 1 ? (
                            <>PRÓXIMO <ArrowRight size={20} /></>
                        ) : (
                            <>INICIAR CARREIRA <SoccerBall size={20} weight="fill" /></>
                        )}
                    </EfButton>
                </div>

                <div style={{ marginTop: '8px' }}>
                    <button
                        onClick={skip}
                        style={{
                            background: 'none',
                            border: 'none',
                            color: colors.textMuted,
                            cursor: 'pointer',
                            fontSize: '0.8rem',
                            fontFamily: 'var(--font-mono)',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '6px',
                            padding: '8px'
                        }}
                    >
                        <FastForward size={14} /> PULAR TUTORIAL
                    </button>
                </div>
            </EfPanel>
        </div>
    );
}

// Helper: check tutorial state
export function isTutorialDone() {
    try {
        return localStorage.getItem(STORAGE_KEY) !== null;
    } catch {
        return false;
    }
}

export default TutorialView;

/**
 * DashboardAlerts — alert strip Stitch refactor.
 */

import React from 'react';
import './dashboard.css';

export function DashboardAlerts({ injured, expiringContracts, avgEnergy, transferOffersCount, onOpenTransfers }) {
    const hasAlerts = injured.length > 0 || expiringContracts.length > 0 || avgEnergy < 50 || transferOffersCount > 0;
    if (!hasAlerts) return null;

    return (
        <div className="ef-dash-alerts">
            {injured.length > 0 && (
                <span className="ef-dash-alert ef-dash-alert-danger">
                    🏥 {injured.length} lesionado{injured.length > 1 ? 's' : ''}
                </span>
            )}
            {expiringContracts.length > 0 && (
                <span className="ef-dash-alert ef-dash-alert-warning">
                    📋 {expiringContracts.length} contrato{expiringContracts.length > 1 ? 's' : ''} vencendo
                </span>
            )}
            {avgEnergy < 50 && (
                <span className="ef-dash-alert ef-dash-alert-danger">
                    ⚡ Elenco cansado ({avgEnergy.toFixed(0)}%)
                </span>
            )}
            {transferOffersCount > 0 && (
                <span className="ef-dash-alert ef-dash-alert-info" onClick={onOpenTransfers}>
                    📬 {transferOffersCount} oferta{transferOffersCount > 1 ? 's' : ''}
                </span>
            )}
        </div>
    );
}

export default DashboardAlerts;

