export function EfBanner({ type, customTitle, customSubtitle, onDismiss }) {
    const cfg = BANNER_CONFIG[type] || BANNER_CONFIG.offer;

    useEffect(() => {
        const t = setTimeout(() => { onDismiss?.(); }, cfg.duration);
