/**
 * EfButton — SNES 16-bit Brutalist Arcade
 *
 * Variants: primary | secondary | danger | ghost
 * Sizes: sm | md | lg
 *
 * Heavy 4px bevel borders, pixel-perfect press feedback,
 * Press Start 2P for labels, zero border-radius.
 */

import React from 'react';

export function EfButton({
    variant = 'primary',
    size = 'md',
    icon,
    loading = false,
    disabled = false,
    children,
    onClick,
    type = 'button',
    title,
    className = '',
    'aria-label': ariaLabel,
    ...rest
}) {
    const isDisabled = disabled || loading;

    return (
        <button
            type={type}
            onClick={isDisabled ? undefined : onClick}
            disabled={isDisabled}
            title={title}
            aria-label={ariaLabel}
            aria-busy={loading || undefined}
            className={`ef-btn ef-btn-${variant} ef-btn-${size} ${className}`.trim()}
            {...rest}
        >
            {loading && <span className="ef-anim-spinner-sm" aria-label="Carregando" />}
            {!loading && icon && <span className="ef-btn-icon">{icon}</span>}
            {children}
        </button>
    );
}

export default EfButton;

/**
 * EfCardPlayer — Stitch component
 *
 * Player card com retrato 32×32 + nome + posição + 3 atributos com mini-progress.
 * 16-bit Brutalist Arcade edition.
 */

import React from 'react';
import { PlayerAvatar } from '../../utils/avatar';

const POSITION_COLOR = {
    GOL: '#FFD700',
    DEF: '#40BAF7',
    MEI: '#39FF14',
    ATA: '#FF3333'
};

function MiniBar({ value, max = 100, label }) {
    const pct = Math.max(0, Math.min(100, (value / max) * 100));
    let color = '#FF3333';
    if (pct >= 80) color = '#39FF14';
    else if (pct >= 60) color = '#6ABC3A';
    else if (pct >= 35) color = '#FFD700';

    return (
        <div className="ef-minibar">
            <span className="ef-minibar-label">{label}</span>
            <div className="ef-minibar-track">
                <div 
                    className="ef-minibar-fill" 
                    style={{ width: `${pct}%`, background: color }} 
                />
            </div>
            <span className="ef-minibar-value">{value}</span>
        </div>
    );
}

export function EfCardPlayer({
    player,
    layout = 'row',
    showAttrs = true,
    onClick,
    selected = false,
    badge,
    children
}) {
    if (!player) return null;

    const isCol = layout === 'column';
    const posColor = POSITION_COLOR[player.position] || '#888';

    return (
        <div
            className={`ef-card-player ef-card-player-${isCol ? 'col' : 'row'} ${selected ? 'ef-selected' : ''}`}
            onClick={onClick}
            role={onClick ? 'button' : 'group'}
            tabIndex={onClick ? 0 : undefined}
        >
            <PlayerAvatar name={player.name} size={32} />

            <div className="ef-card-player-info">
                <div className="ef-card-player-header">
                    <strong className="ef-card-player-name">{player.name}</strong>
                    <span 
                        className="ef-card-player-pos" 
                        style={{ background: posColor }}
                    >
                        {player.position}
                    </span>
                </div>
                <div className="ef-card-player-meta">
                    OVR {player.ovr || '?'} · {player.age || '?'}a
                </div>

                {showAttrs && player.career && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '2px', marginTop: '4px' }}>
                        <MiniBar value={player.energy ?? 100} label="ENE" />
                        <MiniBar value={player.moral ?? 50} label="MOR" />
                    </div>
                )}
            </div>

            {badge && (
                <div className="ef-card-player-badge">
                    {badge}
                </div>
            )}

            {children}
        </div>
    );
}

export default EfCardPlayer;

/**
 * EfClubBadge v3 — pixel-art sprite-based club shield (SPEC-060).
 *
 * Usa spritesheets PNG geradas via Stitch (Gemini 3 Flash):
 *   /sprites/clubs/spritesheet-serie-{a,b,c,d}.png
 *   Cada sheet 5 cols × 4 rows = 20 badges
 *   80 clubes total Série A/B/C/D
 *
 * 100% pixel-art SNES direção arte:
 * - PNG nativo Stitch chunky pixels visible
 * - background-position crop per club
 * - image-rendering: pixelated (nearest-neighbor scale)
 * - Fallback SVG abstract para clubes não mapeados
 *
 * Sizes: sm 24, md 48, lg 96, xl 128 (8px grid)
 */

import React from 'react';
import { HIGH_END_SHIELDS } from '../../assets/shields/high_end';

const SIZE_PX = {
    sm: 24,
    md: 48,
    lg: 96,
    xl: 128,
    xxl: 180
};

export function EfClubBadge({
    name,
    size = 'md',
    style = {},
    showName = false,
    onClick = null
}) {
    const px = SIZE_PX[size] || SIZE_PX.md;

    const wrapperStyle = {
        display: 'inline-flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: '4px',
        cursor: onClick ? 'pointer' : 'default',
        ...style
    };

    const badgeProps = {
        role: onClick ? 'button' : 'img',
        'aria-label': `Escudo ${name}`,
        onClick
    };

    const img = HIGH_END_SHIELDS[name];

    return (
        <div style={wrapperStyle} {...badgeProps}>
            {img ? (
                <img src={img} alt={name} style={{ width: px, height: px, imageRendering: 'pixelated', WebkitImageRendering: 'pixelated', objectFit: 'contain' }} />
            ) : (
                <div style={{ width: px, height: px, backgroundColor: '#111417', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '3px solid #000' }}>
                    <span style={{ color: '#E2E8F0', fontSize: px/3, fontFamily: "'Press Start 2P', monospace" }}>?</span>
                </div>
            )}
            {showName && (
                <span style={{
                    fontFamily: "'Press Start 2P', monospace",
                    fontSize: size === 'sm' ? '7px' : size === 'md' ? '8px' : '10px',
                    color: '#E2E8F0',
                    textTransform: 'uppercase',
                    letterSpacing: '0.04em',
                    textAlign: 'center',
                    maxWidth: `${px * 1.5}px`,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap'
                }}>
                    {name}
                </span>
            )}
        </div>
    );
}

export default EfClubBadge;

/**
 * EfInput — Stitch component
 *
 * Beveled inverso (sunk), focus ring info, error state.
 * 16-bit Brutalist Arcade edition.
 */

import React from 'react';

import { rng as systemRng } from '../../engine/rng.js';

export function EfInput({
    type = 'text',
    value,
    onChange,
    placeholder,
    icon,
    error,
    label,
    helper,
    id,
    disabled = false,
    size = 'md',
    'aria-label': ariaLabel,
    ...rest
}) {
    const SIZE_MAP = {
        sm: { padding: '4px 8px', fontSize: '12px' },
        md: { padding: '8px 12px', fontSize: '14px' },
        lg: { padding: '12px 16px', fontSize: '16px' }
    };
    const sizing = SIZE_MAP[size] || SIZE_MAP.md;
    const inputId = id || `ef-input-${systemRng().toString(36).slice(2, 8)}`;

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
            {label && (
                <label htmlFor={inputId} style={{
                    fontSize: '0.5rem',
                    fontFamily: "'Press Start 2P', monospace",
                    fontWeight: 600,
                    color: '#888',
                    textTransform: 'uppercase',
                    letterSpacing: '0.04em'
                }}>
                    {label}
                </label>
            )}

            <div style={{ position: 'relative', display: 'flex', alignItems: 'center' }}>
                {icon && (
                    <span style={{
                        position: 'absolute',
                        left: '8px',
                        color: '#888',
                        pointerEvents: 'none'
                    }}>
                        {icon}
                    </span>
                )}
                <input
                    id={inputId}
                    type={type}
                    value={value}
                    onChange={onChange}
                    placeholder={placeholder}
                    disabled={disabled}
                    aria-label={ariaLabel}
                    aria-invalid={!!error || undefined}
                    aria-describedby={helper ? `${inputId}-helper` : undefined}
                    style={{
                        flex: 1,
                        padding: sizing.padding,
                        paddingLeft: icon ? '32px' : sizing.padding.split(' ')[1],
                        fontSize: sizing.fontSize,
                        fontFamily: 'monospace',
                        color: '#E2E8F0',
                        background: '#111417',
                        border: '4px solid',
                        borderColor: error
                            ? '#FF3333'
                            : '#111417 #4A5059 #4A5059 #111417',
                        boxShadow: 'inset 2px 2px 0 #040805',
                        outline: 'none',
                        transition: 'border-color 0.1s',
                        opacity: disabled ? 0.5 : 1,
                        cursor: disabled ? 'not-allowed' : 'text'
                    }}
                    onFocus={(e) => {
                        if (!error) {
                            e.target.style.borderColor = '#40BAF7';
                        }
                    }}
                    onBlur={(e) => {
                        e.target.style.borderColor = error
                            ? '#FF3333'
                            : '#111417 #4A5059 #4A5059 #111417';
                    }}
                    {...rest}
                />
            </div>

            {error && (
                <span style={{
                    fontSize: '0.45rem',
                    color: '#FF3333',
                    fontFamily: "'Press Start 2P', monospace"
                }}>
                    ⚠ {error}
                </span>
            )}

            {helper && !error && (
                <span id={`${inputId}-helper`} style={{
                    fontSize: '0.45rem',
                    color: '#888',
                    fontFamily: "'Press Start 2P', monospace"
                }}>
                    {helper}
                </span>
            )}
        </div>
    );
}

export default EfInput;

/**
 * EfModal — Stitch component
 *
 * Centro tela, painel beveled, fundo escuro fade. Esc fecha.
 * Sizes: sm | md | lg | fullscreen
 */

import React, { useEffect } from 'react';

const SIZE_MAP = {
    sm: '320px',
    md: '480px',
    lg: '720px',
    fullscreen: '100%'
};

export function EfModal({
    open,
    onClose,
    title,
    size = 'md',
    closeOnEsc = true,
    closeOnBackdrop = true,
    children,
    footer
}) {
    useEffect(() => {
        if (!open || !closeOnEsc) return;
        const handler = (e) => { if (e.key === 'Escape') onClose?.(); };
        window.addEventListener('keydown', handler);
        return () => window.removeEventListener('keydown', handler);
    }, [open, closeOnEsc, onClose]);

    if (!open) return null;

    return (
        <div
            role="dialog"
            aria-modal="true"
            aria-labelledby={title ? 'ef-modal-title' : undefined}
            onClick={closeOnBackdrop ? onClose : undefined}
            style={{
                position: 'fixed',
                inset: 0,
                background: '#040805',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                zIndex: 9999,
                padding: '16px',
                animation: 'ef-modal-fade 200ms ease-out'
            }}
        >
            <div
                onClick={(e) => e.stopPropagation()}
                style={{
                    width: '100%',
                    maxWidth: SIZE_MAP[size] || SIZE_MAP.md,
                    maxHeight: '90vh',
                    backgroundColor: '#1E2124',
                    border: '4px solid',
                    borderColor: '#4A5059 #111417 #111417 #4A5059',
                    boxShadow: '0 16px 0 #040805',
                    display: 'flex',
                    flexDirection: 'column',
                    overflow: 'hidden',
                    animation: 'ef-pop-in 200ms ease-out',
                    fontFamily: "'Press Start 2P', monospace",
                }}
            >
                {/* Header */}
                {title && (
                    <div style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        padding: '12px 16px',
                        background: '#111417',
                        borderBottom: '4px solid #000',
                        color: '#FFF',
                        textShadow: '2px 2px 0 #000'
                    }}>
                        <h3 id="ef-modal-title" style={{
                            margin: 0,
                            fontSize: '0.85rem',
                            color: '#FFD700',
                            lineHeight: 1.5
                        }}>
                            {title}
                        </h3>
                        <button
                            onClick={onClose}
                            aria-label="Fechar"
                            style={{
                                background: '#FF3333',
                                border: '2px solid',
                                borderColor: '#FF9999 #880000 #880000 #FF9999',
                                color: '#FFF',
                                fontSize: '10px',
                                fontFamily: "'Press Start 2P', monospace",
                                cursor: 'pointer',
                                padding: '4px 8px',
                                lineHeight: 1,
                                boxShadow: '2px 2px 0 #000'
                            }}
                        >
                            X
                        </button>
                    </div>
                )}

                {/* Body */}
                <div style={{
                    flex: 1,
                    padding: '16px',
                    overflowY: 'auto',
                    color: '#CCC',
                    fontFamily: 'Outfit, sans-serif',
                    fontSize: '1rem',
                    lineHeight: 1.6
                }}>
                    {children}
                </div>

                {/* Footer */}
                {footer && (
                    <div style={{
                        padding: '12px 16px',
                        borderTop: '4px solid #111417',
                        background: '#1A1C20',
                        display: 'flex',
                        justifyContent: 'flex-end',
                        gap: '12px'
                    }}>
                        {footer}
                    </div>
                )}
            </div>
        </div>
    );
}

export default EfModal;

/**
 * EfPanel — SNES 16-bit Brutalist Arcade Container
 *
 * Heavy metal beveled container with zero transparency.
 * Variants: default | elev | sunk | hero | warning | danger
 */

import React from 'react';

export function EfPanel({
    variant = 'default',
    title,
    icon,
    headerColor,
    padding = 'md',
    children,
    onClick,
    className = '',
    style = {}
}) {
    return (
        <div
            onClick={onClick}
            className={`ef-panel ef-panel-${variant} ef-panel-p-${padding} ${className}`.trim()}
            style={{
                cursor: onClick ? 'pointer' : 'default',
                ...style
            }}
        >
            {title && (
                <div className="ef-panel-header" style={headerColor ? { background: headerColor } : {}}>
                    {icon && <span>{icon}</span>}
                    {title}
                </div>
            )}
            <div className={`ef-panel-content`}>
                {children}
            </div>
        </div>
    );
}

export default EfPanel;

/**
 * EfStatLine — inline stat com label + value + optional bar.
 *
 * Used em painéis denso (Dashboard ISS-style).
 */

import React from 'react';

export function EfStatLine({
    label,
    value,
    suffix,
    color,
    barValue,
    barMax = 100,
    icon,
    bold = false
}) {
    let valColor = color || '#E2E8F0';

    if (!color && typeof barValue === 'number') {
        const pct = (barValue / barMax) * 100;
        if (pct >= 80) valColor = '#39FF14';
        else if (pct >= 60) valColor = '#6ABC3A';
        else if (pct >= 35) valColor = '#FFD700';
        else valColor = '#FF3333';
    }

    return (
        <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            gap: '8px',
            fontSize: '13px',
            fontFamily: "'Press Start 2P', monospace"
        }}>
            <span style={{
                color: '#888',
                display: 'flex',
                alignItems: 'center',
                gap: '4px',
                fontSize: '0.5rem'
            }}>
                {icon && <span>{icon}</span>}
                {label}
            </span>
            <span style={{
                color: valColor,
                fontWeight: bold ? 700 : 500,
                fontFamily: typeof value === 'number' ? "monospace" : "'Press Start 2P', monospace",
                fontSize: '0.6rem'
            }}>
                {value}{suffix}
            </span>
        </div>
    );
}

export default EfStatLine;

