import React, { createContext, useContext, useState, useRef, useEffect } from 'react';
import { Engine } from '../engine/engine';
import { Tournament } from '../engine/tournaments/Tournament';
import { League } from '../engine/tournaments/League';
import { KnockoutCup } from '../engine/tournaments/KnockoutCup';
import { ContinentalCup } from '../engine/tournaments/ContinentalCup';
import { MonitorService } from '../services/MonitorService';
import { ProPlayer } from '../engine/PlayerCareer';
import { ManagerLegacy } from '../engine/SeasonSystem';

const GameContext = createContext();

export const useGame = () => useContext(GameContext);

// AKITA-RFCT-017: SAVE_VERSION bumped 1 → 3 (FIM v1.0.5 refactor).
// AKITA-050 (v1.0.7): SAVE_VERSION 3 → 4 (Camada 2 events array foundation).
// AKITA-051 (v1.1): SAVE_VERSION 4 → 5 (Camada 5 Mito halls + retiredPlayers).
// AKITA-052 (v1.1.5): SAVE_VERSION 5 → 6 (regen inheritance traits).
// AKITA-053 (v1.2): SAVE_VERSION 6 → 7 (transição jogador→técnico + manager_president).
// AKITA-054 (v1.3): SAVE_VERSION 7 → 8 (regenLineage filhos-regens).
// AKITA-055 (v1.4): SAVE_VERSION 8 → 9 (arcs array completo + 6 named arcs).
// AKITA-056 (v1.5): SAVE_VERSION 9 → 10 (chronicle export — fim roadmap v1.x).
// AKITA-127 (v1.6): SAVE_VERSION 10 → 11 (Sul-Americana + real promo/rel counts + ecosystem fix).
// Saves v<11 são auto-invalidados (start fresh).
const SAVE_KEY = 'elifoot_save_v1';
const SAVE_VERSION = 11;

/**
 * §7: CRC32 integrity checksum — detects corrupted or tampered saves.
 * Lightweight (no crypto dependency), sufficient for data-corruption detection.
 */
function crc32(str) {
    let crc = -1;
    for (let i = 0; i < str.length; i++) {
        crc = (crc >>> 8) ^ _crc32Table[(crc ^ str.charCodeAt(i)) & 0xff];
    }
    return (crc ^ -1) >>> 0;
}
const _crc32Table = (() => {
    const table = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
        let c = i;
        for (let j = 0; j < 8; j++) c = c & 1 ? 0xedb88320 ^ (c >>> 1) : c >>> 1;
        table[i] = c;
    }
    return table;
})();

// Map class name → constructor para prototype restoration (BUG-021)
const TOURNAMENT_CLASSES = { Tournament, League, KnockoutCup, ContinentalCup };

function tournamentClassFromShape(t) {
    if (!t || typeof t !== 'object') return Tournament;
    if (t.__class && TOURNAMENT_CLASSES[t.__class]) return TOURNAMENT_CLASSES[t.__class];
    if (typeof t.level === 'number') return League;
    if (Array.isArray(t.groupWeeks)) return ContinentalCup;
    if (Array.isArray(t.roundWeeks)) return KnockoutCup;
    return Tournament;
}

// BUG-020 fix: localStorage auto-save + restore
function saveToStorage(engine, gameState) {
    try {
        const engineData = serializeEngine(engine);
        const engineJson = JSON.stringify(engineData);
        const checksum = crc32(engineJson);
        const payload = {
            version: SAVE_VERSION,
            timestamp: Date.now(),
            checksum,
            gameState,
            engine: engineData,
        };
        localStorage.setItem(SAVE_KEY, JSON.stringify(payload));
    } catch (e) {
        console.warn('[Save] Failed to persist state:', e);
    }
}

function loadFromStorage() {
    try {
        const raw = localStorage.getItem(SAVE_KEY);
        if (!raw) return null;
        const payload = JSON.parse(raw);
        if (payload.version !== SAVE_VERSION) {
            console.info(`[Save] Version mismatch (saved v${payload.version}, current v${SAVE_VERSION}). Save invalidated.`);
            return null;
        }
        // §7: Verify integrity checksum
        if (payload.checksum !== undefined && payload.engine) {
            const expected = crc32(JSON.stringify(payload.engine));
            if (payload.checksum !== expected) {
                console.warn(`[Save] Integrity check failed (expected ${expected}, got ${payload.checksum}). Save corrupted.`);
                return null;
            }
        }
        return payload;
    } catch (e) {
        console.warn('[Save] Failed to load state:', e);
        return null;
    }
}

function clearStorage() {
    try {
        localStorage.removeItem(SAVE_KEY);
    } catch { /* ignore */ }
}

// Campos engine que são instâncias de classes — skip em save (recriam em constructor).
// AKITA-RFCT-017: includes services (Myth/Relationship/Narrative/Career + MatchSimulator).
// AKITA-052: includes InheritanceService.
const ENGINE_CLASS_FIELDS = [
    'staff', 'board', 'legacy',
    '_matchSimulator', '_mythService', '_relationshipService', '_narrativeService', '_careerService',
    '_inheritanceService', '_weekProcessor', '_seasonProcessor', '_aiDirector'
];

function serializeEngine(engine) {
    const safe = {};
    for (const key of Object.keys(engine)) {
        if (ENGINE_CLASS_FIELDS.includes(key)) continue;
        try {
            const v = engine[key];
            if (typeof v === 'function') continue;
            if (v instanceof Map || v instanceof Set) continue;
            JSON.stringify(v);
            safe[key] = v;
        } catch { /* skip non-serializable */ }
    }
    // BUG-096: Strip brain objects + volatile NPC AI state from teams.
    // Brains are persisted separately via BrainPersistence.js with compaction.
    // Including them in engine save doubles storage usage (~2-3MB of duplicated qTables).
    if (Array.isArray(safe.teams)) {
        safe.teams = safe.teams.map(t => {
            if (!t) return t;
            const { brain, _lastTacticDecision, _aiDirectorState, ...clean } = t;
            return clean;
        });
    }
    // Save staff state separately (just hired array)
    if (engine.staff && Array.isArray(engine.staff.hired)) {
        safe._staffHired = engine.staff.hired;
    }
    // BUG-075: save legacy separately — ManagerLegacy excluded from ENGINE_CLASS_FIELDS
    // so it was never persisted → titles/seasons lost on every reload.
    if (engine.legacy) {
        safe._legacy = {
            managerName: engine.legacy.managerName,
            reputation: engine.legacy.reputation,
            seasons: engine.legacy.seasons,
            titles: engine.legacy.titles,
            totalWins: engine.legacy.totalWins,
            totalMatches: engine.legacy.totalMatches,
        };
    }
    // BUG-021: tag tournaments com class name pra prototype restore
    if (Array.isArray(engine.tournaments)) {
        safe.tournaments = engine.tournaments.map(t => ({
            ...t,
            __class: t?.constructor?.name || 'Tournament'
        }));
    }
    return safe;
}

function restoreEngine(engine, snapshot) {
    if (!snapshot) return;
    for (const [key, val] of Object.entries(snapshot)) {
        if (key === '_staffHired') continue;
        if (ENGINE_CLASS_FIELDS.includes(key)) continue;
        try {
            engine[key] = val;
        } catch { /* skip */ }
    }
    // BUG-021 fix: re-attach tournament prototypes
    if (Array.isArray(engine.tournaments)) {
        engine.tournaments = engine.tournaments.map(rawT => {
            if (!rawT) return rawT;
            const ClassConstructor = tournamentClassFromShape(rawT);
            const restored = Object.create(ClassConstructor.prototype);
            for (const [k, v] of Object.entries(rawT)) {
                if (k === '__class') continue;
                restored[k] = v;
            }
            return restored;
        });
    }
    // Restore staff hired list (preserva StaffManager class)
    if (snapshot._staffHired && engine.staff) {
        engine.staff.hired = [...snapshot._staffHired];
    }
    // BUG-075 fix: restore ManagerLegacy instance from saved plain object
    if (snapshot._legacy) {
        const ld = snapshot._legacy;
        const ml = new ManagerLegacy(ld.managerName || '');
        ml.reputation = ld.reputation ?? 30;
        ml.seasons = ld.seasons ?? [];
        ml.titles = ld.titles ?? [];
        ml.totalWins = ld.totalWins ?? 0;
        ml.totalMatches = ld.totalMatches ?? 0;
        engine.legacy = ml;
    }
    // BUG-024 fix: rehydrate ProPlayer prototype after JSON restore.
    // Save loses class methods (hasFlag/setFlag/etc); OffPitchEventsDeck triggers crash.
    if (engine.proPlayer && typeof engine.proPlayer.hasFlag !== 'function') {
        try {
            Object.setPrototypeOf(engine.proPlayer, ProPlayer.prototype);
            if (!engine.proPlayer.flags) engine.proPlayer.flags = {};
        } catch { /* ignore — defensive filter in deck consumers also catches */ }
    }
}

export const GameProvider = ({ children }) => {
    const engineRef = useRef(new Engine());
    const [, setTick] = useState(0);
    const forceUpdate = () => setTick(t => t + 1);

    // v1.7: Auto-instrument engine for monitor (sem user action)
    React.useEffect(() => {
        try {
            MonitorService.getInstance().instrumentEngine(engineRef.current);
        } catch { /* ignore */ }
    }, []);

    // BUG-020: try restore on mount
    const restored = loadFromStorage();
    const [gameState, setGameState] = useState(
        restored?.gameState || {
            started: false,
            view: 'start',
            manager: '',
            teamId: null,
            mode: 'manager'
        }
    );

    useEffect(() => {
        if (restored?.engine) {
            restoreEngine(engineRef.current, restored.engine);
            forceUpdate();
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    // Auto-save em mudança gameState
    useEffect(() => {
        if (gameState.started) {
            saveToStorage(engineRef.current, gameState);
        }
    }, [gameState]);

    const startGame = (name, teamId, scenario = 'livre', mode = 'manager', position = 'ATA', personality = 'maverick') => {
        clearStorage(); // limpa save antigo ao começar nova carreira
        engineRef.current.initGame(name, teamId, mode, scenario, position);
        if (mode === 'player' && engineRef.current.proPlayer) {
            engineRef.current.proPlayer.personality = personality;
        }
        try {
            MonitorService.getInstance().recordGameplay('GAME_START', {
                name, teamId, scenario, mode, position, personality
            });
            // Re-instrument após initGame (alguns métodos podem ter sido reset)
            MonitorService.getInstance().instrumentEngine(engineRef.current);
        } catch { /* ignore */ }
        setGameState({
            started: true,
            view: mode === 'player' ? 'player_dashboard' : 'dashboard',
            manager: name,
            teamId,
            mode
        });
    };

    const changeView = (view) => {
        try {
            MonitorService.getInstance().recordGameplay('NAV', {
                from: gameState.view,
                to: view
            });
        } catch { /* ignore */ }
        setGameState(prev => ({ ...prev, view }));
    };

    // BUG-022 fix: mode-aware dashboard route (avoid player→manager unintended switch)
    const getDashboardView = () => gameState.mode === 'player' ? 'player_dashboard' : 'dashboard';

    const saveGame = () => saveToStorage(engineRef.current, gameState);
    const resetGame = () => {
        clearStorage();
        engineRef.current = new Engine();
        setGameState({ started: false, view: 'start', manager: '', teamId: null, mode: 'manager' });
    };

    const getEngine = () => engineRef.current;

    return (
        <GameContext.Provider value={{ gameState, startGame, changeView, getEngine, forceUpdate, saveGame, resetGame, getDashboardView }}>
            {children}
        </GameContext.Provider>
    );
};

import { rng as systemRng } from './rng.js';
/**
 * FilhosRegenSystem — SPEC-081: Regens-Filhos de Ex-Companheiros
 *
 * 16-18 anos após o auge de ex-companheiro, emerge regen com linhagem nomeada.
 * Escassez intencional: 1 a cada 3-4 seasons.
 * Cria continuidade temporal — save tem memória.
 *
 * Stateless: recebe contexto, retorna regen se condições satisfeitas.
 */

const SPAWN_CHANCE = 0.25; // 25% chance per check (~1 per 4 seasons)
const LEGACY_DELAY_YEARS = 16; // emerge 16-18 years after companion's prime

/**
 * Verifica se um Filho Regen deve emergir nesta season.
 *
 * @param {object} opts
 * @param {number} opts.managerId
 * @param {number} opts.saveYear — ano atual do save
 * @param {number} opts.season
 * @param {Array<{playerId,name,primeYear,position,ovr,traits}>} opts.formerCompanions
 * @param {number} [opts.seed]
 * @returns {{ regenAvailable, regen? }}
 */
export function evaluate({ managerId = 0, saveYear = 2030, season = 1, formerCompanions = [], seed = null } = {}) {
    const rand = seed !== null ? seededRandom(seed) : systemRng;

    // Check every 4 seasons at earliest
    if (season < 4 || season % 4 !== 0) return { regenAvailable: false };

    const eligible = formerCompanions.filter(c => {
        const elapsed = saveYear - (c.primeYear || saveYear - 20);
        return elapsed >= LEGACY_DELAY_YEARS - 2 && elapsed <= LEGACY_DELAY_YEARS + 2;
    });

    if (eligible.length === 0 || rand() > SPAWN_CHANCE) return { regenAvailable: false };

    const parent = eligible[Math.floor(rand() * eligible.length)];
    const regen = buildRegen(parent, rand);

    return { regenAvailable: true, regen };
}

// ─── helpers ────────────────────────────────────────────────

function buildRegen(parent, rand) {
    const nameParts = parent.name.split(' ');
    const surname = nameParts[nameParts.length - 1];
    const firstNames = ['Mateus', 'Lucas', 'Rafael', 'João', 'Pedro', 'Caio', 'Felipe'];
    const firstName = firstNames[Math.floor(rand() * firstNames.length)];

    const ovrBase = Math.max(50, (parent.ovr || 65) - 15 + Math.floor(rand() * 20));

    return {
        id: `regen-${parent.playerId}-${Date.now()}`,
        name: `${firstName} ${surname}`,
        parentId: parent.playerId,
        parentName: parent.name,
        position: parent.position || 'MEI',
        age: 16 + Math.floor(rand() * 3),
        ovr: ovrBase,
        inheritedTraits: parent.traits || [],
        loreDescription: `Filho de ${parent.name}. A mesma posição. O mesmo sobrenome. A torcida vai comparar.`,
    };
}

function seededRandom(seed) {
    let s = seed;
    return function() {
        s = (s * 1664525 + 1013904223) & 0xffffffff;
        return (s >>> 0) / 0xffffffff;
    };
}

import { rng as systemRng } from './rng.js';
/**
 * GrowthEventSystem — SPEC-134: Progression Growth Events
 *
 * Injeta eventos de crescimento orgânico que movem o OVR do squad.
 * Resolve Progression score=30 (growthEventCount=0, slope=0.08 em 203 seasons).
 *
 * Stateless: recebe squad, retorna eventos + mutações a aplicar.
 */

const OVR_FLOOR = 30;
const OVR_CAP   = 99;

/**
 * Avalia squad e retorna growth events da semana.
 *
 * @param {object} opts
 * @param {number} opts.teamId
 * @param {number} opts.week
 * @param {number} opts.season
 * @param {Array}  opts.players — array de jogadores do squad
 * @param {Array<string>} [opts.teamRecentResults=[]] — 'W'|'D'|'L' recentes
 * @returns {{ growthEvents: Array, newSquadOvrAvg: number }}
 */
export function evaluateGrowth({ teamId, week, season, players, teamRecentResults = [] }) {
    const events = [];
    const seenPlayers = new Set();

    const hotStreak = countTrailingWins(teamRecentResults) >= 5;
    const primeGames = (p) => (p.gamesThisSeason || 0) >= 15;

    for (const player of players) {
        if (!player || player._retired || player.injury) continue;

        const age = player.age || 25;
        const ovr = player.ovr || 50;
        const pid = player.id;

        // Youth Breakthrough — sub-21, chance semanal
        if (age < 21 && !seenPlayers.has(`${pid}-youth`) && systemRng() < 0.04) {
            const delta = 2 + Math.floor(systemRng() * 4); // +2 a +5
            const finalOvr = clamp(ovr + delta);
            events.push({
                type: 'youth_breakthrough',
                playerId: pid,
                playerName: player.name,
                ovrDelta: finalOvr - ovr,
                permanent: true,
                narrativeTag: 'CRAQUE_EMERGED',
                apply: () => { player.ovr = finalOvr; applyAttrsBoost(player, delta); },
            });
            seenPlayers.add(`${pid}-youth`);
        }

        // Hot Streak — forma excelente temporal
        if (hotStreak && !seenPlayers.has(`${pid}-hot`) && systemRng() < 0.06) {
            events.push({
                type: 'hot_streak',
                playerId: pid,
                playerName: player.name,
                ovrDelta: 3,
                permanent: false,
                duration: 4,
                narrativeTag: 'FORM_HOT_STREAK',
                apply: () => { player._hotStreakBonus = 3; player._hotStreakWeeks = 4; },
            });
            seenPlayers.add(`${pid}-hot`);
        }

        // Peak Season — prime years, bom volume de jogos
        if (age >= 23 && age <= 27 && primeGames(player) && !seenPlayers.has(`${pid}-peak`) && systemRng() < 0.08) {
            const finalOvr = clamp(ovr + 1);
            events.push({
                type: 'peak_season',
                playerId: pid,
                playerName: player.name,
                ovrDelta: finalOvr - ovr,
                permanent: true,
                narrativeTag: 'PEAK_SEASON',
                apply: () => { player.ovr = finalOvr; },
            });
            seenPlayers.add(`${pid}-peak`);
        }

        // Decline — veteranos
        if (age >= 32 && !seenPlayers.has(`${pid}-decline`) && systemRng() < (age - 30) * 0.03) {
            const finalOvr = Math.max(OVR_FLOOR, ovr - 1);
            events.push({
                type: 'decline',
                playerId: pid,
                playerName: player.name,
                ovrDelta: finalOvr - ovr,
                permanent: true,
                narrativeTag: 'AGING_SIGNAL',
                apply: () => { player.ovr = finalOvr; },
            });
            seenPlayers.add(`${pid}-decline`);
        }

        // Training Breakthrough — jogadores com muitos treinos
        const trainCount = player._recentTrainCount || 0;
        if (trainCount >= 4 && !seenPlayers.has(`${pid}-train`) && systemRng() < 0.12) {
            const finalOvr = clamp(ovr + 2);
            events.push({
                type: 'training_breakthrough',
                playerId: pid,
                playerName: player.name,
                ovrDelta: finalOvr - ovr,
                permanent: true,
                narrativeTag: 'TRAINING_PEAK',
                apply: () => { player.ovr = finalOvr; player._recentTrainCount = 0; },
            });
            seenPlayers.add(`${pid}-train`);
        }
    }

    // Apply all events
    events.forEach(e => { if (e.apply) e.apply(); });

    const activeOvrs = players.filter(p => !p._retired && !p.injury).map(p => p.ovr || 50);
    const newSquadOvrAvg = activeOvrs.length > 0
        ? Math.round(activeOvrs.reduce((s, v) => s + v, 0) / activeOvrs.length)
        : 0;

    // Clean apply refs from output
    return {
        growthEvents: events.map(({ apply: _apply, ...rest }) => rest),
        newSquadOvrAvg,
    };
}

// ─── helpers ────────────────────────────────────────────────

function clamp(v) {
    return Math.max(OVR_FLOOR, Math.min(OVR_CAP, v));
}

function countTrailingWins(results) {
    let count = 0;
    for (const r of results) {
        if (r === 'W') count++;
        else break;
    }
    return count;
}

function applyAttrsBoost(player, amount) {
    if (!player.attributes) return;
    const attrs = Object.keys(player.attributes);
    // Boost 1-2 random attributes
    const picks = attrs.sort(() => systemRng() - 0.5).slice(0, 2);
    picks.forEach(attr => {
        player.attributes[attr] = Math.min(99, (player.attributes[attr] || 50) + amount);
    });
}

import { rng as systemRng } from './rng.js';
/**
 * HeritageTraitSystem — SPEC-079: Traits Herdáveis de Lendas
 *
 * Regens herdam traits do Hall de Lendas do clube onde emergem.
 * Continuidade narrativa: DNA de ídolos ressurge em jovens talentos.
 *
 * Stateless: recebe hall, retorna traits gerados.
 */

const INHERITABLE_TRAITS = ['garra', 'talento_natural', 'lealdade', 'frieza'];
const TRAIT_FLOOR = 0;
const TRAIT_CAP   = 100;

/**
 * Gera traits herdáveis para um regen baseado no Hall de Lendas.
 *
 * @param {object} opts
 * @param {number} opts.clubId
 * @param {object} opts.hall — resultado de HallOfLegendsSystem.compute()
 * @param {number} [opts.baseChance=0.6] — chance de herdar de um slot preenchido
 * @param {number} [opts.seed] — seed para determinismo
 * @returns {{ traits: object, inheritedFrom: Array<string>, inheritanceNarrative: string }}
 */
export function inherit({ clubId, hall, baseChance = 0.6, seed = null } = {}) {
    const rand = seed !== null ? seededRandom(seed) : systemRng;
    const slots = hall?.slots || {};
    const filledSlots = Object.keys(slots);

    const traits = {};
    const inheritedFrom = [];

    // Each filled slot contributes to one trait
    const slotTraitMap = {
        idoloEterno:  'garra',
        goleirao:     'talento_natural',
        criaDaBase:   'lealdade',
        carrasco:     'frieza',
        lendaTragica: 'garra',   // tragic legend → determination
        traidor:      null,       // traitors don't pass traits
    };

    INHERITABLE_TRAITS.forEach(t => { traits[t] = 30; }); // base value

    for (const slot of filledSlots) {
        const traitKey = slotTraitMap[slot];
        if (!traitKey) continue;
        if (rand() < baseChance) {
            // Inherit: bump trait by 20-40 points
            const bonus = Math.floor(rand() * 20) + 20;
            traits[traitKey] = clamp(traits[traitKey] + bonus);
            inheritedFrom.push(slot);
        }
    }

    const topSlot = inheritedFrom[0];
    const legend = topSlot ? slots[topSlot]?.playerName : null;
    const inheritanceNarrative = legend
        ? `Tem o espírito de ${legend} — a torcida sente desde o primeiro treino.`
        : 'Chega sem história, mas com potencial para criar a sua.';

    return { traits, inheritedFrom, inheritanceNarrative };
}

// ─── helpers ────────────────────────────────────────────────

function clamp(v) {
    return Math.max(TRAIT_FLOOR, Math.min(TRAIT_CAP, v));
}

function seededRandom(seed) {
    let s = seed;
    return function() {
        s = (s * 1664525 + 1013904223) & 0xffffffff;
        return (s >>> 0) / 0xffffffff;
    };
}

/**
 * HumiliationCascadeSystem — SPEC-076: Vexame com Consequências Narrativas
 *
 * Dispara cascata de eventos ao sofrer goleada.
 * Transforma VEXAME de anomalia passiva em momento de decisão narrativo.
 *
 * Stateless: recebe contexto da partida, retorna cascata.
 */

/**
 * Avalia humilhação e retorna cascata de eventos.
 *
 * @param {object} opts
 * @param {number} [opts.teamId]
 * @param {number} [opts.managerId]
 * @param {number} [opts.scoreDiff=0] — gols sofridos - gols marcados
 * @param {'home'|'away'} [opts.homeOrAway='home']
 * @param {number} [opts.week=1]
 * @param {number} [opts.season=1]
 * @param {number} [opts.managerTension=50]
 * @param {boolean} [opts.isPlayerManager=true]
 * @returns {{ humiliationLevel, cascadeEvents, survivalNarrative }}
 */
export function evaluate({ teamId = 0, managerId = 0, scoreDiff = 0, homeOrAway = 'home', week = 1, season = 1, managerTension = 50, isPlayerManager = true } = {}) {
    const level = computeLevel(scoreDiff);

    if (level === 0) {
        return { humiliationLevel: 0, cascadeEvents: [], survivalNarrative: { active: false, milestoneDescription: '' } };
    }

    const events = [];

    // Level 1+: morale_collapse + press_hostility
    events.push({ type: 'morale_collapse', severity: 0.4, description: 'Elenco devastado pelo resultado. Moral em colapso.' });
    events.push({ type: 'press_hostility', severity: 0.3, description: 'Imprensa exige explicações do técnico.' });

    // Level 2+: board_meeting + fan_protest
    if (level >= 2) {
        events.push({ type: 'board_meeting', severity: 0.6, description: 'Presidente convoca reunião de emergência.', tensionDelta: -15 });
        events.push({ type: 'fan_protest', severity: 0.6, description: 'Torcida protesta fora do estádio.' });
    }

    // Level 3+: player_request_transfer + manager_ultimatum
    if (level >= 3) {
        events.push({ type: 'player_request_transfer', severity: 0.8, description: 'Um jogador pede para sair. O vestiário está em frangalhos.' });
        events.push({ type: 'manager_ultimatum', severity: 1.0, description: 'Presidente dá ultimato ao técnico.', tensionDelta: -30 });
    }

    // Survival narrative: active if manager survives level 3
    const survivalNarrative = {
        active: level >= 3,
        milestoneDescription: level >= 3
            ? 'Técnico sobrevive ao escândalo — agora é provar que foi só uma vez.'
            : '',
    };

    return { humiliationLevel: level, cascadeEvents: events, survivalNarrative };
}

// ─── helpers ────────────────────────────────────────────────

function computeLevel(diff) {
    if (diff >= 8) return 3;
    if (diff >= 6) return 2;
    if (diff >= 4) return 1;
    return 0;
}

import { rng as systemRng } from './rng.js';
/**
 * InjurySystem.js — Lesões e recuperação
 * Inspirado em FM (severity tiers) + Elifoot (simplicidade)
 */

const INJURY_TYPES = [
    { id: "muscle", name: "Lesão muscular", minWeeks: 1, maxWeeks: 3, emoji: "🦵" },
    { id: "ankle", name: "Torção no tornozelo", minWeeks: 2, maxWeeks: 4, emoji: "🦶" },
    { id: "knee", name: "Lesão no joelho", minWeeks: 3, maxWeeks: 8, emoji: "🦿" },
    { id: "hamstring", name: "Estiramento na coxa", minWeeks: 1, maxWeeks: 3, emoji: "🩹" },
    { id: "fracture", name: "Fratura", minWeeks: 6, maxWeeks: 15, emoji: "🏥" },
    { id: "concussion", name: "Concussão", minWeeks: 1, maxWeeks: 2, emoji: "🤕" },
];

/**
 * Rola chance de lesão para um jogador.
 * @param {object} player - jogador do squad
 * @param {string} context - 'match' | 'training_double' | 'training'
 * @returns {object|null} injury object ou null
 */
export function rollInjury(player, context = 'match') {
    let chance = 0;

    // Base chance por contexto
    if (context === 'match') chance = 0.04; // 4% por jogo
    else if (context === 'training_double') chance = 0.06;
    else chance = 0.02;

    // Modificadores
    if (player.energy < 30) chance *= 2.0; // cansaço dobra risco
    if (player.energy < 15) chance *= 3.0;
    if (player.age > 32) chance *= 1.5; // veterano
    if (player.age < 20) chance *= 0.7; // jovem

    if (systemRng() > chance) return null;

    // Severidade: energia baixa = lesão mais grave
    const severityPool = player.energy < 30
        ? INJURY_TYPES // todas possíveis
        : INJURY_TYPES.filter(t => t.maxWeeks <= 4); // só leves

    const type = severityPool[Math.floor(systemRng() * severityPool.length)];
    const weeks = type.minWeeks + Math.floor(systemRng() * (type.maxWeeks - type.minWeeks + 1));

    return {
        type: type.id,
        name: type.name,
        emoji: type.emoji,
        weeksLeft: weeks,
        totalWeeks: weeks,
    };
}

/**
 * Avança recuperação de lesão.
 * @returns {boolean} true se curou
 */
export function healInjury(player) {
    if (!player.injury) return false;
    player.injury.weeksLeft--;
    if (player.injury.weeksLeft <= 0) {
        player.injury = null;
        player.energy = 60; // volta com energia parcial
        return true;
    }
    return false;
}

/**
 * Aplica lesões ao plantel após partida.
 */
export function processMatchInjuries(squad) {
    const injuries = [];
    squad.filter(p => p.isTitular && !p.injury).forEach(player => {
        const injury = rollInjury(player, 'match');
        if (injury) {
            player.injury = injury;
            player.isTitular = false; // sai do time titular
            injuries.push({ player: player.name, ...injury });
        }
    });
    return injuries;
}

/**
 * Aplica lesões ao plantel no treino.
 */
export function processTrainingInjuries(squad, trainingType) {
    const context = trainingType === 'double' ? 'training_double' : 'training';
    const injuries = [];
    squad.filter(p => !p.injury).forEach(player => {
        const injury = rollInjury(player, context);
        if (injury) {
            player.injury = injury;
            player.isTitular = false;
            injuries.push({ player: player.name, ...injury });
        }
    });
    return injuries;
}

import { rng as systemRng } from './rng.js';
/**
 * LossStreakResponseSystem — SPEC-077: Resposta a Sequência de Derrotas
 *
 * Sequências de derrotas geram choices de gestão de crise para player,
 * resposta automática para NPCs.
 *
 * Partially stateful: rastreia streak por time.
 */

const MORALE_FLOOR = 5;

const NPC_RESPONSES = [
    { action: 'tactic_change', description: 'Time NPC muda tática para sair da crise.' },
    { action: 'emergency_training', description: 'Time NPC intensifica treinos.' },
    { action: 'star_benched', description: 'Time NPC banca estrela para reação.' },
];

const RESPONSE_OPTIONS = [
    { id: 'squad_meeting', label: 'Reunião de elenco', effect: { moraleDelta: +10, tensionDelta: 0 } },
    { id: 'intensive_training', label: 'Semana de treino intensivo', effect: { moraleDelta: +5, tensionDelta: 0 } },
    { id: 'change_tactic', label: 'Mudar tática radicalmente', effect: { moraleDelta: 0, tensionDelta: -5 } },
    { id: 'public_statement', label: 'Coletiva de imprensa positiva', effect: { moraleDelta: +8, tensionDelta: +5 } },
    { id: 'resign', label: 'Pedir demissão', effect: { moraleDelta: 0, tensionDelta: 0 } },
];

const _streaks = new Map(); // teamId → lossStreak count

/**
 * Avalia resposta necessária para sequência de derrotas.
 *
 * @param {object} opts
 * @param {number} [opts.teamId]
 * @param {number} [opts.managerId]
 * @param {number} [opts.streakLength]
 * @param {number} [opts.currentTension=50]
 * @param {number} [opts.squadMorale=50]
 * @param {boolean} [opts.isPlayerManager=true]
 * @param {number} [opts.week=1]
 * @returns {object} avaliação completa
 */
export function evaluate({ teamId = 0, managerId = 0, streakLength = 0, currentTension = 50, squadMorale = 50, isPlayerManager = true, week = 1 } = {}) {
    const severity = computeSeverity(streakLength);
    const forcedEvent = isPlayerManager && streakLength >= 8;

    // Morale floor enforcement
    const moraleFloorApplied = squadMorale < MORALE_FLOOR;
    const newMorale = Math.max(MORALE_FLOOR, squadMorale);

    // Tension penalty for collapse
    let tensionApplied = null;
    if (streakLength >= 11) {
        tensionApplied = -40;
    }

    if (!isPlayerManager) {
        const npcResponse = NPC_RESPONSES[Math.floor(systemRng() * NPC_RESPONSES.length)];
        return { streakSeverity: severity, forcedEvent: false, npcResponse, moraleFloorApplied, newMorale, tensionApplied };
    }

    const result = { streakSeverity: severity, forcedEvent, moraleFloorApplied, newMorale, tensionApplied };

    if (streakLength >= 5) {
        result.responseOptions = RESPONSE_OPTIONS;
    }

    return result;
}

/**
 * Registra resultado de uma partida (W/D/L).
 */
export function recordResult({ teamId, result } = {}) {
    if (result === 'W') {
        _streaks.set(teamId, 0);
    } else if (result === 'L') {
        _streaks.set(teamId, (_streaks.get(teamId) || 0) + 1);
    }
    // Draw: no change
}

/**
 * Retorna streak atual de um time.
 */
export function getCurrentStreak(teamId) {
    return _streaks.get(teamId) || 0;
}

// ─── helpers ────────────────────────────────────────────────

function computeSeverity(streak) {
    if (streak >= 11) return 'collapse';
    if (streak >= 8)  return 'crisis';
    if (streak >= 5)  return 'serious';
    if (streak >= 3)  return 'mild';
    return 'none';
}

import { MatchCardsATA } from './decks/MatchCardsATA';
import { MatchCardsMEI } from './decks/MatchCardsMEI';
import { MatchCardsDEF } from './decks/MatchCardsDEF';
import { MatchCardsGOL } from './decks/MatchCardsGOL';

import { rng as systemRng } from './rng.js';

export const MatchEventsDeck = {
    ATA: MatchCardsATA,
    MEI: MatchCardsMEI,
    DEF: MatchCardsDEF,
    GOL: MatchCardsGOL
};

// Tier weights for draw probability
const TIER_WEIGHTS = { common: 60, uncommon: 25, rare: 12, legendary: 3 };

/**
 * Draws a card from the deck based on position, renown, and personality.
 * @param {string} position - GOL, DEF, MEI, ATA
 * @param {number} renown - Player renown (gates legendary cards)
 * @param {string} personality - maverick|virtuoso|heartbeat (future filter)
 * @returns {object|null} A card object or null
 */
export function drawCard(position, renown = 0, personality = null) {
    const deck = MatchEventsDeck[position];
    if (!deck || deck.length === 0) return null;

    // Filter by renown (legendary cards need minRenown)
    const eligible = deck.filter(card => {
        if (card.minRenown && renown < card.minRenown) return false;
        return true;
    });

    if (eligible.length === 0) return null;

    // Weighted random by tier
    const totalWeight = eligible.reduce((sum, card) => sum + (TIER_WEIGHTS[card.tier] || 10), 0);
    let roll = systemRng() * totalWeight;

    for (const card of eligible) {
        roll -= (TIER_WEIGHTS[card.tier] || 10);
        if (roll <= 0) return card;
    }

    return eligible[eligible.length - 1];
}

/**
 * OrganicChallengeSystem — SPEC-074: Desafios e Missões Espontâneos
 *
 * Desafios opcionais que aparecem durante o jogo baseados no contexto.
 * Nunca obrigatórios. Surgem organicamente (salvamento, gigante caído, etc.).
 *
 * Stateless: recebe estado, retorna desafio disponível.
 */

const CHALLENGE_TYPES = {
    crisis_save:    { minRep: 0,  reputationBoost: 20, reputationLoss: 5,  narrativeTitle: 'O Médico dos Clubes' },
    giant_revival:  { minRep: 40, reputationBoost: 30, reputationLoss: 10, narrativeTitle: 'O Ressurgimento' },
    cup_mission:    { minRep: 20, reputationBoost: 15, reputationLoss: 3,  narrativeTitle: 'O Copeiro' },
    total_rebuild:  { minRep: 30, reputationBoost: 25, reputationLoss: 8,  narrativeTitle: 'O Arquiteto' },
    style_duel:     { minRep: 0,  reputationBoost: 10, reputationLoss: 2,  narrativeTitle: 'O Estrategista' },
};

/**
 * Avalia se um desafio orgânico está disponível.
 *
 * @param {object} opts
 * @param {number} [opts.managerId]
 * @param {number} [opts.currentClubId]
 * @param {number} [opts.season=1]
 * @param {number} [opts.week=1]
 * @param {number} [opts.managerReputation=10]
 * @param {boolean} [opts.managerAvailable=true]
 * @param {Array<{id,name,division}>} [opts.clubsInRelegationZone=[]]
 * @param {Array<{id,name,division,historicDivision}>} [opts.historicClubsInLowerDivisions=[]]
 * @param {number} [opts.upcomingRivalWeek=-1] — week of next big rival match
 * @returns {{ challengeAvailable, challenge? }}
 */
export function evaluate({ managerId = 0, currentClubId = 0, season = 1, week = 1, managerReputation = 10, managerAvailable = true, clubsInRelegationZone = [], historicClubsInLowerDivisions = [], upcomingRivalWeek = -1 } = {}) {
    // Challenges only from season 2 onward (player needs to establish themselves)
    if (season < 2) return { challengeAvailable: false };

    // Try each challenge type in priority order
    const crisis = clubsInRelegationZone.find(c => c.id !== currentClubId);
    if (crisis && managerReputation >= CHALLENGE_TYPES.crisis_save.minRep) {
        return buildChallenge('crisis_save', crisis, `O ${crisis.name} está no Z4 — eles precisam de você agora.`, week);
    }

    const giant = historicClubsInLowerDivisions.find(c => c.id !== currentClubId && c.historicDivision === 1 && c.division >= 2);
    if (giant && managerReputation >= CHALLENGE_TYPES.giant_revival.minRep) {
        return buildChallenge('giant_revival', giant, `O ${giant.name} quer voltar à elite. Você aceita o desafio?`, week);
    }

    if (upcomingRivalWeek > 0 && upcomingRivalWeek <= week + 2) {
        const dummy = { id: -1, name: 'Rival Tático' };
        return buildChallenge('style_duel', dummy, `Clássico com stakes extras: prove sua superioridade tática.`, week);
    }

    // §14.2: Total Rebuild — when manager has high rep and a struggling team exists
    const struggling = clubsInRelegationZone.find(c => c.id !== currentClubId && c.division >= 2);
    if (struggling && managerReputation >= CHALLENGE_TYPES.total_rebuild.minRep && season >= 3) {
        return buildChallenge('total_rebuild', struggling, `O ${struggling.name} precisa de uma reconstrução total. Será que você tem o que é preciso?`, week);
    }

    // §14.2: Cup Mission — triggered mid-season when cup competition is active
    if (week >= 10 && week <= 30 && managerReputation >= CHALLENGE_TYPES.cup_mission.minRep) {
        const cupTarget = { id: currentClubId, name: 'Seu clube' };
        if (season >= 2 && week % 15 === 0) {
            return buildChallenge('cup_mission', cupTarget, `A diretoria exige: "Precisamos de um título de Copa este ano!"`, week);
        }
    }

    return { challengeAvailable: false };
}

/**
 * Processa aceitação de desafio.
 * @param {object} challenge — desafio retornado por evaluate()
 * @returns {{ accepted: true, challengeId }}
 */
export function accept(challenge) {
    return { accepted: true, challengeId: challenge.challengeId };
}

/**
 * Completa desafio — sucesso ou falha.
 * @param {object} opts
 * @param {string} opts.challengeType
 * @param {boolean} opts.success
 * @param {number} [opts.currentReputation=10]
 * @returns {{ reputationDelta, narrativeTitle, outcome }}
 */
export function complete({ challengeType, success, currentReputation = 10 } = {}) {
    const cfg = CHALLENGE_TYPES[challengeType] || CHALLENGE_TYPES.style_duel;
    if (success) {
        return {
            reputationDelta: +cfg.reputationBoost,
            narrativeTitle: cfg.narrativeTitle,
            outcome: 'success',
        };
    }
    return {
        reputationDelta: -cfg.reputationLoss,
        narrativeTitle: null,
        outcome: 'failure',
    };
}

// ─── helpers ────────────────────────────────────────────────

function buildChallenge(type, club, description, week) {
    const cfg = CHALLENGE_TYPES[type];
    return {
        challengeAvailable: true,
        challenge: {
            challengeId: `ch-${type}-${club.id}-${week}`,
            type,
            targetClubId: club.id,
            targetClubName: club.name,
            description,
            reward: { reputationBoost: cfg.reputationBoost, narrativeTitle: cfg.narrativeTitle },
            penalty: { reputationLoss: cfg.reputationLoss },
            deadline: week + 4,
            optional: true,
        },
    };
}

/**
 * PlayerDevelopment.js — Aging, Form, Development, Retirement
 * 
 * §3 do Game Design Document — Player Development Science:
 * - Crescimento: CA → PA asymptotic (últimos 5% são os mais difíceis)
 * - Curvas de idade DIFERENTES por posição (§3.1)
 * - Physical stats declinam rápido; mental stats podem SUBIR após 30
 * - Individual variance (σ = 1-3 anos around peak)
 * - Aposentadoria: 35-40 com chance crescente (goleiros até 38)
 * - Form: hot/cold streaks baseado em performance
 */

import { rng } from './rng';
import { calcMarketValue } from './MarketPricer.js';

/**
 * BUG-096: Guard — garante que player.attributes existe e tem todos os 5 campos.
 * Autoplay session 08 revelou ~1.500 crashes por jogadores com attributes=undefined
 * (causados por transição de temporada, PlayerCareer, ou transferências com schema incompleto).
 * Chamada como guard ANTES de qualquer acesso a player.attributes.
 */
export function ensureAttributes(player) {
    if (!player) return player;
    const defaults = { FIS: 50, DEF: 50, CRI: 50, FIN: 50, REF: 50 };
    if (!player.attributes || typeof player.attributes !== 'object') {
        player.attributes = { ...defaults };
    } else {
        for (const [attr, fallback] of Object.entries(defaults)) {
            if (player.attributes[attr] === undefined || player.attributes[attr] === null) {
                player.attributes[attr] = fallback;
            }
        }
    }
    return player;
}

const PERSONALITY_GROWTH = {
    "Profissional": 1.3,     // treina mais, cresce mais
    "Ambicioso": 1.2,        // quer jogar, cresce se titular
    "Determinado": 1.15,     // constante
    "Casual": 0.9,           // não se esforça tanto
    "Preguiçoso": 0.7,       // mínimo esforço
    "Líder Nato": 1.25,      // MEGA PATCH: inspira e cresce junto
    "Rebelde": 1.1,          // MEGA PATCH: talentoso mas inconsistente
    "Tímido": 0.95,          // MEGA PATCH: cresce devagar mas não reclama
};

/**
 * §3.1: Position-specific age curves.
 * peak = center of peak zone, declineOnset = when physical decline begins
 * retireMin = earliest retirement age, peakVariance = σ individual spread
 */
const POSITION_AGE_CURVES = {
    ATA: { peak: 27, declineOnset: 31, retireMin: 34, peakVariance: 2 },
    MEI: { peak: 28, declineOnset: 31, retireMin: 34, peakVariance: 2 },
    DEF: { peak: 29, declineOnset: 32, retireMin: 35, peakVariance: 2 },
    GOL: { peak: 30, declineOnset: 34, retireMin: 36, peakVariance: 3 },
};

/**
 * Attribute categories — physical decline fast, mental can improve.
 * §3.1: "Physical stats decline sharply after peak; Mental stats can IMPROVE past 30"
 */
const PHYSICAL_ATTRS = ['FIS'];        // speed, stamina, acceleration
const TECHNICAL_ATTRS = ['FIN', 'REF']; // finishing, reflexes — slow decline
const MENTAL_ATTRS = ['CRI'];           // creativity, vision, positioning — can grow
const DEFENSIVE_ATTR = 'DEF';           // depends on position

/**
 * §3.2: Processa desenvolvimento semanal de um jogador.
 * CA approaches PA asymptotically — the last 5% is hardest.
 * Not every player reaches their potential.
 *
 * Retorna um array de mensagens de mudança.
 */
export function processPlayerDevelopment(player) {
    ensureAttributes(player); // BUG-096: guard contra attributes undefined
    const changes = [];
    const personalityMod = PERSONALITY_GROWTH[player.personality] || 1.0;
    const curve = POSITION_AGE_CURVES[player.position] || POSITION_AGE_CURVES.MEI;

    // Individual variance: cada jogador tem ±variance anos de offset
    // Deterministic per player using id hash (não muda entre semanas)
    const playerVariance = player._peakVariance ?? 0;

    const effectivePeak = curve.peak + playerVariance;
    const effectiveDecline = curve.declineOnset + playerVariance;

    // === CRESCIMENTO NATURAL (pre-peak) ===
    if (player.age < effectivePeak) {
        // §3.2: Gap entre PA e CA determina growth rate (asymptotic)
        const potential = player.potential || (player.ovr + 15);
        const gap = Math.max(0, potential - (player.ovr || 50));

        // Growth chance scales with gap: big gap = easier, small gap = very hard
        // Asymptotic formula: chance = base × (gap / maxGap) × personalityMod
        const ageBonus = player.age < 20 ? 1.5 : player.age < 23 ? 1.2 : 1.0;
        const gapFactor = gap > 20 ? 0.30 : gap > 10 ? 0.18 : gap > 5 ? 0.10 : 0.04;
        const growthChance = gapFactor * personalityMod * ageBonus;

        if (rng.chance(growthChance)) {
            const attrs = Object.keys(player.attributes);
            const attr = rng.pick(attrs);
            const boost = player.age < 20 ? 2 : 1;
            const oldVal = player.attributes[attr];
            // Cap at potential-derived ceiling
            const ceiling = Math.min(99, Math.floor(potential * 1.05));
            player.attributes[attr] = Math.min(ceiling, oldVal + boost);
            if (player.attributes[attr] > oldVal) {
                changes.push({ type: 'growth', player: player.name, attr, from: oldVal, to: player.attributes[attr] });
            }
        }
    }

    // === DECLÍNIO (post-peak, position-specific) ===
    if (player.age >= effectiveDecline) {
        const yearsOverDecline = player.age - effectiveDecline;

        // Physical attributes: decline sharply (§3.1)
        const physDeclineChance = yearsOverDecline * 0.06; // 6% per year
        PHYSICAL_ATTRS.forEach(attr => {
            if (player.attributes[attr] !== undefined && rng.chance(physDeclineChance)) {
                const oldVal = player.attributes[attr];
                const drop = yearsOverDecline >= 3 ? 2 : 1;
                player.attributes[attr] = Math.max(20, oldVal - drop);
                if (player.attributes[attr] < oldVal) {
                    changes.push({ type: 'decline', player: player.name, attr, from: oldVal, to: player.attributes[attr] });
                }
            }
        });

        // Technical attributes: decline slowly (§3.1)
        const techDeclineChance = yearsOverDecline * 0.03; // 3% per year
        TECHNICAL_ATTRS.forEach(attr => {
            if (player.attributes[attr] !== undefined && rng.chance(techDeclineChance)) {
                const oldVal = player.attributes[attr];
                player.attributes[attr] = Math.max(25, oldVal - 1);
                if (player.attributes[attr] < oldVal) {
                    changes.push({ type: 'decline', player: player.name, attr, from: oldVal, to: player.attributes[attr] });
                }
            }
        });

        // DEF attribute: position-dependent decline
        // Centerbacks/GKs lose defensive awareness slower (cognitive compensates)
        if (player.attributes[DEFENSIVE_ATTR] !== undefined) {
            const defDeclineRate = (player.position === 'DEF' || player.position === 'GOL')
                ? yearsOverDecline * 0.02  // very slow — experience compensates
                : yearsOverDecline * 0.04; // moderate for other positions
            if (rng.chance(defDeclineRate)) {
                const oldVal = player.attributes[DEFENSIVE_ATTR];
                player.attributes[DEFENSIVE_ATTR] = Math.max(25, oldVal - 1);
                if (player.attributes[DEFENSIVE_ATTR] < oldVal) {
                    changes.push({ type: 'decline', player: player.name, attr: DEFENSIVE_ATTR, from: oldVal, to: player.attributes[DEFENSIVE_ATTR] });
                }
            }
        }

        // Mental attributes: can IMPROVE past peak! (§3.1)
        // Creativity/positioning grows from experience — 5% chance per year
        const mentalGrowthChance = 0.05 * personalityMod;
        MENTAL_ATTRS.forEach(attr => {
            if (player.attributes[attr] !== undefined && rng.chance(mentalGrowthChance)) {
                const oldVal = player.attributes[attr];
                player.attributes[attr] = Math.min(99, oldVal + 1);
                if (player.attributes[attr] > oldVal) {
                    changes.push({ type: 'growth', player: player.name, attr, from: oldVal, to: player.attributes[attr] });
                }
            }
        });
    }

    // === APOSENTADORIA (position-aware) ===
    if (player.age >= curve.retireMin) {
        const yearsOverRetireMin = player.age - curve.retireMin;
        const retireChance = (yearsOverRetireMin + 1) * 0.12;
        if (rng.chance(retireChance)) {
            player._retired = true;
            changes.push({ type: 'retirement', player: player.name, age: player.age });
        }
    }
    // BUG-079: safety cap — force-retire if age > 42 (probability of reaching this
    // naturally is ~0, so any player here escaped the stochastic retirement system).
    if (!player._retired && player.age > 42) {
        player._retired = true;
        changes.push({ type: 'retirement', player: player.name, age: player.age });
    }

    // Assign individual peak variance on first run (deterministic from id)
    if (player._peakVariance === undefined) {
        // Hash player id to get ±variance consistently
        const hash = typeof player.id === 'string'
            ? player.id.split('').reduce((h, c) => ((h << 5) - h + c.charCodeAt(0)) | 0, 0)
            : (player.id || 0);
        player._peakVariance = (Math.abs(hash) % (curve.peakVariance * 2 + 1)) - curve.peakVariance;
    }

    // Recalc OVR
    recalcOvr(player);

    return changes;
}

/**
 * Envelhece jogadores 1 ano. Chamar 1x por temporada.
 */
export function ageSquad(squad) {
    const events = [];
    squad.forEach(p => {
        p.age++;
        if (p.age >= 35) {
            events.push(`🎂 ${p.name} fez ${p.age} anos. A aposentadoria se aproxima.`);
        }
    });
    return events;
}

/**
 * Form system — tracks últimas 5 participações em jogos
 * Cada jogador tem player.form = { last5: [1,0,-1,1,0], trend: 'hot'|'cold'|'normal' }
 */
export function initForm(player) {
    if (!player.form) {
        player.form = { last5: [], trend: 'normal' };
    }
}

export function updateForm(player, result) {
    initForm(player);
    // result: 1 = bom (titular em vitória/gol), 0 = neutro, -1 = ruim (derrota)
    player.form.last5.push(result);
    if (player.form.last5.length > 5) player.form.last5.shift();

    const avg = player.form.last5.reduce((s, v) => s + v, 0) / player.form.last5.length;
    if (avg >= 0.6) player.form.trend = 'hot';
    else if (avg <= -0.4) player.form.trend = 'cold';
    else player.form.trend = 'normal';
}

export function getFormEmoji(trend) {
    if (trend === 'hot') return '🔥';
    if (trend === 'cold') return '❄️';
    return '';
}

export function getFormModifier(trend) {
    if (trend === 'hot') return 1.08;   // +8% em performance
    if (trend === 'cold') return 0.92;  // -8%
    return 1.0;
}

