/**
 * Check if two teams are rivals (same city/zone)
 */
export function isRivalry(team1, team2) {
    if (!team1 || !team2) return false;
    // Same zone = rivalry
    return team1.zone === team2.zone && team1.division === team2.division;
}

/**
 * Transfer Negotiation — counter-offer system
 */
export function generateCounterOffer(player, initialOffer, round) {
    const baseValue = player.value || (player.ovr * 100000);
    const desiredPrice = baseValue * (1.3 + systemRng() * 0.7); // 130-200% of value

    if (round >= 3) {
        // Final offer — take it or leave it
        return {
            round,
            accepted: initialOffer >= desiredPrice * 0.85,
            counterAmount: Math.floor(desiredPrice * 0.9),
            msg: initialOffer >= desiredPrice * 0.85
                ? `${player.name} aceita a proposta!`
                : `${player.name} recusa a oferta final. Negociação encerrada.`,
            final: true,
        };
    }

    if (initialOffer >= desiredPrice) {
        return { round, accepted: true, counterAmount: initialOffer, msg: `Oferta aceita por ${player.name}!`, final: true };
    }

    // Counter with a price between current and desired
    const gap = desiredPrice - initialOffer;
    const counterAmount = Math.floor(initialOffer + gap * (0.4 + round * 0.15));

    return {
        round,
        accepted: false,
        counterAmount,
        msg: `O agente de ${player.name} pede R$ ${(counterAmount / 1000000).toFixed(1)}M.`,
        final: false,
    };
}

/**
 * RivalryUpgradeSystem — SPEC-080: Rivalidades com Peso Narrativo Real
 *
 * Expande SPEC-017 (derby básico): criticalCount real + 6 arcos nomeados.
 * Resolve: rivais se enfrentam 11x mas criticalCount=0 (nenhum decisivo).
 *
 * Stateless: recebe histórico de confrontos, retorna estado de rivalidade.
 */

const NAMED_ARCS = [
    { id: 'classico_eterno',   threshold: 10, name: 'Clássico Eterno',   description: '10+ confrontos registrados' },
    { id: 'batalha_das_geracoes', threshold: 20, name: 'Batalha das Gerações', description: '20+ confrontos com múltiplas eras' },
    { id: 'revanche',          threshold: 5,  name: 'Revanche',          description: '3+ vitórias consecutivas de um lado' },
    { id: 'equilíbrio_perfeito', threshold: 0, name: 'Equilíbrio Perfeito', description: 'Winrate entre 45-55% para ambos' },
    { id: 'dominio_absoluto',  threshold: 0,  name: 'Domínio Absoluto',  description: 'Um lado com 70%+ winrate' },
    { id: 'confronto_titulo',  threshold: 0,  name: 'Confronto de Título', description: 'Ambos disputaram título no mesmo ano' },
];

/**
 * Avalia estado atual de uma rivalidade entre dois clubes.
 *
 * @param {object} opts
 * @param {number} opts.clubAId
 * @param {number} opts.clubBId
 * @param {Array<{clubAScore, clubBScore, week, season, isDecisive}>} [opts.history=[]]
 * @param {boolean} [opts.bothInTitleRace=false]
 * @returns {{ rivalryScore, criticalCount, activeArc, h2h, namedRivalry }}
 */
export function evaluate({ clubAId, clubBId, history = [], bothInTitleRace = false } = {}) {
    const total = history.length;
    const aWins = history.filter(m => m.clubAScore > m.clubBScore).length;
    const bWins = history.filter(m => m.clubBScore > m.clubAScore).length;
    const draws = total - aWins - bWins;
    const criticalCount = history.filter(m => m.isDecisive).length;

    const aWinRate = total > 0 ? aWins / total : 0;
    const bWinRate = total > 0 ? bWins / total : 0;

    // Rivalry score 0-100
    const rivalryScore = Math.min(100, Math.round(total * 4 + criticalCount * 10));

    const h2h = { total, aWins, bWins, draws, aWinRate, bWinRate, criticalCount };

    // Determine active arc
    const activeArc = pickArc({ total, aWinRate, bWinRate, criticalCount, bothInTitleRace, history });

    const namedRivalry = rivalryScore >= 40;

    return { rivalryScore, criticalCount, activeArc, h2h, namedRivalry };
}

/**
 * Registra confronto crítico (decisivo para título/classificação).
 */
export function markCritical(match) {
    return { ...match, isDecisive: true };
}

// ─── helpers ────────────────────────────────────────────────

function pickArc({ total, aWinRate, bWinRate, criticalCount, bothInTitleRace, history }) {
    if (bothInTitleRace) return NAMED_ARCS.find(a => a.id === 'confronto_titulo');
    // Match-count arcs take priority (historia > equilíbrio momentâneo)
    if (total >= 20) return NAMED_ARCS.find(a => a.id === 'batalha_das_geracoes');
    if (total >= 10) return NAMED_ARCS.find(a => a.id === 'classico_eterno');
    if (aWinRate >= 0.7 || bWinRate >= 0.7) return NAMED_ARCS.find(a => a.id === 'dominio_absoluto');
    if (Math.abs(aWinRate - bWinRate) < 0.1 && total >= 5) return NAMED_ARCS.find(a => a.id === 'equilíbrio_perfeito');
    // Check revenge arc: 3+ consecutive wins for one side
    if (history.length >= 3) {
        const last3 = history.slice(-3);
        const allAWins = last3.every(m => m.clubAScore > m.clubBScore);
        const allBWins = last3.every(m => m.clubBScore > m.clubAScore);
        if (allAWins || allBWins) return NAMED_ARCS.find(a => a.id === 'revanche');
    }
    return null;
}

/**
 * SPEC-150: Season Story Engine — gera resumo narrativo de cada temporada.
 * AUDIT-FIX #G: Adicionado sistema de arcos inter-temporada.
 */
export function generateSeasonStory({ wins = 0, draws = 0, losses = 0, goalsFor = 0, goalsAgainst = 0,
    topScorer = null, longestWinStreak = 0, biggestWin = null, worstLoss = null,
    position = 10, promoted = false, relegated = false, division = 1, seasonNumber = 1,
    previousStories = [] } = {}) {

    const record = `${wins}V ${draws}E ${losses}D`;
    const mood = (promoted && wins >= 20) ? 'epic'
        : relegated ? 'tragic'
        : position <= 3 ? 'great'
        : position >= 17 ? 'survival'
        : 'mediocre';

    // ── AUDIT-FIX #G: Inter-season arc detection ──────────────
    const arc = detectArc(previousStories, mood, division, position, seasonNumber);

    let headline;
    if (arc.active) {
        // Use arc narrative instead of generic headline
        headline = arc.headline;
    } else if (promoted && wins >= 20) {
        const divNames = ['', 'Série A', 'Série B', 'Série C', 'Série D'];
        headline = `Campeão! Promovido para ${divNames[division - 1] || 'divisão acima'} com ${wins} vitórias`;
    } else if (promoted) {
        headline = `Promovido! ${wins}V na temporada`;
    } else if (relegated) {
        headline = `Rebaixado após temporada difícil (${wins}V ${losses}D)`;
    } else if (longestWinStreak >= 8) {
        headline = `Sequência histórica de ${longestWinStreak} vitórias seguidas`;
    } else if (biggestWin?.diff >= 4) {
        headline = `Goleada memorável de ${biggestWin.score}`;
    } else {
        headline = `Temporada ${position}º — ${wins}V ${draws}E ${losses}D`;
    }

    const scorerText = topScorer?.goals > 0
        ? `${topScorer.name} — ${topScorer.goals} gols`
        : null;

    const moment = longestWinStreak >= 5
        ? `Sequência de ${longestWinStreak} vitórias`
        : (worstLoss?.diff >= 4 ? `Goleada sofrida: ${worstLoss.score}` : null);

    return { headline, topScorer: scorerText, record, moment, mood, season: seasonNumber, arc: arc.name || null };
}

/**
 * AUDIT-FIX #G: Detect multi-season narrative arcs.
 * Tracks patterns across previous seasons and generates contextual headlines.
 */
function detectArc(previousStories, currentMood, division, position, season) {
    if (!previousStories || previousStories.length < 2) {
        return { active: false };
    }

    const recent = previousStories.slice(-5);

    // ── ARC: DYNASTY (3+ consecutive good/epic seasons) ──────
    const consecutiveGood = countConsecutiveFromEnd(recent, s => s.mood === 'great' || s.mood === 'epic');
    if (consecutiveGood >= 2 && (currentMood === 'great' || currentMood === 'epic')) {
        const years = consecutiveGood + 1;
        return {
            active: true,
            name: 'DYNASTY',
            headline: `🏛️ ${years}ª temporada consecutiva no topo — a DINASTIA continua!`
        };
    }

    // ── ARC: REBUILDING (2+ mediocre/survival after tragic) ──
    const hadTragic = recent.some(s => s.mood === 'tragic');
    const recentMediocre = countConsecutiveFromEnd(recent, s => s.mood === 'mediocre' || s.mood === 'survival');
    if (hadTragic && recentMediocre >= 1 && (currentMood === 'mediocre' || currentMood === 'survival')) {
        const years = recentMediocre + 1;
        return {
            active: true,
            name: 'REBUILDING',
            headline: `🔨 Ano ${years} de reconstrução — o projeto começa a tomar forma`
        };
    }

    // ── ARC: PHOENIX (great/epic season right after tragic) ──
    const lastMood = recent[recent.length - 1]?.mood;
    if (lastMood === 'tragic' && (currentMood === 'great' || currentMood === 'epic')) {
        return {
            active: true,
            name: 'PHOENIX',
            headline: `🔥 RENASCIMENTO! Da humilhação ao topo em uma temporada!`
        };
    }

    // ── ARC: YO-YO (alternating tragic/great moods) ──────────
    if (recent.length >= 3) {
        const pattern = recent.slice(-3).map(s => s.mood);
        const isYoyo = (pattern[0] === 'tragic' && pattern[1] === 'great' && currentMood === 'tragic') ||
                       (pattern[0] === 'great' && pattern[1] === 'tragic' && currentMood === 'great');
        if (isYoyo) {
            return {
                active: true,
                name: 'YOYO',
                headline: `🎢 O ELEVADOR não para — mais uma temporada na montanha-russa!`
            };
        }
    }

    // ── ARC: UNDERDOG CLIMB (steadily improving position) ────
    if (recent.length >= 2) {
        const improving = recent.every((s, i) => {
            if (i === 0) return true;
            // mood order: tragic < survival < mediocre < great < epic
            const moodOrder = { tragic: 0, survival: 1, mediocre: 2, great: 3, epic: 4 };
            return (moodOrder[s.mood] || 0) >= (moodOrder[recent[i-1].mood] || 0);
        });
        const currentOrder = { tragic: 0, survival: 1, mediocre: 2, great: 3, epic: 4 };
        if (improving && (currentOrder[currentMood] || 0) > (currentOrder[recent[recent.length - 1]?.mood] || 0)) {
            return {
                active: true,
                name: 'UNDERDOG',
                headline: `📈 A escalada continua! ${season}ª temporada de progresso constante!`
            };
        }
    }

    return { active: false };
}

function countConsecutiveFromEnd(arr, predicate) {
    let count = 0;
    for (let i = arr.length - 1; i >= 0; i--) {
        if (predicate(arr[i])) count++;
        else break;
    }
    return count;
}

/**
 * SquadHealthMonitor — SPEC-132: Squad Emergency Market
 *
 * Detecta squad com jogadores insuficientes e aciona resposta.
 * Resolve SQUAD_SHORT (7 players season 44 sem nenhuma reação).
 *
 * Stateless: recebe dados, retorna ação a tomar.
 */

const MIN_SQUAD = 11;
const CRISIS_SQUAD = 8;
const TRIGGER_COOLDOWN_KEY = '_squadMonitorLastWeek';

/**
 * Verifica saúde do squad e retorna ação necessária.
 *
 * @param {object} opts
 * @param {number} opts.teamId
 * @param {number} opts.squadSize — jogadores disponíveis (não lesionados)
 * @param {number} opts.budget
 * @param {boolean} opts.isPlayerManager
 * @param {number} opts.week
 * @param {number} [opts.squadAvgOvr=65]
 * @param {Array} [opts.marketPlayers=[]] — jogadores disponíveis no mercado
 * @param {object} [opts._cooldowns={}] — mapa teamId→última semana de trigger
 * @returns {object} resultado da verificação
 */
export function checkSquadHealth({ teamId, squadSize, budget, isPlayerManager, week, squadAvgOvr = 65, marketPlayers = [], _cooldowns = {} }) {
    // Cooldown: não disparar mais de 1x por semana por time
    if (_cooldowns[teamId] === week) {
        return { triggered: false, action: 'none' };
    }

    if (squadSize >= MIN_SQUAD) {
        return { triggered: false, action: 'none' };
    }

    // Para player-manager: sempre alerta (nunca compra automático)
    if (isPlayerManager) {
        const shortage = MIN_SQUAD - squadSize;
        return {
            triggered: true,
            action: 'alert_player',
            alertMessage: squadSize <= CRISIS_SQUAD
                ? `⚠️ CRISE! Apenas ${squadSize} jogadores disponíveis. Você precisa de ${shortage} reforços urgentes!`
                : `📋 Elenco curto: ${squadSize} jogadores. Considere contratar ${shortage} reforços.`,
            forceMarketOpen: squadSize <= CRISIS_SQUAD,
        };
    }

    // Para NPCs: compra automática se há budget
    if (budget <= 0) {
        return { triggered: true, action: 'auto_buy', playersBought: [], budgetSpent: 0 };
    }

    const needed = MIN_SQUAD - squadSize;
    const bought = buyEmergencyPlayers(needed, squadAvgOvr, budget, marketPlayers);

    return {
        triggered: true,
        action: 'auto_buy',
        playersBought: bought.players,
        budgetSpent: bought.totalCost,
    };
}

// ─── helpers ────────────────────────────────────────────────

function buyEmergencyPlayers(needed, squadAvgOvr, budget, marketPlayers) {
    const maxOvr = squadAvgOvr + 5; // não up-grade em emergência
    const affordable = marketPlayers
        .filter(p => p.ovr <= maxOvr && (p.value || 0) <= budget * 0.5)
        .sort((a, b) => b.ovr - a.ovr);

    const players = [];
    let totalCost = 0;

    for (let i = 0; i < needed && i < affordable.length; i++) {
        const p = affordable[i];
        const cost = p.value || 100000;
        if (totalCost + cost > budget * 0.5) continue;
        players.push({ playerId: p.id, name: p.name, ovr: p.ovr, cost });
        totalCost += cost;
    }

    return { players, totalCost };
}

/**
 * StarProtectionSystem — SPEC-075: Craque Protegido pelo Técnico
 *
 * Técnico declara proteção a 1 jogador. Board tentando vender → tensão spike.
 * narrativeState calculado a partir de performance real do protegido.
 *
 * Stateful: armazena proteção ativa por managerId.
 */

const _protected = new Map(); // managerId → protectionState

/**
 * Declara proteção a um jogador.
 * @throws 'AlreadyProtecting' se já há protegido
 * @throws 'PlayerUnavailableLongTerm' se injuryWeeksLeft > 8
 */
export function protect({ managerId, playerId, playerName = 'Jogador', playerOvr = 70, publicDeclaration = false, injuryWeeksLeft = 0 } = {}) {
    if (_protected.has(managerId)) throw new Error('AlreadyProtecting');
    if (injuryWeeksLeft > 8) throw new Error('PlayerUnavailableLongTerm');

    const state = {
        protectedPlayerId: playerId,
        protectedPlayerName: playerName,
        active: true,
        declaredPublicly: publicDeclaration,
        performanceSince: { games: 0, goals: 0, assists: 0, avgRating: 7.0 },
        narrativeState: 'neutral',
    };
    _protected.set(managerId, state);

    const result = { protection: state };
    if (publicDeclaration) {
        result.pressEvent = {
            type: 'manager_protects_player',
            description: `Técnico declara apoio público a ${playerName}. A cidade inteira vai acompanhar.`,
            sentiment: 'neutral',
        };
    }
    return result;
}

/**
 * Retorna estado de proteção atual (ou null).
 */
export function getProtected(managerId) {
    return _protected.get(managerId) || null;
}

/**
 * Revoga proteção atual.
 */
export function revoke({ managerId } = {}) {
    const current = _protected.get(managerId);
    if (!current) return { narrativeEvent: { type: 'nothing' } };
    _protected.delete(managerId);
    return {
        narrativeEvent: {
            type: 'manager_revoked_protection',
            description: `Técnico encerrou a proteção pública a ${current.protectedPlayerName}.`,
            sentiment: 'neutral',
        },
    };
}

/**
 * Board tenta vender jogador protegido → tensão spike.
 */
export function onBoardSellAttempt({ managerId, playerId } = {}) {
    const current = _protected.get(managerId);
    if (!current || current.protectedPlayerId !== playerId) return null;
    return {
        type: 'board_threatened_protected',
        tensionDelta: -30,
        publicReaction: 'Torcida apoia técnico. Diretoria sob pressão.',
        managerChoice: 'defend',
    };
}

/**
 * Computa narrativeState a partir da performance registrada.
 */
export function computeState({ performanceSince } = {}) {
    const { games = 0, avgRating = 7.0 } = performanceSince;
    let narrativeState = 'neutral';
    if (games >= 5) {
        if (avgRating >= 7.5) narrativeState = 'hero';
        else if (avgRating < 6.0) narrativeState = 'villain';
    }
    return { narrativeState };
}

/**
 * Gera eventos narrativos baseados no state atual.
 */
export function generateNarrativeEvents({ narrativeState, playerName = 'Jogador' } = {}) {
    if (narrativeState === 'hero') {
        return [{ type: 'press_headline', sentiment: 'positive', text: `${playerName} confirma genialidade do técnico.` }];
    }
    if (narrativeState === 'villain') {
        return [{ type: 'press_headline', sentiment: 'negative', text: `Mídia questiona escolha do técnico por ${playerName}.` }];
    }
    return [];
}

/** Update performance stats for protected player */
export function updatePerformance({ managerId, goals = 0, assists = 0, rating = 7.0 } = {}) {
    const current = _protected.get(managerId);
    if (!current) return;
    const p = current.performanceSince;
    p.games++;
    p.goals += goals;
    p.assists += assists;
    p.avgRating = (p.avgRating * (p.games - 1) + rating) / p.games;
    current.narrativeState = computeState({ performanceSince: p }).narrativeState;
}

