export function actionRelevance(action, goal) {
    const map = GOAL_RELEVANCE[goal] || {};
    return map[action] ?? 0;
}

// ─── PROSPECT THEORY REWARD (Fase 3) ─────────────────────────

/**
 * Prospect Theory value function.
 * - Gains: v(x) = x^α           (concave → risk-averse when winning)
 * - Losses: v(x) = -λ·|x|^β     (convex → risk-seeking when losing)
 *
 * @param {number} x — raw reward delta
 * @returns {number} perceived value
 */
function prospectValue(x) {
    if (x >= 0) {
        return Math.pow(x, DIMINISHING_GAINS_ALPHA);
    }
    return -LOSS_AVERSION_LAMBDA * Math.pow(Math.abs(x), RISK_SEEKING_LOSSES_BETA);
}

/**
 * Compute reward from match + state delta.
 * Now uses Prospect Theory (Fase 3):
 *   - Losses weighted 2x heavier (loss aversion)
 *   - Gains have diminishing returns (risk aversion when ahead)
 *   - Reference point = expected position for division
 *
 * @param {Object} params
 * @param {number} [params.emotionalLossMod=1.0] — from EmotionalEngine
 */
export function computeReward({
    matchResult, balanceDelta, positionDelta, promoted, relegated, title,
    goalsScored = 0, goalsAllowed = 0, scoreDiff = 0,
    emotionalLossMod = 1.0
}) {
    let r = 0;

    // Match result base (raw, before Prospect Theory)
    if (matchResult === 'W') r += 10;
    else if (matchResult === 'D') r += 2;
    else if (matchResult === 'L') {
        // BUG-041: soften crushing losses but reward narrow ones
        if (Math.abs(scoreDiff) <= 1) r -= 1;
        else if (Math.abs(scoreDiff) <= 3) r -= 3;
        else r -= 5;
        // Emotional amplification: ANXIOUS/TILTED feel losses harder
        r *= emotionalLossMod;
    }

    // BUG-041: own scoring is intrinsic positive signal even in loss
    r += Math.min(5, goalsScored * 1.5);
    // Defensive performance
    if (matchResult !== 'L' && goalsAllowed === 0) r += 3;

    // Balance trend — apply Prospect Theory
    if (balanceDelta) {
        const balReward = balanceDelta / 1_000_000;
        r += prospectValue(Math.max(-10, Math.min(10, balReward)));
    }

    // Position movement — apply Prospect Theory
    if (positionDelta) {
        r += prospectValue(positionDelta * 2);
    }

    // Season events — BUG-RC1 fix: rewards MUST be symmetric to avoid
    // Q-value collapse during yo-yo cycles. Previous: promoted=+50, relegated=-100
    // caused net=-50 per cycle × 93 cycles = -4650 cumulative bias.
    if (promoted) r += 60;
    if (relegated) r -= 60 * emotionalLossMod;
    if (title) r += 200;

    return r;
}

// ─── ADAPTIVE BRAIN CLASS ────────────────────────────────────

export class AdaptiveBrain {
    /**
     * @param {string|null} personalityId — archetype seed (e.g. 'GUARDIOLA')
     */
    constructor(personalityId = null) {
        this.qTable = {};
        this.visitCount = {};
        this.totalUpdates = 0;
        this.lastSavedAt = 0;

        // Q(λ) Eligibility Traces — Replacing Traces variant
        // Ref: Singh & Sutton, 1996 — "RL with Replacing Eligibility Traces"
        // Each entry: traces[stateKey][actionKey] = traceValue (0..1)
        this.traces = {};

        // Fase 1: OCEAN personality
        this.personality = personalityId
            ? generatePersonality(personalityId)
            : generateRandomPersonality();

        // Fase 2: Emotional State Machine
        this.emotions = new EmotionalEngine(this.personality);

        // SPEC-122 BUG-054: episodic memory — last N decisions+outcomes for RAG.
        this.memory = [];
        this.memoryMax = 30;

        // Fase 5: Learned Goal Relevance Matrix
        // Ref: Agrawal & Goyal (2013) — Thompson Sampling for Contextual Bandits
        this.goalRelevance = new LearnedGoalRelevance();

        // Fase C: Experience Replay Buffer
        // Ref: Lin (1992) — "Self-Improving Reactive Agents Based on RL, Planning and Teaching"
        // Ref: Schaul et al (2015) — "Prioritized Experience Replay"
        // Stores recent transitions for offline re-training at season boundaries
        this.replayBuffer = [];

        // AUDIT-FIX #F: Yo-yo detector — tracks division history for meta-learning
        // Detects promotion→relegation→promotion cycles and applies penalty
        this.divisionHistory = [];
        this._yoyoCount = 0;

        this._restore();
    }

    // ─── EMOTIONAL INTERFACE (Fase 2) ────────────────────────

    /**
     * Process a match result through the Emotional Engine.
     * Call this AFTER each match to update the bot's emotional state.
     *
     * @param {'W'|'D'|'L'} result
     * @param {number} streak — current streak (positive=wins, negative=losses)
     * @param {boolean} [isRelegationRisk=false]
     * @returns {{ from, to, changed }}
     */
    processMatchResult(result, streak, isRelegationRisk = false) {
        const event = result === 'W' ? 'WIN' : result === 'D' ? 'DRAW' : 'LOSS';
        return this.emotions.processEvent(event, streak, isRelegationRisk);
    }

    /**
     * Process a major season event.
     * @param {'TITLE'|'PROMOTION'|'RELEGATION_RISK'|'STREAK_BROKEN'} event
     */
    processSeasonEvent(event, streak = 0) {
        return this.emotions.processEvent(event, streak);
    }

    /**
     * Get current emotional state name.
     */
    get emotionalState() {
        return this.emotions.state;
    }

    // ─── MEMORY ──────────────────────────────────────────────

    /**
     * Append decision+outcome to episodic memory (ring buffer).
     */
    remember(entry) {
        if (!entry) return;
        this.memory.push({ ts: Date.now(), ...entry });
        if (this.memory.length > this.memoryMax) {
            this.memory = this.memory.slice(-this.memoryMax);
        }
    }

    /**
     * Get formatted memory context for LLM RAG prompt.
     */
    recallContext(limit = 10) {
        return this.memory.slice(-limit).map((m, i) => {
            const r = (m.reward != null) ? `r=${m.reward.toFixed(1)}` : '';
            return `${i + 1}. wk${m.week ?? '?'}: ${m.action || m.decision || '?'} → ${m.result || ''} ${r}`.trim();
        }).join('\n');
    }

    // ─── PERSISTENCE ─────────────────────────────────────────

    _restore() {
        try {
            if (typeof localStorage === 'undefined') return;
            const raw = localStorage.getItem(STORAGE_KEY);
            if (!raw) return;
            const parsed = JSON.parse(raw);
            if (parsed.qTable) this.qTable = parsed.qTable;
            if (parsed.visitCount) this.visitCount = parsed.visitCount;
            if (typeof parsed.totalUpdates === 'number') this.totalUpdates = parsed.totalUpdates;
            if (Array.isArray(parsed.memory)) this.memory = parsed.memory;
            if (Array.isArray(parsed.replayBuffer)) this.replayBuffer = parsed.replayBuffer;
            if (parsed.personality) this.personality = parsed.personality;
            if (parsed.emotions) this.emotions.restore(parsed.emotions);
        } catch { /* ignore */ }
    }

    save() {
        try {
            if (typeof localStorage === 'undefined') return;
            const payload = {
                qTable: this.qTable,
                visitCount: this.visitCount,
                totalUpdates: this.totalUpdates,
                memory: this.memory,
                replayBuffer: this.replayBuffer,
                personality: this.personality,
                emotions: this.emotions.serialize(),
                savedAt: Date.now()
            };
            localStorage.setItem(STORAGE_KEY, JSON.stringify(payload));
            this.lastSavedAt = Date.now();
        } catch { /* ignore */ }
    }

    reset() {
        this.qTable = {};
        this.visitCount = {};
        this.traces = {};
        this.totalUpdates = 0;
        this.memory = [];
        this.replayBuffer = [];
        this._lastGoals = null;
        this.emotions.forceState('CALM');
        this.goalRelevance.reset();
        try {
            if (typeof localStorage !== 'undefined') localStorage.removeItem(STORAGE_KEY);
        } catch { /* ignore */ }
    }

    // ─── Q-LEARNING CORE ─────────────────────────────────────

    getQ(stateKey, actionKey) {
        return this.qTable[stateKey]?.[actionKey] ?? 0;
    }

    /**
     * Pick action: epsilon-greedy + goal modulation + emotional modifiers.
     */
    pickAction(stateKey, availableActions, ctx = {}) {
        if (!Array.isArray(availableActions) || availableActions.length === 0) return null;

        // Always compute goals first — observe() needs fresh goals for feedback
        const goals = detectGoals(ctx, this.personality);
        this._lastGoals = goals;

        const emo = this.emotions.getModifiers();

        // Emotional tactic override (DESPERATE forces attacking)
        if (emo.tacticOverride) {
            const forced = availableActions.find(a => a.includes(emo.tacticOverride));
            if (forced) return forced;
        }

        // Effective epsilon with visit-based decay
        // Ref: Watkins (1989) — convergence requires ε → 0
        // Decays from BASE_EPSILON → 0.02 floor as state is visited more
        const directorMod = this._aiDirectorMod || 1.0;
        const visits = this.visitCount[stateKey] || 0;
        const decayedEpsilon = BASE_EPSILON / (1 + visits * 0.1); // ~0.15 → 0.03 @ 40 visits
        const effectiveEpsilon = Math.min(0.95, Math.max(0.02, decayedEpsilon * emo.epsilonMod * (2.0 - directorMod)));

        // TILT MECHANIC: high epsilonMod makes decisions erratic
        const lossStreak = ctx.lossStreak || 0;
        if (checkIsTilted(this.personality, lossStreak)) {
            if (systemRng() < 0.5) {
                return availableActions[Math.floor(systemRng() * availableActions.length)];
            }
        }

        // Cold start or exploration
        if (visits < 3 || systemRng() < effectiveEpsilon) {
            return availableActions[Math.floor(systemRng() * availableActions.length)];
        }

        let bestAction = availableActions[0];
        let bestScore = -Infinity;
        for (const action of availableActions) {
            const q = this.getQ(stateKey, action);
            const goalBoost = goals.reduce((sum, g) => sum + g.weight * this.goalRelevance.getRelevance(action, g.goal), 0);
            const score = q + goalBoost;
            if (score > bestScore) {
                bestScore = score;
                bestAction = action;
            }
        }
        return bestAction;
    }

    /**
     * Q(λ) with Replacing Eligibility Traces.
     *
     * Ref: Sutton & Barto, Ch.12 (2018); Singh & Sutton (1996).
     *
     * Instead of updating only Q[s][a], we:
     *   1. Compute TD error δ = r + γ·max(Q[s'][a']) - Q[s][a]
     *   2. Set trace e[s][a] = 1 (replacing, not accumulating)
     *   3. Update ALL traced state-action pairs: Q[s'][a'] += α·δ·e[s'][a']
     *   4. Decay all traces: e[s'][a'] *= γ·λ
     *
     * This propagates credit ~3-4 steps back (with λ=0.7),
     * making the bot learn 3-5x faster from delayed rewards.
     */
    observe(stateKey, actionKey, reward, nextStateKey, nextActions = []) {
        if (!this.qTable[stateKey]) this.qTable[stateKey] = {};
        const oldQ = this.qTable[stateKey][actionKey] || 0;

        // Fase D: Soft reward clipping — prevents Q-value explosion from
        // extreme rewards (title=+200, relegation=-60) while preserving signal.
        // Uses tanh scaling: maps [-Inf,+Inf] → [-REWARD_CLIP, +REWARD_CLIP]
        // Ref: Mnih et al (2015) — Atari DQN used hard clipping [-1,+1]
        // We use soft clip to preserve ordinal ranking of reward magnitudes.
        const clippedReward = REWARD_CLIP * Math.tanh(reward / REWARD_CLIP);

        let maxNextQ = 0;
        if (nextStateKey && nextActions.length > 0) {
            maxNextQ = Math.max(...nextActions.map(a => this.getQ(nextStateKey, a)));
        }

        // TD error with clipped reward
        const delta = clippedReward + GAMMA * maxNextQ - oldQ;

        // Replacing trace: set current (s,a) to 1.0
        // (replaces rather than accumulates — more stable for control tasks)
        if (!this.traces[stateKey]) this.traces[stateKey] = {};
        this.traces[stateKey][actionKey] = 1.0;

        // Propagate TD error to ALL traced state-action pairs
        const traceStates = Object.keys(this.traces);
        for (let i = traceStates.length - 1; i >= 0; i--) {
            const ts = traceStates[i];
            const actions = this.traces[ts];
            const actionKeys = Object.keys(actions);
            for (let j = actionKeys.length - 1; j >= 0; j--) {
                const ta = actionKeys[j];
                const trace = actions[ta];

                // Update Q-value weighted by trace
                // Alpha decay: stabilize mature Q-values over time
                // Ref: Even-Dar & Mansour (2003) — α=O(1/t) guarantees convergence
                const effectiveAlpha = Math.max(0.01, ALPHA / (1 + this.totalUpdates * 0.0001));
                if (!this.qTable[ts]) this.qTable[ts] = {};
                const newQ = (this.qTable[ts][ta] || 0) + effectiveAlpha * delta * trace;
                // Fase D: Q-value bounding — hard cap prevents runaway accumulation
                this.qTable[ts][ta] = Math.max(-Q_VALUE_BOUND, Math.min(Q_VALUE_BOUND, newQ));

                // Decay trace
                const decayed = trace * GAMMA * LAMBDA;
                if (decayed < TRACE_MIN) {
                    delete actions[ta];
                } else {
                    actions[ta] = decayed;
                }
            }
            // Clean empty state entries
            if (Object.keys(actions).length === 0) {
                delete this.traces[ts];
            }
        }

        // Bound trace table (emergency pruning if too large)
        this._pruneTraces();

        this.visitCount[stateKey] = (this.visitCount[stateKey] || 0) + 1;
        this.totalUpdates++;

        // Bound Q-table size — evict LRU-ish (lowest visit count)
        if (Object.keys(this.qTable).length > MAX_BUCKETS) {
            const sortedByVisits = Object.keys(this.visitCount)
                .sort((a, b) => (this.visitCount[a] || 0) - (this.visitCount[b] || 0));
            const toEvict = sortedByVisits[0];
            if (toEvict && toEvict !== stateKey) {
                delete this.qTable[toEvict];
                delete this.visitCount[toEvict];
                delete this.traces[toEvict]; // also evict traces
            }
        }

        // Save throttled (every 50 updates)
        if (this.totalUpdates % 50 === 0) this.save();

        // Fase 5: Feed goal relevance learner
        // The reward signal tells us if this action was good for current goals
        if (this.goalRelevance && this._lastGoals) {
            for (const g of this._lastGoals) {
                this.goalRelevance.update(g.goal, actionKey, reward);
            }
        }

        // Fase C: Record transition in experience replay buffer
        this.replayBuffer.push({ s: stateKey, a: actionKey, r: reward, s2: nextStateKey, na: nextActions });
        if (this.replayBuffer.length > MAX_REPLAY_BUFFER) {
            this.replayBuffer = this.replayBuffer.slice(-MAX_REPLAY_BUFFER);
        }
    }

    /**
     * Clear all eligibility traces. Call at episode boundaries
     * (e.g. season end) to prevent cross-episode credit leakage.
     */
    clearTraces() {
        this.traces = {};
    }

    /**
     * Replay high-impact experiences from buffer to reinforce learning.
     * Call at season boundaries AFTER clearTraces().
     *
     * Only replays transitions with |reward| > REPLAY_REWARD_THRESHOLD
     * (promotions, relegations, title wins, big transfers) at 50% learning
     * rate to prevent overfitting to replayed data.
     *
     * Ref: Lin (1992) — "Self-Improving Reactive Agents Based on RL"
     * Ref: Schaul et al (2015) — "Prioritized Experience Replay"
     *
     * @returns {number} count of replayed experiences
     */
    replayExperiences() {
        const impactful = this.replayBuffer.filter(e => Math.abs(e.r) > REPLAY_REWARD_THRESHOLD);
        if (impactful.length === 0) return 0;

        let replayed = 0;
        for (const exp of impactful) {
            if (!exp.s || !exp.a) continue;

            // Compute TD error with clipped + attenuated reward
            const clippedR = REWARD_CLIP * Math.tanh(exp.r / REWARD_CLIP);
            const replayReward = clippedR * 0.5;
            if (!this.qTable[exp.s]) this.qTable[exp.s] = {};
            const oldQ = this.qTable[exp.s][exp.a] || 0;

            let maxNextQ = 0;
            if (exp.s2 && Array.isArray(exp.na) && exp.na.length > 0) {
                maxNextQ = Math.max(...exp.na.map(a => this.getQ(exp.s2, a)));
            }

            const delta = replayReward + GAMMA * maxNextQ - oldQ;
            const effectiveAlpha = Math.max(0.01, ALPHA / (1 + this.totalUpdates * 0.0001));

            // Direct Q-update (no traces during replay — traces are cleared)
            const newQ = oldQ + effectiveAlpha * delta;
            this.qTable[exp.s][exp.a] = Math.max(-Q_VALUE_BOUND, Math.min(Q_VALUE_BOUND, newQ));
            replayed++;
        }

        // Save after replay
        if (replayed > 0) this.save();
        return replayed;
    }

    /**
     * Prune trace table if it exceeds MAX_TRACE_ENTRIES.
     * Removes entries with lowest trace values first.
     * @private
     */
    _pruneTraces() {
        let count = 0;
        for (const s of Object.keys(this.traces)) {
            count += Object.keys(this.traces[s]).length;
        }
        if (count <= MAX_TRACE_ENTRIES) return;

        // Collect all trace entries and sort by value (ascending)
        const entries = [];
        for (const s of Object.keys(this.traces)) {
            for (const a of Object.keys(this.traces[s])) {
                entries.push({ s, a, v: this.traces[s][a] });
            }
        }
        entries.sort((a, b) => a.v - b.v);

        // Remove lowest half
        const toRemove = Math.floor(entries.length / 2);
        for (let i = 0; i < toRemove; i++) {
            const { s, a } = entries[i];
            if (this.traces[s]) {
                delete this.traces[s][a];
                if (Object.keys(this.traces[s]).length === 0) delete this.traces[s];
            }
        }
    }

    // ─── AUDIT-FIX #F: YO-YO DETECTOR + META-LEARNING ────────

    /**
     * Record season-end division for yo-yo detection.
     * Call at season boundary (after promo/relegation resolves).
     *
     * @param {number} division — current division after promo/releg
     * @param {number} season — season number
     * @returns {{ isYoyo: boolean, yoyoCount: number, penalty: number }}
     */
    recordSeasonDivision(division, season) {
        this.divisionHistory.push({ div: division, season });
        // Keep last 10 seasons
        if (this.divisionHistory.length > 10) {
            this.divisionHistory = this.divisionHistory.slice(-10);
        }

        // Detect yo-yo: division changed direction 3+ times in last 6 seasons
        const recent = this.divisionHistory.slice(-6);
        let directionChanges = 0;
        for (let i = 2; i < recent.length; i++) {
            const prev = recent[i-1].div - recent[i-2].div;
            const curr = recent[i].div - recent[i-1].div;
            if (prev !== 0 && curr !== 0 && Math.sign(prev) !== Math.sign(curr)) {
                directionChanges++;
            }
        }

        const isYoyo = directionChanges >= 2;
        if (isYoyo) this._yoyoCount++;

        // Apply escalating penalty: each yo-yo cycle gets punished harder
        // This teaches the agent that stability > oscillation
        const penalty = isYoyo ? -15 * Math.min(5, this._yoyoCount) : 0;

        return { isYoyo, yoyoCount: this._yoyoCount, penalty };
    }

    // ─── ANALYTICS ───────────────────────────────────────────

    topActions(limit = 10) {
        const tally = {};
        for (const stateKey of Object.keys(this.qTable)) {
            for (const actionKey of Object.keys(this.qTable[stateKey])) {
                tally[actionKey] = (tally[actionKey] || 0) + this.qTable[stateKey][actionKey];
            }
        }
        return Object.entries(tally)
            .sort((a, b) => b[1] - a[1])
            .slice(0, limit)
            .map(([action, totalQ]) => ({ action, totalQ }));
    }

    summary() {
        // Count active trace entries
        let traceEntries = 0;
        for (const s of Object.keys(this.traces)) {
            traceEntries += Object.keys(this.traces[s]).length;
        }
        return {
            states: Object.keys(this.qTable).length,
            totalUpdates: this.totalUpdates,
            activeTraces: traceEntries,
            replayBuffer: this.replayBuffer.length,
            replayImpactful: this.replayBuffer.filter(e => Math.abs(e.r) > REPLAY_REWARD_THRESHOLD).length,
            lambda: LAMBDA,
            yoyoCount: this._yoyoCount,
            divisionHistory: this.divisionHistory,
            topActions: this.topActions(5),
            personality: {
                id: this.personality?.id,
                label: this.personality?.label,
                ocean: this.personality?.ocean,
                traits: this.personality?.traits
            },
            emotional: this.emotions.summary()
        };
    }
}

/**
 * BrainPersistence — MARL Fase 6.5
 *
 * Gerencia persistência de múltiplos AdaptiveBrain em localStorage.
 * Resolve o problema de 60+ brains estourando o limite de ~5MB.
 *
 * Estratégias:
 *   1. Lazy save: só salva brains que foram modificados
 *   2. Compactação: mantém apenas top-N states por brain
 *   3. Batched: serializa tudo de uma vez (evita 60 keys separadas)
 *   4. Fallback: se exceder limite, poda os brains com menos updates
 */

const STORAGE_KEY_PREFIX = 'elifoot_npc_brains';
const MAX_STATES_PER_BRAIN = 30;   // compact Q-tables
const MAX_MEMORIES_PER_BRAIN = 10; // compact episodic memory
const ESTIMATED_LIMIT_BYTES = 4_500_000; // 90% of 5MB localStorage

// ─── SAVE ────────────────────────────────────────────────────

/**
 * Salva todos os brains de times NPC em localStorage.
 * Compacta cada brain para manter tamanho controlado.
 *
 * @param {Array<Object>} teams — engine.teams
 * @returns {{ saved: number, bytes: number, pruned: number }}
 */
export function saveAllBrains(teams) {
    if (typeof localStorage === 'undefined') return { saved: 0, bytes: 0, pruned: 0 };

    const brainData = {};
    let saved = 0;

    for (const team of teams) {
        if (!team.brain || team.brain.totalUpdates === 0) continue;

        brainData[team.id] = compactBrain(team.brain);
        saved++;
    }

    const json = JSON.stringify(brainData);
    let pruned = 0;

    // Check size — if too big, prune lowest-update brains
    if (json.length > ESTIMATED_LIMIT_BYTES) {
        const entries = Object.entries(brainData)
            .sort((a, b) => (a[1].u || 0) - (b[1].u || 0)); // sort by updates asc

        // Remove bottom 30%
        const toRemove = Math.ceil(entries.length * 0.3);
        for (let i = 0; i < toRemove; i++) {
            delete brainData[entries[i][0]];
            pruned++;
        }
    }

    try {
        localStorage.setItem(STORAGE_KEY_PREFIX, JSON.stringify(brainData));
    } catch (e) {
        // Storage full — aggressive prune
        try {
            const entries = Object.entries(brainData)
                .sort((a, b) => (a[1].u || 0) - (b[1].u || 0));
            // Keep only top 20
            const kept = Object.fromEntries(entries.slice(-20));
            localStorage.setItem(STORAGE_KEY_PREFIX, JSON.stringify(kept));
            pruned = entries.length - 20;
        } catch { /* give up */ }
    }

    return { saved, bytes: json.length, pruned };
}

// ─── RESTORE ─────────────────────────────────────────────────

/**
 * Restaura brains de todos os times NPC do localStorage.
 *
 * @param {Array<Object>} teams — engine.teams (mutates team.brain in-place)
 * @returns {number} count of restored brains
 */
export function restoreAllBrains(teams) {
    if (typeof localStorage === 'undefined') return 0;

    let raw;
    try {
        raw = localStorage.getItem(STORAGE_KEY_PREFIX);
    } catch { return 0; }
    if (!raw) return 0;

    let brainData;
    try {
        brainData = JSON.parse(raw);
    } catch { return 0; }

    let restored = 0;
    for (const team of teams) {
        if (!team.brain || !brainData[team.id]) continue;
        expandBrain(team.brain, brainData[team.id]);
        restored++;
    }

    return restored;
}

// ─── COMPACTION ──────────────────────────────────────────────

/**
 * Compacta um brain para persistência.
 * Mantém apenas top-N states por visitas, trunca memória,
 * serializa emotions.
 *
 * @param {Object} brain — AdaptiveBrain instance
 * @returns {Object} compact representation
 */
function compactBrain(brain) {
    // Top-N states by visit count
    const stateKeys = Object.keys(brain.qTable || {});
    const topStates = stateKeys
        .sort((a, b) => (brain.visitCount[b] || 0) - (brain.visitCount[a] || 0))
        .slice(0, MAX_STATES_PER_BRAIN);

    const q = {};
    const v = {};
    for (const key of topStates) {
        q[key] = brain.qTable[key];
        v[key] = brain.visitCount[key] || 0;
    }

    return {
        q,        // compact Q-table
        v,        // visit counts
        u: brain.totalUpdates,
        m: (brain.memory || []).slice(-MAX_MEMORIES_PER_BRAIN),
        p: brain.personality,
        e: brain.emotions?.serialize() || null
    };
}

/**
 * Expande dados compactados de volta num brain existente.
 *
 * @param {Object} brain — AdaptiveBrain instance (mutated)
 * @param {Object} data — compact representation from compactBrain
 */
function expandBrain(brain, data) {
    if (data.q) brain.qTable = data.q;
    if (data.v) brain.visitCount = data.v;
    if (typeof data.u === 'number') brain.totalUpdates = data.u;
    if (Array.isArray(data.m)) brain.memory = data.m;
    if (data.p) brain.personality = data.p;
    if (data.e && brain.emotions) brain.emotions.restore(data.e);
}

/**
 * CognitiveBiases — MARL Fase 5
 *
 * Vieses cognitivos humanos aplicados ao mercado de transferências.
 * Cada função recebe dados objetivos + um fator de personalidade (0-1)
 * e retorna um valor distorcido que um humano real perceberia.
 *
 * Baseado em:
 *   - Kahneman & Tversky (1979) — Prospect Theory, Anchoring
 *   - Thaler (1980) — Endowment Effect
 *   - Arkes & Blumer (1985) — Sunk Cost Fallacy
 *   - Banerjee (1992) — Herd Behavior
 *   - Tversky & Kahneman (1973) — Availability/Recency Bias
 */




// ─── SUNK COST FALLACY ───────────────────────────────────────

/**
 * Bot resiste a vender abaixo do preço que pagou, mesmo que o jogador
 * tenha depreciado. "Eu paguei caro, não vou entregar por menos."
 *
 * Bots com OCEAN.A alto (leais) e OCEAN.N alto (neuróticos) são
 * mais suscetíveis ao sunk cost.
 *
 * @param {number} purchasePrice — quanto o bot pagou pelo jogador (0 se da base)
 * @param {number} currentValue — valor de mercado atual
 * @param {number} sunkCostBias — 0-1 (derivado de (OCEAN.A + OCEAN.N) / 2)
 * @returns {number} preço mínimo aceitável de venda
 */
export function applySunkCost(purchasePrice, currentValue, sunkCostBias = 0.5) {
    if (purchasePrice <= 0) return currentValue; // jogador da base = sem sunk cost
    const bias = Math.min(1, Math.max(0, sunkCostBias));
    // Preço mínimo = interpolação entre valor atual e preço de compra
    // bias=0 → aceita o mercado (racional)
    // bias=1 → exige o preço original de volta
    const floor = currentValue * (1 - bias) + purchasePrice * bias;
    // Nunca abaixo de 70% do valor atual (sanidade)
    return Math.round(Math.max(currentValue * 0.7, floor));
}

// ─── ENDOWMENT EFFECT ────────────────────────────────────────

/**
 * "Meus jogadores valem mais." Humanos inflam o valor de coisas que possuem.
 *
 * Efeito universal (~1.3-1.5x), com leve modulação por OCEAN.A (lealdade).
 *
 * @param {number} value — valor de mercado
 * @param {boolean} isOwn — jogador pertence ao elenco do bot?
 * @param {number} loyaltyFactor — 0-1 (OCEAN.A do bot, default 0.5)
 * @returns {number} valor percebido
 */
export function applyEndowment(value, isOwn, loyaltyFactor = 0.5) {
    if (!isOwn) return value;
    // Base multiplier: 1.3x para bots racionais, até 1.6x para leais
    const multiplier = 1.3 + loyaltyFactor * 0.3;
    return Math.round(value * multiplier);
}

// ─── HERD BEHAVIOR ───────────────────────────────────────────

/**
 * Se muitos times compraram na posição X recentemente, o bot sente
 * urgência para fazer o mesmo. "Todo mundo tá contratando atacante,
 * preciso de um também!"
 *
 * Bots com OCEAN.N alto (neuróticos) e OCEAN.O baixo (conservadores)
 * são mais suscetíveis ao efeito manada.
 *
 * @param {Array<{position: string}>} recentLeagueTransfers — compras recentes na liga
 * @param {string} position — posição que o bot está avaliando
 * @param {number} herdSusceptibility — 0-1 (derivado de OCEAN.N, ou (N + (1-O)) / 2)
 * @returns {number} urgencyMultiplier 1.0-2.0
 */
export function applyHerdBehavior(recentLeagueTransfers, position, herdSusceptibility = 0.3) {
    if (!Array.isArray(recentLeagueTransfers) || recentLeagueTransfers.length === 0) {
        return 1.0;
    }
    const transfersInPosition = recentLeagueTransfers.filter(t => t.position === position).length;
    const ratio = transfersInPosition / Math.max(1, recentLeagueTransfers.length);
    // 0% da liga comprando na posição → 1.0x
    // 40%+ da liga comprando na posição → até 2.0x (se herdSusceptibility=1)
    const herdPressure = Math.min(1, ratio / 0.4);
    const urgency = 1.0 + herdPressure * herdSusceptibility;
    return Math.min(2.0, urgency);
}

// ─── SCARCITY PANIC ──────────────────────────────────────────

/**
 * Últimas semanas da janela de transferências: preços inflam
 * porque o bot entra em pânico. "Se não comprar agora, fico sem!"
 *
 * @param {number} windowWeeksLeft — semanas restantes na janela
 * @param {number} totalWindowWeeks — duração total da janela (ex: 8 semanas)
 * @param {number} panicSusceptibility — 0-1 (derivado de OCEAN.N)
 * @returns {number} priceMultiplier 1.0-1.8
 */
export function applyScarcityPanic(windowWeeksLeft, totalWindowWeeks, panicSusceptibility = 0.5) {
    if (totalWindowWeeks <= 0 || windowWeeksLeft >= totalWindowWeeks) return 1.0;
    // Fração de tempo restante (0 = acabou, 1 = início)
    const timeLeft = Math.max(0, windowWeeksLeft / totalWindowWeeks);
    // Urgência = inverso do tempo restante, exponencial
    // Últimas 25% da janela = efeito forte
    const rawPanic = Math.pow(1 - timeLeft, 2);
    // Modulado pela susceptibilidade do bot
    const panic = rawPanic * panicSusceptibility * 0.8;
    return Math.min(1.8, 1.0 + panic);
}

// ─── RECENCY BIAS ────────────────────────────────────────────

/**
 * Último jogo do jogador tem peso desproporcional na avaliação.
 * Hat-trick ontem = "vale ouro!" Fraco ontem = "não serve."
 *
 * Bots com OCEAN.O baixo (conservadores/pouco abertos) são mais
 * suscetíveis ao recency bias.
 *
 * @param {{ goals: number, assists: number, rating: number }} lastMatchStats
 * @param {number} recencyBias — 0-1 (derivado de 1 - OCEAN.O)
 * @returns {number} valueModifier — multiplicador sobre o valor (0.7 a 1.5)
 */
export function applyRecencyBias(lastMatchStats, recencyBias = 0.3) {
    if (!lastMatchStats) return 1.0;
    const { goals = 0, assists = 0, rating = 6.0 } = lastMatchStats;

    // Performance score: -1 (péssimo) a +1 (excepcional)
    let performanceScore = 0;
    performanceScore += Math.min(3, goals) * 0.25;    // até 0.75 de gols
    performanceScore += Math.min(2, assists) * 0.15;   // até 0.30 de assists
    performanceScore += (rating - 6.0) * 0.1;          // rating 6 = neutro

    // Clamp entre -1 e +1
    performanceScore = Math.max(-1, Math.min(1, performanceScore));

    // Modulado pelo bias: 0 = ignora último jogo, 1 = último jogo é tudo
    const modifier = 1.0 + performanceScore * recencyBias * 0.5;
    return Math.max(0.7, Math.min(1.5, modifier));
}

// ─── STATUS QUO BIAS ─────────────────────────────────────────

/**
 * Resistência a mudar o elenco. "Time que está ganhando não se mexe."
 * Aparece quando o bot está em boa fase — resiste a comprar/vender.
 *
 * @param {number} recentWinRate — taxa de vitória nas últimas 10 partidas (0-1)
 * @param {number} conscientiousness — OCEAN.C do bot (0-1)
 * @returns {number} changePenalty — 0 (sem resistência) a 1 (máxima resistência)
 */
export function applyStatusQuoBias(recentWinRate, conscientiousness = 0.5) {
    if (recentWinRate < 0.4) return 0; // perdendo = quer mudança
    // Ganhando muito + disciplinado = "não mexe no que tá funcionando"
    const winFactor = Math.min(1, (recentWinRate - 0.4) / 0.4); // 0 at 40%, 1 at 80%
    return winFactor * conscientiousness * 0.7;
}

// ─── COMPOSITE: Apply all biases to a transfer decision ──────

/**
 * Aplica todos os vieses relevantes de uma vez para decisão de compra.
 * Retorna o valor percebido e a urgência ajustada.
 *
 * @param {Object} params
 * @param {number} params.realValue — valor de mercado do alvo
 * @param {Object} params.personality — OCEAN personality object
 * @param {Object} [params.context] — { recentLeagueTransfers, windowWeeksLeft, totalWindowWeeks, lastMatchStats, recentWinRate }
 * @returns {{ perceivedValue: number, urgencyMod: number, biasesApplied: string[] }}
 */
export function applyBuyBiases({ realValue, personality, context = {} }) {
    const ocean = personality?.ocean || { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 };
    const biasesApplied = [];
    let perceivedValue = realValue;
    let urgencyMod = 1.0;

    // Scarcity Panic
    if (context.windowWeeksLeft != null && context.totalWindowWeeks) {
        const panic = applyScarcityPanic(context.windowWeeksLeft, context.totalWindowWeeks, ocean.N);
        if (panic > 1.05) {
            perceivedValue = Math.round(perceivedValue * panic);
            biasesApplied.push(`SCARCITY(×${panic.toFixed(2)})`);
        }
    }

    // Herd Behavior
    if (context.recentLeagueTransfers && context.targetPosition) {
        const herdMod = applyHerdBehavior(context.recentLeagueTransfers, context.targetPosition, (ocean.N + (1 - ocean.O)) / 2);
        if (herdMod > 1.05) {
            urgencyMod *= herdMod;
            biasesApplied.push(`HERD(×${herdMod.toFixed(2)})`);
        }
    }

    // Recency Bias on target
    if (context.lastMatchStats) {
        const recMod = applyRecencyBias(context.lastMatchStats, 1 - ocean.O);
        if (Math.abs(recMod - 1.0) > 0.05) {
            perceivedValue = Math.round(perceivedValue * recMod);
            biasesApplied.push(`RECENCY(×${recMod.toFixed(2)})`);
        }
    }

    // Status Quo (resistance to buy)
    if (context.recentWinRate != null) {
        const sqPenalty = applyStatusQuoBias(context.recentWinRate, ocean.C);
        if (sqPenalty > 0.1) {
            urgencyMod *= (1 - sqPenalty);
            biasesApplied.push(`STATUS_QUO(−${(sqPenalty * 100).toFixed(0)}%)`);
        }
    }

    return { perceivedValue, urgencyMod, biasesApplied };
}

/**
 * Aplica todos os vieses relevantes para decisão de venda.
 *
 * @param {Object} params
 * @param {number} params.offerAmount — quanto estão oferecendo
 * @param {number} params.playerValue — valor de mercado do jogador
 * @param {number} params.purchasePrice — quanto o bot pagou (0 se da base)
 * @param {Object} params.personality — OCEAN personality object
 * @param {Object} [params.context] — { lastMatchStats }
 * @returns {{ minAcceptable: number, perceivedValue: number, biasesApplied: string[] }}
 */
export function applySellBiases({ offerAmount, playerValue, purchasePrice = 0, personality, context = {} }) {
    const ocean = personality?.ocean || { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 };
    const biasesApplied = [];

    // Endowment Effect — "meu jogador vale mais"
    const endowedValue = applyEndowment(playerValue, true, ocean.A);
    biasesApplied.push(`ENDOWMENT(${playerValue}→${endowedValue})`);

    // Sunk Cost — "paguei caro, não entrego barato"
    const sunkCostBias = (ocean.A + ocean.N) / 2;
    const minAcceptable = applySunkCost(purchasePrice, endowedValue, sunkCostBias);
    if (purchasePrice > 0) {
        biasesApplied.push(`SUNK_COST(min=${minAcceptable})`);
    }

    // Recency Bias — "fez gol ontem, vale ouro"
    let perceivedValue = endowedValue;
    if (context.lastMatchStats) {
        const recMod = applyRecencyBias(context.lastMatchStats, 1 - ocean.O);
        perceivedValue = Math.round(perceivedValue * recMod);
        if (Math.abs(recMod - 1.0) > 0.05) {
            biasesApplied.push(`RECENCY(×${recMod.toFixed(2)})`);
        }
    }

    return { minAcceptable, perceivedValue, biasesApplied };
}

/**
 * LearnedEmotionalModifiers — SARSA(λ) for Emotional Response Tuning
 *
 * Ref: Rummery & Niranjan (1994) — "On-Line Q-Learning Using Connectionist
 *      Systems" (original SARSA)
 *      Sutton & Barto (2018) — Ch.12 Eligibility Traces
 *
 * The EmotionalEngine FSM stays intact (it models real emotional states well).
 * This module REPLACES the hardcoded STATES modifier table with learned values.
 *
 * Instead of:
 *   ANXIOUS: { epsilonMod: 1.5, lossMod: 2.0, riskMod: 0.30 }  ← fixed
 *
 * We learn:
 *   ANXIOUS + bottom + poor + late: { epsilonMod: ?, lossMod: ?, riskMod: ? }
 *     → SARSA(λ) discovers optimal modifiers per context
 *
 * WHY SARSA NOT Q-LEARNING?
 * SARSA is on-policy: it learns the value of the policy BEING FOLLOWED,
 * including "bad" emotional actions. For emotion modeling this is crucial —
 * we DON'T want the agent to learn a cold "optimal" policy that ignores
 * the cost of emotional decisions. SARSA naturally learns safe/conservative
 * responses in risky situations.
 *
 * State: (emotionalState, positionTier, balanceTier, seasonPhase)
 * Actions: modifier presets (LOW, MEDIUM, HIGH for each modifier dimension)
 * Reward: same reward signal from AdaptiveBrain.observe()
 */

import { rng as systemRng } from '../../engine/rng.js';

const STORAGE_KEY = 'elifoot_emotion_sarsa';

// SARSA(λ) hyperparameters
const ALPHA = 0.08;      // learning rate (slightly lower than Q-learning for stability)
const GAMMA = 0.85;       // discount factor
const LAMBDA = 0.6;       // trace decay (shorter than Q(λ) — emotions are more local)
const EPSILON = 0.12;     // base exploration rate
const MIN_EPSILON = 0.03; // floor after decay
const TRACE_MIN = 0.01;
const MAX_STATES = 200;   // bound state table
const REWARD_CLIP = 20;   // soft-clip for SARSA (tighter than Q-Learning)
const Q_VALUE_BOUND = 30; // hard cap on SARSA Q-values

// ─── MODIFIER PRESETS ───────────────────────────────────────
// Instead of learning continuous values (needs neural net),
// we discretize into 3-5 presets per emotional response dimension.
// SARSA picks the best preset combo for each (emotion, context).

const RESPONSE_PRESETS = {
    // How much to explore (epsilonMod)
    EXPLORE_LOW:    { epsilonMod: 0.3 },   // stick with what works
    EXPLORE_NORMAL: { epsilonMod: 1.0 },   // baseline
    EXPLORE_HIGH:   { epsilonMod: 2.0 },   // try new things
    EXPLORE_WILD:   { epsilonMod: 3.5 },   // panic exploration

    // How much losses hurt (lossMod)
    LOSS_NUMB:      { lossMod: 0.5 },      // desensitized
    LOSS_NORMAL:    { lossMod: 1.0 },      // baseline
    LOSS_PAINFUL:   { lossMod: 2.0 },      // losses hurt extra
    LOSS_CRUSHING:  { lossMod: 3.0 },      // devastating

    // Risk appetite for spending (riskMod)
    RISK_CAUTIOUS:  { riskMod: 0.20 },     // very conservative
    RISK_NORMAL:    { riskMod: 0.40 },     // baseline
    RISK_AGGRESSIVE:{ riskMod: 0.65 },     // willing to spend
    RISK_YOLO:      { riskMod: 0.90 },     // all in
};

// Each "emotional action" is a combo of 3 dimensions
// Total: 4 × 4 × 4 = 64 possible response combos
// But we'll use representative presets to keep it manageable
const EMOTIONAL_ACTIONS = [
    // Conservative responses
    { id: 'STOIC',       epsilonMod: 0.3, lossMod: 0.5, riskMod: 0.20, tacticOverride: null },
    { id: 'CAUTIOUS',    epsilonMod: 0.5, lossMod: 1.0, riskMod: 0.25, tacticOverride: null },
    { id: 'COMPOSED',    epsilonMod: 0.8, lossMod: 0.8, riskMod: 0.35, tacticOverride: null },

    // Balanced responses
    { id: 'NEUTRAL',     epsilonMod: 1.0, lossMod: 1.0, riskMod: 0.40, tacticOverride: null },
    { id: 'ADAPTIVE',    epsilonMod: 1.2, lossMod: 1.2, riskMod: 0.45, tacticOverride: null },

    // Aggressive responses
    { id: 'BOLD',        epsilonMod: 0.4, lossMod: 0.6, riskMod: 0.60, tacticOverride: null },
    { id: 'AGGRESSIVE',  epsilonMod: 1.5, lossMod: 1.5, riskMod: 0.55, tacticOverride: 'offensive' },
    { id: 'RECKLESS',    epsilonMod: 2.5, lossMod: 2.0, riskMod: 0.70, tacticOverride: 'offensive' },

    // Defensive responses
    { id: 'DEFENSIVE',   epsilonMod: 0.6, lossMod: 1.5, riskMod: 0.20, tacticOverride: 'defensive' },
    { id: 'BUNKER',      epsilonMod: 0.3, lossMod: 2.0, riskMod: 0.15, tacticOverride: 'defensive' },

    // Panic responses
    { id: 'PANICKED',    epsilonMod: 3.0, lossMod: 2.5, riskMod: 0.80, tacticOverride: null },
    { id: 'DESPERATE',   epsilonMod: 4.0, lossMod: 3.0, riskMod: 0.90, tacticOverride: 'offensive' },
];

const ACTION_IDS = EMOTIONAL_ACTIONS.map(a => a.id);
const ACTION_MAP = Object.fromEntries(EMOTIONAL_ACTIONS.map(a => [a.id, a]));

// ─── SARSA(λ) CLASS ─────────────────────────────────────────

export class LearnedEmotionalModifiers {
    constructor() {
        this.qTable = {};      // state → action → Q-value
        this.traces = {};      // eligibility traces
        this.visitCount = {};
        this.totalUpdates = 0;

        // SARSA needs to remember the last (state, action, reward) tuple
        this._lastState = null;
        this._lastAction = null;
        this._lastReward = 0;

        this._restore();
    }

    /**
     * Encode emotional context into a state key.
     * Uses: emotional state + position tier + balance tier + season phase
     *
     * @param {string} emotionState — current FSM state (CALM, ANXIOUS, etc.)
     * @param {Object} ctx — game context from _buildStateCtx()
     * @returns {string} e.g. "ANXIOUS|bottom|poor|late"
     */
    encodeState(emotionState, ctx = {}) {
        const pos = ctx.position || 10;
        const totalTeams = ctx.totalTeams || 20;
        const posTier = pos <= Math.floor(totalTeams * 0.25) ? 'top'
            : pos <= Math.floor(totalTeams * 0.6) ? 'mid'
            : pos <= Math.floor(totalTeams * 0.8) ? 'bottom' : 'rele';

        const bal = ctx.balance || 0;
        const balTier = bal > 5_000_000 ? 'rich'
            : bal > 1_000_000 ? 'ok'
            : bal > 0 ? 'poor' : 'broke';

        const week = ctx.week || 0;
        const phase = week < 13 ? 'early' : (week < 26 ? 'mid' : 'late');

        return `${emotionState}|${posTier}|${balTier}|${phase}`;
    }

    /**
     * Pick an emotional response action using ε-greedy from SARSA Q-table.
     *
     * @param {string} stateKey — from encodeState()
     * @returns {{ actionId: string, modifiers: Object }}
     */
    pickResponse(stateKey) {
        // Visit-based ε-decay: explore less as states become familiar
        const visits = this.visitCount[stateKey] || 0;
        const effectiveEpsilon = Math.max(MIN_EPSILON, EPSILON / (1 + visits * 0.1));

        if (systemRng() < effectiveEpsilon || !this.qTable[stateKey]) {
            const idx = Math.floor(systemRng() * EMOTIONAL_ACTIONS.length);
            const action = EMOTIONAL_ACTIONS[idx];
            return { actionId: action.id, modifiers: { ...action } };
        }

        // Exploit: pick action with highest Q-value
        const stateQ = this.qTable[stateKey];
        let bestId = ACTION_IDS[0];
        let bestQ = -Infinity;

        for (const id of ACTION_IDS) {
            const q = stateQ[id] || 0;
            if (q > bestQ) {
                bestQ = q;
                bestId = id;
            }
        }

        const action = ACTION_MAP[bestId];
        return { actionId: bestId, modifiers: { ...action } };
    }

    /**
     * SARSA(λ) update with replacing eligibility traces.
     *
     * SARSA update rule:
     *   Q(s,a) += α · [r + γ · Q(s',a') - Q(s,a)] · e(s,a)
     *
     * Where a' is the ACTUAL next action (not max — this is on-policy).
     *
     * Call pattern: observe(s', a', r) where r is the reward received
     * for the PREVIOUS action that led to s'.
     *
     * @param {string} stateKey — current state s'
     * @param {string} actionId — current action a' (just chosen)
     * @param {number} reward — reward received from previous (s,a) transition
     */
    observe(stateKey, actionId, reward) {
        if (!this._lastState || !this._lastAction) {
            // First step — just record, no update yet
            this._lastState = stateKey;
            this._lastAction = actionId;
            this._lastReward = reward;
            return;
        }

        // SARSA TD error uses the reward from the PREVIOUS step
        // r = reward received after taking _lastAction in _lastState
        const r = this._lastReward;

        // SARSA: use Q(s', a') where a' is the ACTUALLY chosen action (on-policy)
        if (!this.qTable[this._lastState]) this.qTable[this._lastState] = {};
        const oldQ = this.qTable[this._lastState][this._lastAction] || 0;

        if (!this.qTable[stateKey]) this.qTable[stateKey] = {};
        const nextQ = this.qTable[stateKey][actionId] || 0;

        // Soft-clip reward to prevent extreme emotional Q-value drift
        const clippedR = REWARD_CLIP * Math.tanh(r / REWARD_CLIP);

        // TD error (SARSA — uses actual next action, not max)
        const delta = clippedR + GAMMA * nextQ - oldQ;

        // Replacing trace for last (state, action)
        if (!this.traces[this._lastState]) this.traces[this._lastState] = {};
        this.traces[this._lastState][this._lastAction] = 1.0;

        // Propagate TD error to all traced state-action pairs
        for (const s of Object.keys(this.traces)) {
            const actions = this.traces[s];
            for (const a of Object.keys(actions)) {
                const trace = actions[a];

                if (!this.qTable[s]) this.qTable[s] = {};
                // Alpha decay: stabilize mature emotional Q-values
                const effectiveAlpha = Math.max(0.01, ALPHA / (1 + this.totalUpdates * 0.0001));
                const newQ = (this.qTable[s][a] || 0) + effectiveAlpha * delta * trace;
                this.qTable[s][a] = Math.max(-Q_VALUE_BOUND, Math.min(Q_VALUE_BOUND, newQ));

                // Decay trace
                const decayed = trace * GAMMA * LAMBDA;
                if (decayed < TRACE_MIN) {
                    delete actions[a];
                } else {
                    actions[a] = decayed;
                }
            }
            if (Object.keys(actions).length === 0) {
                delete this.traces[s];
            }
        }

        this.visitCount[stateKey] = (this.visitCount[stateKey] || 0) + 1;
        this.totalUpdates++;

        // Bound Q-table size
        if (Object.keys(this.qTable).length > MAX_STATES) {
            const sorted = Object.keys(this.visitCount)
                .sort((a, b) => (this.visitCount[a] || 0) - (this.visitCount[b] || 0));
            const evict = sorted[0];
            if (evict && evict !== stateKey) {
                delete this.qTable[evict];
                delete this.visitCount[evict];
                delete this.traces[evict];
            }
        }

        // Update last state/action/reward for next SARSA step
        this._lastState = stateKey;
        this._lastAction = actionId;
        this._lastReward = reward;

        // Save throttled
        if (this.totalUpdates % 30 === 0) this.save();
    }

    /**
     * Clear traces at episode boundary (season end).
     */
    clearTraces() {
        this.traces = {};
        this._lastState = null;
        this._lastAction = null;
        this._lastReward = 0;
    }

    // ─── PERSISTENCE ────────────────────────────────────────

    _restore() {
        try {
            if (typeof localStorage === 'undefined') return;
            const raw = localStorage.getItem(STORAGE_KEY);
            if (!raw) return;
            const parsed = JSON.parse(raw);
            if (parsed.qTable) this.qTable = parsed.qTable;
            if (parsed.visitCount) this.visitCount = parsed.visitCount;
            if (typeof parsed.totalUpdates === 'number') this.totalUpdates = parsed.totalUpdates;
        } catch { /* ignore */ }
    }

    save() {
        try {
            if (typeof localStorage === 'undefined') return;
            localStorage.setItem(STORAGE_KEY, JSON.stringify({
                qTable: this.qTable,
                visitCount: this.visitCount,
                totalUpdates: this.totalUpdates,
                savedAt: Date.now()
            }));
        } catch { /* ignore */ }
    }

    reset() {
        this.qTable = {};
        this.traces = {};
        this.visitCount = {};
        this.totalUpdates = 0;
        this._lastState = null;
        this._lastAction = null;
        this._lastReward = 0;
        try {
            if (typeof localStorage !== 'undefined') localStorage.removeItem(STORAGE_KEY);
        } catch { /* ignore */ }
    }

    // ─── ANALYTICS ──────────────────────────────────────────

    /**
     * Get the preferred response for an emotional state across all contexts.
     */
    preferredResponse(emotionState) {
        const matches = {};
        for (const stateKey of Object.keys(this.qTable)) {
            if (!stateKey.startsWith(emotionState + '|')) continue;
            const actions = this.qTable[stateKey];
            for (const [actionId, q] of Object.entries(actions)) {
                matches[actionId] = (matches[actionId] || 0) + q;
            }
        }
        const sorted = Object.entries(matches).sort((a, b) => b[1] - a[1]);
        return sorted.length > 0 ? sorted[0][0] : 'NEUTRAL';
    }

    summary() {
        let traceCount = 0;
        for (const s of Object.keys(this.traces)) {
            traceCount += Object.keys(this.traces[s]).length;
        }
        return {
            states: Object.keys(this.qTable).length,
            totalUpdates: this.totalUpdates,
            activeTraces: traceCount,
            preferredByEmotion: {
                CALM: this.preferredResponse('CALM'),
                CONFIDENT: this.preferredResponse('CONFIDENT'),
                ANXIOUS: this.preferredResponse('ANXIOUS'),
                TILTED: this.preferredResponse('TILTED'),
                DESPERATE: this.preferredResponse('DESPERATE')
            }
        };
    }
}

/**
 * SmartMarketEngine — ML-Driven Transfer Decisions
 *
 * This module does NOT make decisions itself. Instead:
 *   1. Analyzes squad + player + context → encodes a compact market STATE
 *   2. Passes state to AdaptiveBrain.pickAction() → Q-Learning decides
 *   3. Brain observes reward after transfer outcome → learns over time
 *
 * The state encoding captures 8 features that the brain learns to associate
 * with good/bad transfer outcomes:
 *   - Squad need at position (gap detection)
 *   - Quality delta (upgrade potential)
 *   - Age trajectory (peak/decline/potential)
 *   - Affordability ratio
 *   - Squad size pressure
 *   - Emotional state modifier
 *   - Personality risk appetite
 *   - Window urgency
 *
 * Over multiple seasons, the Q-table learns patterns like:
 *   "When squad is weak at DEF and player is a big upgrade and affordable → BUY"
 *   "When desperate and overstocked → SELL even cheap"
 *
 * Works for both AutoPlay bot AND NPC managers.
 */

import { applyBuyBiases, applySellBiases } from './CognitiveBiases.js';

// ─── EMOTIONAL STATE SCALE (used by composite encoders) ──
const EMO_SCALE = {
    CALM: 0, CONFIDENT: 1, EUPHORIC: 2,
    ANXIOUS: 2, TILTED: 3, DESPERATE: 4
};

// ─── POSITION IDEAL DEPTH ────────────────────────────────────
const IDEAL_DEPTH = { GOL: 2, DEF: 6, MEI: 6, ATA: 4 };

// ─── SQUAD ANALYSIS ──────────────────────────────────────────

/**
 * Analyze squad and return per-position metrics.
 */
export function analyzeSquad(squad = []) {
    const result = {};
    for (const pos of ['GOL', 'DEF', 'MEI', 'ATA']) {
        const players = squad.filter(p => p.position === pos && !p._retired);
        const ovrs = players.map(p => p.ovr || 50);
        const avg = ovrs.length > 0 ? ovrs.reduce((a, b) => a + b, 0) / ovrs.length : 0;
        const max = ovrs.length > 0 ? Math.max(...ovrs) : 0;
        const ideal = IDEAL_DEPTH[pos] || 4;
        result[pos] = {
            depth: players.length,
            idealDepth: ideal,
            gap: ideal - players.length,
            avgOvr: avg,
            maxOvr: max,
            avgAge: players.length > 0
                ? players.reduce((s, p) => s + (p.age || 25), 0) / players.length : 25,
        };
    }
    return result;
}

// ═══════════════════════════════════════════════════════════════
// BUY STATE ENCODING (for Q-table)
// ═══════════════════════════════════════════════════════════════

/**
 * Encode a potential buy into a compact state key for Q-learning.
 *
 * Uses 3 composite features (instead of 7 independent) for faster convergence:
 *   - deal: squad need + quality upgrade + affordability → "is this a good deal?"
 *   - risk: emotional state + personality + squad bloat → "am I in a state to buy?"
 *   - player: age trajectory → "is this player worth investing in?"
 *
 * State space: 3×3×3 = 27 states × 2 actions = 54 state-action pairs
 * Converges in ~10-20 seasons vs never with 5^7 = 78,125 states.
 *
 * @param {Object} params
 * @param {Object} params.team
 * @param {Object} params.player — candidate player
 * @param {number} params.askingPrice
 * @param {Object|null} params.personality
 * @param {string} params.emotionalState
 * @returns {string} state key
 */
export function encodeBuyState({ team, player, askingPrice, personality = null, emotionalState = 'CALM' }) {
    const squad = team?.squad || [];
    const pos = player?.position || 'MEI';
    const posAnalysis = analyzeSquad(squad)[pos] || {};

    // ── Composite 1: DEAL QUALITY (need + upgrade + affordability) ──
    // Each sub-feature: -1 (bad), 0 (neutral), +1 (good)
    const needScore = (posAnalysis.gap || 0) >= 2 ? 1 : (posAnalysis.gap || 0) <= -1 ? -1 : 0;
    const ovrDelta = (player?.ovr || 50) - (posAnalysis.avgOvr || 50);
    const upgradeScore = ovrDelta >= 5 ? 1 : ovrDelta <= -5 ? -1 : 0;
    const balance = Math.max(team?.balance || 1, 1);
    const affordScore = (askingPrice / balance) <= 0.25 ? 1 : (askingPrice / balance) >= 0.5 ? -1 : 0;
    // Sum: -3 to +3 → 3 tiers
    const dealSum = needScore + upgradeScore + affordScore;
    const deal = dealSum >= 1 ? 2 : dealSum <= -1 ? 0 : 1; // 0=bad, 1=neutral, 2=good

    // ── Composite 2: RISK PROFILE (emotion + personality + squad pressure) ──
    const emoVal = EMO_SCALE[emotionalState] || 0;
    const emoScore = emoVal >= 3 ? 1 : emoVal === 0 ? -1 : 0; // desperate/tilted = risky
    const ocean = personality?.ocean || {};
    const riskAppetite = ((ocean.O || 0.5) + (ocean.E || 0.5) - (ocean.C || 0.5)) / 2;
    const riskScore = riskAppetite >= 0.5 ? 1 : riskAppetite <= 0.2 ? -1 : 0;
    const squadSize = squad.filter(p => !p._retired).length;
    const squadScore = squadSize >= 24 ? 1 : squadSize <= 16 ? -1 : 0; // bloated = pressure NOT to buy
    const riskSum = emoScore + riskScore - squadScore; // high emo + high risk - bloated
    const risk = riskSum >= 1 ? 2 : riskSum <= -1 ? 0 : 1; // 0=conservative, 1=neutral, 2=aggressive

    // ── Composite 3: PLAYER PROFILE (age trajectory) ──
    const age = player?.age || 25;
    const playerTier = age <= 23 ? 2 : age >= 30 ? 0 : 1; // 0=veteran, 1=peak, 2=young

    return `MKT_B|d${deal}|r${risk}|p${playerTier}`;
}

// ═══════════════════════════════════════════════════════════════
// SELL STATE ENCODING (for Q-table)
// ═══════════════════════════════════════════════════════════════

/**
 * Encode a sell offer into a compact state key for Q-learning.
 *
 * Uses 3 composite features for faster convergence:
 *   - offer: offer/value ratio + financial need → "is this offer worth taking?"
 *   - impact: position depth + is starter → "can I afford to lose this player?"
 *   - context: age + emotion + personality → "should I be selling?"
 *
 * State space: 3×3×3 = 27 states × 2 actions = 54 state-action pairs
 *
 * @param {Object} params
 * @returns {string} state key
 */
export function encodeSellState({ team, player, offerAmount, personality = null, emotionalState = 'CALM' }) {
    const squad = team?.squad || [];
    const pos = player?.position || 'MEI';
    const posAnalysis = analyzeSquad(squad)[pos] || {};
    const playerValue = player?.value || (player?.ovr || 50) * 50_000;

    // ── Composite 1: OFFER QUALITY (ratio + financial urgency) ──
    const offerRatio = offerAmount / Math.max(playerValue, 100_000);
    const ratioScore = offerRatio >= 1.3 ? 1 : offerRatio <= 0.8 ? -1 : 0;
    const balance = team?.balance || 0;
    const finScore = balance < 0 ? 1 : balance < 1_000_000 ? 0 : -1; // negative = urgent to sell
    const offerSum = ratioScore + finScore;
    const offer = offerSum >= 1 ? 2 : offerSum <= -1 ? 0 : 1; // 0=bad offer, 1=neutral, 2=good/urgent

    // ── Composite 2: SQUAD IMPACT (depth + starter status) ──
    const isStarter = (player?.ovr || 0) >= (posAnalysis.maxOvr || 50) - 3 ? 1 : 0;
    const hasDepth = (posAnalysis.depth || 0) >= 3 ? 1 : 0;
    // Selling starter from thin depth = high impact (bad)
    const impact = isStarter && !hasDepth ? 0 : !isStarter ? 2 : 1; // 0=critical loss, 1=moderate, 2=safe

    // ── Composite 3: AGENT CONTEXT (age + emotion + personality) ──
    const age = player?.age || 25;
    const ageScore = age >= 30 ? 1 : age <= 23 ? -1 : 0; // older = more willing to sell
    const emoVal = EMO_SCALE[emotionalState] || 0;
    const emoScore = emoVal >= 3 ? 1 : emoVal === 0 ? -1 : 0;
    const ocean = personality?.ocean || {};
    const sellWill = ((ocean.A || 0.5) - (ocean.N || 0.5) + 0.5) / 1.5;
    const willScore = sellWill >= 0.5 ? 1 : sellWill <= 0.2 ? -1 : 0;
    const ctxSum = ageScore + emoScore + willScore;
    const ctx = ctxSum >= 1 ? 2 : ctxSum <= -1 ? 0 : 1; // 0=reluctant, 1=neutral, 2=willing

    return `MKT_S|o${offer}|i${impact}|c${ctx}`;
}

// ═══════════════════════════════════════════════════════════════
// MARKET ACTIONS (passed to brain.pickAction)
// ═══════════════════════════════════════════════════════════════

export const BUY_ACTIONS = ['MKT_BUY_YES', 'MKT_BUY_NO'];
export const SELL_ACTIONS = ['MKT_SELL_YES', 'MKT_SELL_NO'];

// ═══════════════════════════════════════════════════════════════
// TRANSFER REWARD (call AFTER transfer outcome is known)
// ═══════════════════════════════════════════════════════════════

/**
 * Compute reward for a transfer decision.
 * Called weeks after the transfer to evaluate if it was good.
 *
 * For BUY:
 *   +10 if bought player became starter
 *   +5  if team position improved after buy
 *   -5  if bought player is benched
 *   -10 if team went into financial trouble after buy
 *
 * For SELL:
 *   +10 if sold deadwood (reserve, old) at good price
 *   +5  if team position held/improved
 *   -10 if sold starter and position weakened
 *   -5  if sold cheap (bad deal)
 *
 * @param {Object} params
 * @returns {number} reward
 */
export function computeTransferReward({
    action, // 'BUY' or 'SELL'
    positionBefore, positionAfter,
    balanceBefore, balanceAfter,
    playerBecameStarter = false,
    playerWasStarter = false,
    offerRatio = 1.0,
    emotionalLossMod = 1.0
}) {
    let r = 0;

    if (action === 'BUY') {
        if (playerBecameStarter) r += 10;
        else r -= 5; // benched = wasted money

        // Position improvement
        const posDelta = (positionBefore || 10) - (positionAfter || 10); // positive = improved
        r += Math.min(5, posDelta * 2);

        // Financial health
        if ((balanceAfter || 0) < 0) r -= 10 * emotionalLossMod;

    } else if (action === 'SELL') {
        // Good deal?
        if (offerRatio >= 1.5) r += 8;
        else if (offerRatio >= 1.0) r += 3;
        else r -= 5 * emotionalLossMod; // sold cheap

        // Selling starter hurt?
        if (playerWasStarter) {
            const posDelta = (positionBefore || 10) - (positionAfter || 10);
            if (posDelta < 0) r -= 8 * emotionalLossMod; // position dropped
            else r += 3; // position held despite losing starter
        } else {
            r += 5; // trimming reserves is generally good
        }
    }

    return r;
}

// ═══════════════════════════════════════════════════════════════
// HIGH-LEVEL DECISION INTERFACE
// ═══════════════════════════════════════════════════════════════

/**
 * Ask the brain whether to buy. Returns { buy, reason, action, stateKey, source }.
 *
 * @param {Object} brain — AdaptiveBrain instance
 * @param {Object} params — { team, player, askingPrice, biasCtx }
 * @returns {Object}
 */
export function smartBuyDecision(brain, { team, player, askingPrice, biasCtx = {} }) {
    if (!brain) {
        return { buy: false, reason: 'no brain', source: 'fallback' };
    }

    const emoState = brain.emotions?.state || 'CALM';
    const stateKey = encodeBuyState({
        team, player, askingPrice,
        personality: brain.personality,
        emotionalState: emoState
    });

    const action = brain.pickAction(stateKey, BUY_ACTIONS, {
        position: 0, balance: team?.balance || 0,
        formAvg: 50, lastResult: 'D'
    });

    const buy = action === 'MKT_BUY_YES';

    // Apply cognitive bias as post-filter (can override brain in extreme cases)
    if (buy && brain.personality) {
        try {
            const biases = applyBuyBiases({
                realValue: askingPrice,
                personality: brain.personality,
                context: { ...biasCtx, targetPosition: player?.position }
            });
            // If biases say it's WAY too expensive (asking much more than perceived), override
            if (askingPrice > biases.perceivedValue * 2) {
                return {
                    buy: false,
                    reason: `brain said YES but biases say overpriced (perceived ${biases.perceivedValue.toFixed(0)} vs asked ${askingPrice})`,
                    action, stateKey, source: 'smart+bias_override',
                    biases: biases.biasesApplied
                };
            }
        } catch { /* continue with brain decision */ }
    }

    return {
        buy,
        reason: `brain=${action} state=${stateKey} emo=${emoState}`,
        action, stateKey, source: 'smart',
        biases: []
    };
}

/**
 * Ask the brain whether to sell.
 */
export function smartSellDecision(brain, { team, player, offerAmount }) {
    if (!brain) {
        return { sell: false, reason: 'no brain', source: 'fallback' };
    }

    const emoState = brain.emotions?.state || 'CALM';
    const stateKey = encodeSellState({
        team, player, offerAmount,
        personality: brain.personality,
        emotionalState: emoState
    });

    const action = brain.pickAction(stateKey, SELL_ACTIONS, {
        position: 0, balance: team?.balance || 0,
        formAvg: 50, lastResult: 'D'
    });

    const sell = action === 'MKT_SELL_YES';

    // Cognitive bias post-filter: sunk cost / endowment might override
    if (!sell && brain.personality) {
        try {
            const biases = applySellBiases({
                offerAmount,
                playerValue: player?.value || (player?.ovr || 50) * 50_000,
                purchasePrice: player?._purchasePrice || 0,
                personality: brain.personality,
            });
            // If offer is way above biased minimum AND brain said no, let biases override
            if (offerAmount > biases.minAcceptable * 2.5) {
                return {
                    sell: true,
                    reason: `brain said NO but offer ${offerAmount} >> min ${biases.minAcceptable.toFixed(0)} — too good to refuse`,
                    action, stateKey, source: 'smart+bias_override',
                    biases: biases.biasesApplied
                };
            }
        } catch { /* continue with brain decision */ }
    }

    return {
        sell,
        reason: `brain=${action} state=${stateKey} emo=${emoState}`,
        action, stateKey, source: 'smart',
        biases: []
    };
}

/**
 * Rank scouted candidates by brain score.
 * Returns top N that the brain says BUY.
 */
export function rankCandidates({ brain, team, candidates, biasCtx = {}, limit = 5 }) {
    if (!brain || !candidates?.length) return [];

    const scored = candidates.map(c => {
        const player = c.player || c;
        const askingPrice = Math.round((c.value || (player.ovr || 60) * 50_000) * 1.3);
        const decision = smartBuyDecision(brain, { team, player, askingPrice, biasCtx });
        return { candidate: c, decision, askingPrice };
    });

    return scored
        .filter(s => s.decision.buy)
        .sort((a, b) => {
            // Prefer: higher OVR upgrade, lower cost
            const aUpgrade = (a.candidate.player || a.candidate).ovr || 0;
            const bUpgrade = (b.candidate.player || b.candidate).ovr || 0;
            return bUpgrade - aUpgrade;
        })
        .slice(0, limit);
}

import { HIGH_END_FACES } from '../assets/faces/high_end';

function getFaceIndex(name = '') {
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
        hash = ((hash << 5) - hash) + name.charCodeAt(i);
        hash |= 0;
    }
    return Math.abs(hash) % HIGH_END_FACES.length;
}

export function PlayerAvatar({ name, size = 28 }) {
    const faceIndex = getFaceIndex(name);
    const faceSrc = HIGH_END_FACES[faceIndex];

    return (
        <img
            src={faceSrc}
            alt={`Avatar ${name}`}
            className="player-avatar"
            style={{ 
                width: size, 
                height: size, 
                objectFit: 'cover',
                borderRadius: '0px',
                border: '1px solid #334155',
                backgroundColor: '#111417',
                imageRendering: 'pixelated'
            }}
        />
    );
}

export function getInitials(name) {
    if (!name) return '?';
    const parts = name.trim().split(' ');
    if (parts.length > 1) {
        return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
    }
    return name.substring(0, 2).toUpperCase();
}

export function getAvatarColor(name) {
    if (!name) return '#40BAF7';
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    const color = (hash & 0x00FFFFFF).toString(16).toUpperCase();
    return '#' + '00000'.substring(0, 6 - color.length) + color;
}
